import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const getAISupportResponse = async (query: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: query,
      config: {
        systemInstruction: "You are a helpful support agent for the 'My Rents' application. Your goal is to help users understand how to rent items, create listings, and use the points system. If you cannot solve the problem, tell them it will be sent to jikob67@gmail.com.",
      }
    });
    return response.text || "I'm sorry, I'm having trouble connecting right now.";
  } catch (error) {
    console.error("AI Support Error:", error);
    return "Something went wrong. Please try emailing jikob67@gmail.com directly.";
  }
};

