import React from 'react';
import { Heart, MapPin, Eye, Star, Share2 } from 'lucide-react';
import { Listing, ListingType } from '../types';
import { Link } from 'react-router-dom';

interface ListingCardProps {
  listing: Listing;
  lang: string;
}

const ListingCard: React.FC<ListingCardProps> = ({ listing, lang }) => {
  const isRtl = lang === 'ar';

  const handleShare = async (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();

    const shareData = {
      title: listing.title,
      text: `${listing.description}\n${lang === 'ar' ? 'شاهد هذا العرض على My Rents!' : 'Check out this listing on My Rents!'}`,
      url: `https://ai.studio/apps/drive/1DDfaK8aTtJ9qVfJErQz_OS8zwpsV8fZc?fullscreenApplet=true#/item/${listing.id}`,
    };

    if (navigator.share) {
      try {
        await navigator.share(shareData);
      } catch (err) {
        console.log('Error sharing:', err);
      }
    } else {
      // Fallback: Copy to clipboard
      navigator.clipboard.writeText(shareData.url);
      alert(lang === 'ar' ? 'تم نسخ الرابط!' : 'Link copied!');
    }
  };

  return (
    <div className="bg-white dark:bg-gray-900 rounded-2xl overflow-hidden shadow-sm hover:shadow-xl transition-all group border border-gray-100 dark:border-gray-800">
      <Link to={`/item/${listing.id}`} className="relative block">
        <div className="aspect-[4/3] overflow-hidden">
          <img 
            src={listing.images[0] || `https://picsum.photos/seed/${listing.id}/400/300`} 
            alt={listing.title}
            className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500"
          />
        </div>
        <div className="absolute top-3 right-3 flex flex-col gap-2">
          <button className="p-2 bg-white/90 backdrop-blur text-gray-900 rounded-full hover:bg-brand hover:text-white transition-colors shadow-sm">
            <Heart size={18} />
          </button>
          <div className={`px-3 py-1 text-[10px] font-bold rounded-full uppercase shadow-sm ${listing.type === ListingType.FREE ? 'bg-green-500 text-white' : 'bg-brand text-white'}`}>
            {listing.type}
          </div>
        </div>
        {listing.price > 0 && (
          <div className="absolute bottom-3 left-3 bg-brand text-white px-3 py-1 rounded-lg font-bold shadow-lg">
            {listing.price} {listing.currency}
          </div>
        )}
      </Link>

      <div className="p-4">
        <div className="flex justify-between items-start mb-1">
          <h3 className="font-bold text-lg truncate flex-1 dark:text-white">{listing.title}</h3>
          <div className="flex items-center gap-1 text-yellow-500">
            <Star size={14} fill="currentColor" />
            <span className="text-xs font-semibold">{listing.rating}</span>
          </div>
        </div>

        <div className="flex items-center gap-1 text-gray-500 text-xs mb-3">
          <MapPin size={12} />
          <span>{listing.region}</span>
        </div>

        <div className="flex items-center justify-between pt-3 border-t border-gray-100 dark:border-gray-800">
          <div className="flex items-center gap-3 text-gray-400">
            <div className="flex items-center gap-1">
              <Eye size={14} />
              <span className="text-xs">{listing.views}</span>
            </div>
            <button 
              onClick={handleShare}
              className="flex items-center gap-1 hover:text-brand transition-colors"
            >
              <Share2 size={14} />
              <span className="text-xs font-bold">{lang === 'ar' ? 'مشاركة' : 'Share'}</span>
            </button>
          </div>
          <Link 
            to={`/item/${listing.id}`}
            className="text-brand font-bold text-sm hover:underline"
          >
            {lang === 'ar' ? 'عرض التفاصيل' : 'View Details'}
          </Link>
        </div>
      </div>
    </div>
  );
};

