  const toggleTheme = () => setIsDarkMode(!isDarkMode);

  const currentTranslations = translations[lang] || translations['en'];
  const isRtl = currentTranslations.dir === 'rtl';

  const languageNames: Record<string, string> = {
    en: 'English',
    ar: 'العربية',
    es: 'Español',
    fr: 'Français',
