    zh: '中文',
    hi: 'हिन्दी'
  };

  const handleShareApp = async () => {
    const shareData = {
      title: 'My Rents',
      text: lang === 'ar' ? 'أفضل تطبيق لتأجير الأغراض الشخصية! جربه الآن.' : 'Best app for renting personal items! Try it now.',
      url: 'https://ai.studio/apps/drive/1DDfaK8aTtJ9qVfJErQz_OS8zwpsV8fZc?fullscreenApplet=true',
