      birthDate: '1995-01-01',
      location: 'World',
      status: 'Active Renter',
      points: 0,
      listingsCount: 0,
      walletBalance: 0
    });
  };

  return (
    <HashRouter>
      <div className={`min-h-screen ${isRtl ? 'rtl' : 'ltr'} bg-white dark:bg-gray-950`} dir={isRtl ? 'rtl' : 'ltr'}>
