interface SubscriptionPageProps {
  lang: string;
}

const SubscriptionPage: React.FC<SubscriptionPageProps> = ({ lang }) => {
  const t = translations[lang] || translations['en'];
  const navigate = useNavigate();
  const [step, setStep] = useState(1);
  const [selectedPlan, setSelectedPlan] = useState<SubscriptionPlan | null>(null);
  const [selectedPeriod, setSelectedPeriod] = useState<PlanPeriod>('MONTHLY');
  const [selectedWallet, setSelectedWallet] = useState<string | null>(null);
  const [userWallet, setUserWallet] = useState('');
  const [verifyCode, setVerifyCode] = useState('');

  const nextStep = () => setStep(prev => Math.min(prev + 1, 5));
  const prevStep = () => setStep(prev => Math.max(prev - 1, 1));

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
    alert(lang === 'ar' ? 'تم النسخ!' : 'Copied!');
  };

  const renderStep1 = () => (
    <div className="space-y-6">
      <div className="flex justify-center gap-4 mb-8">
        {(['DAILY', 'MONTHLY', 'YEARLY'] as PlanPeriod[]).map(p => (
          <button
            key={p}
            onClick={() => setSelectedPeriod(p)}
            className={`px-6 py-2 rounded-full font-bold transition-all ${selectedPeriod === p ? 'bg-brand text-white' : 'bg-gray-100 dark:bg-gray-800 text-gray-500'}`}
