            <div className="flex justify-between items-start mb-4">
              <h3 className="text-xl font-bold dark:text-white">{plan.name}</h3>
              {plan.isSpecial && <span className="bg-orange-500 text-white text-[10px] px-2 py-1 rounded-full font-bold uppercase">Hot</span>}
