            <p className="text-gray-500 text-sm mb-4 h-10 overflow-hidden">{plan.description}</p>
            <div className="text-3xl font-black text-brand mb-6">
              ${plan.pricing[selectedPeriod.toLowerCase() as keyof typeof plan.pricing]}
