  const renderStep2 = () => (
    <div className="space-y-6">
      <div className="grid grid-cols-2 sm:grid-cols-3 gap-3">
        {Object.entries(WALLETS).map(([name, address]) => (
          <div 
            key={name}
            onClick={() => setSelectedWallet(name)}
            className={`p-4 rounded-xl border-2 cursor-pointer text-center transition-all ${selectedWallet === name ? 'border-brand bg-brand/5' : 'border-gray-100 dark:border-gray-800'}`}
          >
            <div className="w-10 h-10 bg-gray-100 dark:bg-gray-800 rounded-full flex items-center justify-center mx-auto mb-2 text-brand">
