          <div className="flex items-center justify-between bg-white dark:bg-gray-900 p-3 rounded-lg border border-gray-100 dark:border-gray-800">
            <code className="text-[10px] break-all text-brand font-bold">{WALLETS[selectedWallet as keyof typeof WALLETS]}</code>
            <button onClick={() => copyToClipboard(WALLETS[selectedWallet as keyof typeof WALLETS])} className="text-gray-400 hover:text-brand p-1">
              <Copy size={16} />
            </button>
          </div>
        </div>
      )}

      <div className="flex gap-4">
        <button onClick={prevStep} className="flex-1 py-4 border-2 border-gray-100 dark:border-gray-800 rounded-xl font-bold dark:text-white flex items-center justify-center gap-2">
          <ArrowLeft size={18} /> {t.back}
        </button>
        <button 
          disabled={!selectedWallet}
          onClick={nextStep}
          className="flex-[2] py-4 bg-brand text-white rounded-xl font-bold shadow-xl hover:bg-brand-dark transition-all disabled:opacity-50 flex items-center justify-center gap-2"
        >
          {t.next} <ArrowRight size={18} />
        </button>
      </div>
    </div>
  );

  const renderStep3 = () => (
    <div className="space-y-6">
      <div className="bg-brand/5 p-6 rounded-2xl border border-brand/20">
        <Wallet className="text-brand mb-4" size={32} />
