        <p className="text-sm text-gray-500 mb-4">{lang === 'ar' ? 'يرجى إدخال عنوان المحفظة الذي أرسلت منه الدفعة لتأكيدها.' : 'Please enter the wallet address you sent the payment from for verification.'}</p>
        <input 
          type="text" 
          value={userWallet}
          onChange={(e) => setUserWallet(e.target.value)}
          placeholder={t.walletPlaceholder}
          className="w-full px-4 py-3 rounded-xl bg-white dark:bg-gray-800 border-2 border-gray-100 dark:border-gray-700 outline-none focus:border-brand dark:text-white transition-all"
        />
      </div>
      <div className="flex gap-4">
        <button onClick={prevStep} className="flex-1 py-4 border-2 border-gray-100 dark:border-gray-800 rounded-xl font-bold dark:text-white">
          {t.back}
        </button>
        <button 
          disabled={userWallet.length < 10}
          onClick={nextStep}
          className="flex-[2] py-4 bg-brand text-white rounded-xl font-bold shadow-xl hover:bg-brand-dark transition-all disabled:opacity-50"
        >
          {t.next}
        </button>
      </div>
    </div>
  );

  const renderStep4 = () => (
    <div className="space-y-6">
      <div className="bg-brand/5 p-6 rounded-2xl border border-brand/20">
        <ShieldCheck className="text-brand mb-4" size={32} />
        <h3 className="font-bold text-xl mb-2 dark:text-white">{t.enterVerifyCode}</h3>
        <p className="text-sm text-gray-500 mb-4">{lang === 'ar' ? 'الصق معرف المعاملة (TxID) أو رمز التحقق الذي حصلت عليه بعد الدفع.' : 'Paste the Transaction ID (TxID) or verification code obtained after payment.'}</p>
        <input 
          type="text" 
          value={verifyCode}
          onChange={(e) => setVerifyCode(e.target.value)}
          placeholder={t.verifyPlaceholder}
          className="w-full px-4 py-3 rounded-xl bg-white dark:bg-gray-800 border-2 border-gray-100 dark:border-gray-700 outline-none focus:border-brand dark:text-white transition-all"
        />
      </div>
      <div className="flex gap-4">
        <button onClick={prevStep} className="flex-1 py-4 border-2 border-gray-100 dark:border-gray-800 rounded-xl font-bold dark:text-white">
          {t.back}
        </button>
        <button 
          disabled={verifyCode.length < 5}
          onClick={nextStep}
          className="flex-[2] py-4 bg-brand text-white rounded-xl font-bold shadow-xl hover:bg-brand-dark transition-all disabled:opacity-50"
        >
          {t.finish}
        </button>
      </div>
    </div>
  );

  const renderStep5 = () => (
    <div className="text-center py-10 space-y-6 animate-in zoom-in-95 duration-500">
      <div className="w-24 h-24 bg-green-500 text-white rounded-full flex items-center justify-center mx-auto shadow-2xl shadow-green-500/30">
        <CheckCircle size={48} />
      </div>
      <h2 className="text-3xl font-black dark:text-white">{t.subSuccess}</h2>
      <p className="text-gray-500 max-w-xs mx-auto">{t.successMsg}</p>

      <div className="bg-gray-50 dark:bg-gray-800 p-6 rounded-3xl border border-gray-100 dark:border-gray-700 max-w-sm mx-auto">
        <div className="flex justify-between mb-2">
          <span className="text-gray-400 text-xs uppercase font-bold">{lang === 'ar' ? 'الباقة' : 'Plan'}</span>
          <span className="font-bold text-brand">{selectedPlan?.name}</span>
        </div>
        <div className="flex justify-between">
          <span className="text-gray-400 text-xs uppercase font-bold">{lang === 'ar' ? 'الفترة' : 'Period'}</span>
          <span className="font-bold dark:text-white">{t[selectedPeriod.toLowerCase()]}</span>
        </div>
      </div>

      <button 
        onClick={() => navigate('/')}
        className="w-full py-4 bg-gray-900 dark:bg-white dark:text-gray-900 text-white rounded-2xl font-bold shadow-xl hover:scale-[1.02] transition-all flex items-center justify-center gap-2"
      >
        {t.returnHome}
      </button>
    </div>
  );

  return (
    <div className="max-w-3xl mx-auto p-4 pt-10">
      {/* Progress Bar */}
      <div className="flex justify-between items-center mb-10 px-2 relative">
        <div className="absolute top-1/2 left-0 right-0 h-1 bg-gray-100 dark:bg-gray-800 -translate-y-1/2 -z-10"></div>
        <div 
          className="absolute top-1/2 left-0 h-1 bg-brand -translate-y-1/2 -z-10 transition-all duration-500" 
          style={{ width: `${(step - 1) * 25}%` }}
        ></div>
        {[1, 2, 3, 4, 5].map(s => (
          <div 
            key={s} 
            className={`w-8 h-8 rounded-full flex items-center justify-center font-bold text-sm transition-all duration-500 ${s <= step ? 'bg-brand text-white scale-110 shadow-lg shadow-brand/30' : 'bg-gray-200 dark:bg-gray-800 text-gray-500'}`}
          >
            {s < step ? <CheckCircle size={16} /> : s}
          </div>
        ))}
      </div>

      <h1 className="text-2xl font-black mb-8 dark:text-white text-center">
        {step === 1 && t.choosePlan}
        {step === 2 && t.chooseWallet}
        {step === 3 && t.enterYourWallet}
        {step === 4 && t.enterVerifyCode}
        {step === 5 && t.subSuccess}
      </h1>

      <div className="min-h-[500px]">
        {step === 1 && renderStep1()}
        {step === 2 && renderStep2()}
        {step === 3 && renderStep3()}
        {step === 4 && renderStep4()}
        {step === 5 && renderStep5()}
      </div>
    </div>
  );
};

