import React, { useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { translations } from '../i18n';
import { MapPin, Star, Share2, Heart, MessageCircle, ArrowLeft, Copy, Send, ExternalLink } from 'lucide-react';

const ItemDetailPage: React.FC<{ lang: string }> = ({ lang }) => {
  const { id } = useParams();
  const navigate = useNavigate();
  const t = translations[lang] || translations['en'];
  const [showShareMenu, setShowShareMenu] = useState(false);
  const isRtl = lang === 'ar';

  // Mock item data - in a real app this would be fetched based on the ID
  const item = {
    id,
    title: 'Professional DSLR Camera',
    description: 'High-quality DSLR camera perfect for professional photography and videography. Comes with 2 lenses and a tripod.',
    price: 45,
    currency: 'USD',
    rating: 4.8,
    reviews: 12,
    location: 'Downtown, Riyadh',
    owner: 'Ahmed K.',
    image: 'https://images.unsplash.com/photo-1516035069371-29a1b244cc32?auto=format&fit=crop&q=80&w=800'
  };

  const shareUrl = `${window.location.origin}${window.location.pathname}#/item/${id}`;
  const shareText = `${item.title} - ${lang === 'ar' ? 'استأجر هذا الغرض على My Rents!' : 'Rent this item on My Rents!'}`;

  const shareOptions = [
    { name: t.whatsapp, icon: <Send size={20} />, color: 'bg-green-500', url: `https://wa.me/?text=${encodeURIComponent(shareText + ' ' + shareUrl)}` },
    { name: t.telegram, icon: <Send size={20} />, color: 'bg-blue-400', url: `https://t.me/share/url?url=${encodeURIComponent(shareUrl)}&text=${encodeURIComponent(shareText)}` },
    { name: t.twitter, icon: <ExternalLink size={20} />, color: 'bg-black', url: `https://twitter.com/intent/tweet?url=${encodeURIComponent(shareUrl)}&text=${encodeURIComponent(shareText)}` },
    { name: t.facebook, icon: <ExternalLink size={20} />, color: 'bg-blue-600', url: `https://www.facebook.com/sharer/sharer.php?u=${encodeURIComponent(shareUrl)}` },
  ];

  const handleNativeShare = async () => {
    if (navigator.share) {
      try {
        await navigator.share({ title: item.title, text: shareText, url: shareUrl });
      } catch (err) {
        setShowShareMenu(true);
      }
    } else {
      setShowShareMenu(true);
    }
  };

  const copyLink = () => {
    navigator.clipboard.writeText(shareUrl);
    alert(t.linkCopied);
  };

  return (
    <div className="max-w-4xl mx-auto pb-20 px-4 pt-6">
      <button 
        onClick={() => navigate(-1)}
        className="mb-6 p-2 rounded-full hover:bg-gray-100 dark:hover:bg-gray-800 transition-colors dark:text-white"
      >
        <ArrowLeft size={24} className={isRtl ? 'rotate-180' : ''} />
      </button>

      <div className="bg-white dark:bg-gray-900 rounded-3xl overflow-hidden shadow-sm border border-gray-100 dark:border-gray-800">
        <div className="grid grid-cols-1 md:grid-cols-2">
          <div className="aspect-square relative">
            <img src={item.image} alt={item.title} className="w-full h-full object-cover" />
            <div className="absolute top-4 right-4 flex flex-col gap-2">
              <button className="p-3 bg-white/90 backdrop-blur rounded-full shadow-lg hover:scale-110 transition-transform">
                <Heart size={20} className="text-gray-400 hover:text-brand" />
              </button>
              <button 
                onClick={handleNativeShare}
                className="p-3 bg-brand text-white rounded-full shadow-lg hover:scale-110 transition-transform"
              >
                <Share2 size={20} />
              </button>
            </div>
          </div>

          <div className="p-8 flex flex-col">
            <div className="flex justify-between items-start mb-4">
              <h1 className="text-3xl font-black dark:text-white">{item.title}</h1>
              <div className="flex items-center gap-1 text-yellow-500 bg-yellow-50 dark:bg-yellow-900/20 px-3 py-1 rounded-full">
                <Star size={16} fill="currentColor" />
                <span className="font-bold">{item.rating}</span>
              </div>
            </div>

            <div className="flex items-center gap-2 text-gray-500 mb-6">
              <MapPin size={18} />
              <span className="text-sm">{item.location}</span>
            </div>

            <p className="text-gray-600 dark:text-gray-400 mb-8 leading-relaxed">
              {item.description}
            </p>

            <div className="mt-auto pt-6 border-t border-gray-100 dark:border-gray-800 flex items-center justify-between">
              <div>
                <p className="text-xs text-gray-400 uppercase font-bold mb-1">{t.paid}</p>
                <p className="text-3xl font-black text-brand">{item.price} <span className="text-sm font-normal text-gray-500">{item.currency} / {lang === 'ar' ? 'يوم' : 'day'}</span></p>
              </div>
              <button className="px-8 py-4 bg-brand text-white rounded-2xl font-bold shadow-xl hover:scale-[1.02] active:scale-95 transition-all flex items-center gap-2">
                <MessageCircle size={20} />
                {t.contact}
              </button>
            </div>
          </div>
        </div>
      </div>

      {/* Share Modal */}
      {showShareMenu && (
        <div className="fixed inset-0 z-[100] flex items-end sm:items-center justify-center p-4 bg-black/60 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="bg-white dark:bg-gray-900 w-full max-w-sm rounded-t-[2.5rem] sm:rounded-[2.5rem] p-8 shadow-2xl animate-in slide-in-from-bottom-10 duration-300">
            <div className="w-12 h-1.5 bg-gray-200 dark:bg-gray-800 rounded-full mx-auto mb-6 sm:hidden"></div>
            <h3 className="text-xl font-black mb-6 text-center dark:text-white">{t.shareVia}</h3>

            <div className="grid grid-cols-2 gap-4 mb-8">
              {shareOptions.map((opt) => (
                <a 
                  key={opt.name} 
                  href={opt.url} 
                  target="_blank" 
                  rel="noopener noreferrer"
                  className="flex flex-col items-center gap-2 p-4 rounded-3xl bg-gray-50 dark:bg-gray-800 hover:scale-105 transition-transform"
                >
                  <div className={`w-12 h-12 ${opt.color} text-white rounded-full flex items-center justify-center shadow-lg`}>
                    {opt.icon}
                  </div>
                  <span className="text-xs font-bold dark:text-gray-300">{opt.name}</span>
                </a>
              ))}
            </div>

            <button 
              onClick={copyLink}
              className="w-full py-4 bg-gray-100 dark:bg-gray-800 text-gray-900 dark:text-white rounded-2xl font-bold flex items-center justify-center gap-2 hover:bg-gray-200 dark:hover:bg-gray-700 transition-colors mb-4"
            >
              <Copy size={20} />
              {t.copyLink}
            </button>

            <button 
              onClick={() => setShowShareMenu(false)}
              className="w-full py-4 text-gray-500 font-bold hover:underline"
            >
              {t.back}
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

