import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const checkListingContent = async (title: string, description: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Review this rental listing for safety and community guidelines. Is it safe to publish? Reply with ONLY 'APPROVED' or 'REJECTED' followed by a short reason.
      Title: ${title}
      Description: ${description}`,
      config: {
        systemInstruction: "You are AI My Rents. You must ensure all items are for RENT only. No illegal items. No sales.",
      }
    });
    return response.text?.includes('APPROVED') ? { status: 'APPROVED' } : { status: 'REJECTED', reason: response.text };
  } catch (error) {
    return { status: 'APPROVED' }; // Fallback
  }
};

export const getAISupportResponse = async (query: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: query,
      config: {
        systemInstruction: "You are a helpful support agent for 'My Rents'. Help users with rentals, groups, and payouts. Email: jikob67@gmail.com",
      }
    });
    return response.text || "I'm sorry, I'm having trouble connecting right now.";
  } catch (error) {
    return "Something went wrong. Please try emailing jikob67@gmail.com directly.";
  }
};

