      )}

      {step === 3 && (
        <div className="space-y-6">
          <h2 className="text-2xl font-bold dark:text-white">{t.payoutMethod}</h2>
          <div className="flex gap-4">
            <button onClick={() => setCurrencyType(CurrencyType.CRYPTO)} className={`flex-1 py-3 rounded-xl border ${currencyType === CurrencyType.CRYPTO ? 'bg-brand text-white' : 'dark:text-white'}`}>{t.crypto}</button>
            <button onClick={() => setCurrencyType(CurrencyType.LOCAL)} className={`flex-1 py-3 rounded-xl border ${currencyType === CurrencyType.LOCAL ? 'bg-brand text-white' : 'dark:text-white'}`}>{t.local}</button>
          </div>
          {currencyType === CurrencyType.CRYPTO ? (
            <select value={payoutMethod} onChange={e => setPayoutMethod(e.target.value)} className="w-full p-4 rounded-xl bg-gray-50 dark:bg-gray-800 dark:text-white">
              <option value="">{lang === 'ar' ? 'اختر العملة' : 'Select Currency'}</option>
              {cryptoOptions.map(c => <option key={c} value={c}>{c}</option>)}
            </select>
          ) : (
            <input type="email" placeholder="PayPal Email" value={payoutMethod} onChange={e => setPayoutMethod(e.target.value)} className="w-full p-4 rounded-xl bg-gray-50 dark:bg-gray-800 dark:text-white" />
          )}
          <button disabled={!payoutMethod} onClick={() => setStep(4)} className="w-full py-4 bg-brand text-white rounded-xl font-bold">{t.next}</button>
        </div>
      )}

      {step === 4 && (
        <div className="space-y-6">
          <h2 className="text-2xl font-bold dark:text-white">{lang === 'ar' ? 'السعر والمدة' : 'Price & Period'}</h2>
          <div className="flex gap-2">
            <input type="number" placeholder={t.price} value={price} onChange={e => setPrice(e.target.value)} className="flex-1 p-4 rounded-xl bg-gray-50 dark:bg-gray-800 dark:text-white" />
            <select value={period} onChange={e => setPeriod(e.target.value as RentalPeriod)} className="p-4 rounded-xl bg-gray-50 dark:bg-gray-800 dark:text-white">
              {Object.keys(RentalPeriod).map(p => <option key={p} value={p}>{t.periods[p]}</option>)}
            </select>
          </div>
          <div className="p-4 bg-gray-50 dark:bg-gray-800 rounded-xl flex items-center justify-between">
             <span className="dark:text-white"><MapPin className="inline mr-2" /> {location.address || 'Select on map'}</span>
             <button className="text-brand font-bold">📍</button>
          </div>
          <button disabled={!price} onClick={() => setStep(5)} className="w-full py-4 bg-brand text-white rounded-xl font-bold">{t.next}</button>
        </div>
      )}

      {step === 5 && (
        <div className="text-center space-y-6 py-10">
          <ShieldCheck size={64} className="mx-auto text-brand animate-pulse" />
          <h2 className="text-2xl font-bold dark:text-white">{t.aiChecking}</h2>
          <p className="text-gray-500">Analyzing content for safety and guidelines...</p>
          <button onClick={startAiCheck} className="w-full py-4 bg-brand text-white rounded-xl font-bold flex items-center justify-center gap-2">
            {loading ? <Loader2 className="animate-spin" /> : 'Start Verification'}
          </button>
        </div>
      )}

      {step === 6 && (
        <div className="text-center space-y-6 py-10">
          <CheckCircle size={64} className="mx-auto text-green-500" />
          <h2 className="text-2xl font-bold dark:text-white">{t.aiApproved}</h2>
          <p className="text-gray-500">Your listing is ready to go public.</p>
          <button onClick={finish} className="w-full py-4 bg-green-500 text-white rounded-xl font-bold">Launch Listing</button>
        </div>
      )}
    </div>
  );
};

