                       </div>
                    </div>

                    <div className="grid grid-cols-2 gap-4">
                      <button onClick={() => window.location.hash = '#/subscribe'} className="p-4 bg-brand text-white rounded-3xl font-bold flex flex-col items-center gap-2 shadow-xl shadow-brand/20"><Crown /> {t.subscribe}</button>
                      <button onClick={toggleTheme} className="p-4 bg-gray-100 dark:bg-gray-800 dark:text-white rounded-3xl font-bold flex flex-col items-center gap-2">{isDarkMode ? <Sun /> : <Moon />} {isDarkMode ? 'Light' : 'Dark'}</button>
                    </div>

                    <button onClick={() => setUser(null)} className="mt-10 text-red-500 font-bold hover:underline">{t.logout}</button>
                  </div>
                </div>
              ) : <SignUpFlow />
            } />
          </Routes>
        </main>

        <div className="fixed bottom-24 right-6 md:bottom-8 md:right-8 z-40 flex flex-col gap-3">
          <button onClick={() => window.location.hash = '#/chat'} className="w-14 h-14 bg-brand text-white rounded-full shadow-2xl flex items-center justify-center hover:scale-110 active:scale-95 transition-all"><MessageCircle size={28} /></button>
        </div>
      </div>
    </HashRouter>
  );
};

