        </div>
      </div>
    </HashRouter>
  );
};

export default App;

import React, { useState } from 'react';
import { translations } from '../i18n';
import { CATEGORIES } from '../constants';
import { CurrencyType, RentalPeriod, ListingType } from '../types';
import { checkListingContent } from '../services/geminiService';
import { Camera, Video, MapPin, Loader2, CheckCircle, ShieldCheck } from 'lucide-react';
import { useNavigate } from 'react-router-dom';

const CreateListingPage: React.FC<{ lang: string; user: any }> = ({ lang, user }) => {
  const t = translations[lang];
  const navigate = useNavigate();
  const [step, setStep] = useState(1);
  const [loading, setLoading] = useState(false);

  const [images, setImages] = useState<string[]>([]);
  const [video, setVideo] = useState<string | null>(null);
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [category, setCategory] = useState(CATEGORIES[0]);
  const [currencyType, setCurrencyType] = useState<CurrencyType>(CurrencyType.LOCAL);
  const [payoutMethod, setPayoutMethod] = useState('');
  const [price, setPrice] = useState('');
  const [period, setPeriod] = useState<RentalPeriod>(RentalPeriod.DAY);
  const [location, setLocation] = useState(user?.location || { lat: 0, lng: 0, address: '' });

  // Fixed: Cast the result of Array.from to File[] to satisfy URL.createObjectURL type requirements
  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      const files = Array.from(e.target.files).slice(0, 5) as File[];
      const urls = files.map(f => URL.createObjectURL(f));
      setImages(urls);
    }
  };

  const startAiCheck = async () => {
    setLoading(true);
    const result = await checkListingContent(title, description);
    if (result.status === 'APPROVED') {
      setStep(6);
    } else {
      alert(t.aiRejected + ": " + result.reason);
    }
    setLoading(false);
  };

  const finish = () => {
    // In real app, dispatch to state/API
    navigate('/');
  };

  const cryptoOptions = ['Solana', 'Ethereum', 'Monad', 'Base', 'Sui', 'Polygon', 'Bitcoin'];

  return (
    <div className="max-w-2xl mx-auto p-6 bg-white dark:bg-gray-900 rounded-3xl shadow-sm my-8">
      <div className="flex justify-between mb-8">
        {[1,2,3,4,5,6].map(s => (
          <div key={s} className={`w-3 h-3 rounded-full ${step >= s ? 'bg-brand' : 'bg-gray-200'}`} />
        ))}
      </div>

      {step === 1 && (
        <div className="space-y-6">
          <h2 className="text-2xl font-bold dark:text-white">{lang === 'ar' ? 'رفع صور وفيديو' : 'Upload Media'}</h2>
          <div className="grid grid-cols-3 gap-2">
            {images.map((img, i) => <img key={i} src={img} className="aspect-square object-cover rounded-xl" />)}
            {images.length < 5 && (
              <label className="aspect-square border-2 border-dashed rounded-xl flex items-center justify-center cursor-pointer text-gray-400">
                <Camera size={24} /><input type="file" multiple accept="image/*" className="hidden" onChange={handleImageUpload} />
              </label>
            )}
          </div>
          <p className="text-xs text-gray-500">Min 2, Max 5 images.</p>
          <label className="block p-4 border rounded-xl cursor-pointer dark:text-white">
            <Video className="inline mr-2" /> {lang === 'ar' ? 'رفع فيديو (اختياري)' : 'Upload Video (Optional)'}
            {/* Fixed: Added null-check for target files and index access to satisfy TypeScript */}
            <input type="file" accept="video/*" className="hidden" onChange={(e) => {
              if (e.target.files && e.target.files[0]) {
                setVideo(URL.createObjectURL(e.target.files[0]));
              }
            }} />
          </label>
          <button disabled={images.length < 2} onClick={() => setStep(2)} className="w-full py-4 bg-brand text-white rounded-xl font-bold disabled:opacity-50">{t.next}</button>
        </div>
      )}

      {step === 2 && (
        <div className="space-y-6">
          <h2 className="text-2xl font-bold dark:text-white">{lang === 'ar' ? 'معلومات المنتج' : 'Item Info'}</h2>
          <input type="text" placeholder={lang === 'ar' ? 'اسم المنتج' : 'Item Title'} value={title} onChange={e => setTitle(e.target.value)} className="w-full p-4 rounded-xl bg-gray-50 dark:bg-gray-800 dark:text-white" />
          <textarea placeholder={lang === 'ar' ? 'وصف المنتج' : 'Description'} value={description} onChange={e => setDescription(e.target.value)} className="w-full p-4 rounded-xl bg-gray-50 dark:bg-gray-800 dark:text-white h-32" />
          <select value={category} onChange={e => setCategory(e.target.value)} className="w-full p-4 rounded-xl bg-gray-50 dark:bg-gray-800 dark:text-white">
            {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
          </select>
          <button disabled={!title || !description} onClick={() => setStep(3)} className="w-full py-4 bg-brand text-white rounded-xl font-bold">{t.next}</button>
        </div>
      )}

      {step === 3 && (
        <div className="space-y-6">
          <h2 className="text-2xl font-bold dark:text-white">{t.payoutMethod}</h2>
          <div className="flex gap-4">
            <button onClick={() => setCurrencyType(CurrencyType.CRYPTO)} className={`flex-1 py-3 rounded-xl border ${currencyType === CurrencyType.CRYPTO ? 'bg-brand text-white' : 'dark:text-white'}`}>{t.crypto}</button>
            <button onClick={() => setCurrencyType(CurrencyType.LOCAL)} className={`flex-1 py-3 rounded-xl border ${currencyType === CurrencyType.LOCAL ? 'bg-brand text-white' : 'dark:text-white'}`}>{t.local}</button>
          </div>
          {currencyType === CurrencyType.CRYPTO ? (
            <select value={payoutMethod} onChange={e => setPayoutMethod(e.target.value)} className="w-full p-4 rounded-xl bg-gray-50 dark:bg-gray-800 dark:text-white">
              <option value="">{lang === 'ar' ? 'اختر العملة' : 'Select Currency'}</option>
              {cryptoOptions.map(c => <option key={c} value={c}>{c}</option>)}
            </select>
          ) : (
            <input type="email" placeholder="PayPal Email" value={payoutMethod} onChange={e => setPayoutMethod(e.target.value)} className="w-full p-4 rounded-xl bg-gray-50 dark:bg-gray-800 dark:text-white" />
          )}
          <button disabled={!payoutMethod} onClick={() => setStep(4)} className="w-full py-4 bg-brand text-white rounded-xl font-bold">{t.next}</button>
        </div>
      )}

      {step === 4 && (
        <div className="space-y-6">
          <h2 className="text-2xl font-bold dark:text-white">{lang === 'ar' ? 'السعر والمدة' : 'Price & Period'}</h2>
          <div className="flex gap-2">
            <input type="number" placeholder={t.price} value={price} onChange={e => setPrice(e.target.value)} className="flex-1 p-4 rounded-xl bg-gray-50 dark:bg-gray-800 dark:text-white" />
            <select value={period} onChange={e => setPeriod(e.target.value as RentalPeriod)} className="p-4 rounded-xl bg-gray-50 dark:bg-gray-800 dark:text-white">
              {Object.keys(RentalPeriod).map(p => <option key={p} value={p}>{t.periods[p]}</option>)}
            </select>
          </div>
          <div className="p-4 bg-gray-50 dark:bg-gray-800 rounded-xl flex items-center justify-between">
             <span className="dark:text-white"><MapPin className="inline mr-2" /> {location.address || 'Select on map'}</span>
             <button className="text-brand font-bold">📍</button>
          </div>
          <button disabled={!price} onClick={() => setStep(5)} className="w-full py-4 bg-brand text-white rounded-xl font-bold">{t.next}</button>
        </div>
      )}

      {step === 5 && (
        <div className="text-center space-y-6 py-10">
          <ShieldCheck size={64} className="mx-auto text-brand animate-pulse" />
          <h2 className="text-2xl font-bold dark:text-white">{t.aiChecking}</h2>
          <p className="text-gray-500">Analyzing content for safety and guidelines...</p>
          <button onClick={startAiCheck} className="w-full py-4 bg-brand text-white rounded-xl font-bold flex items-center justify-center gap-2">
            {loading ? <Loader2 className="animate-spin" /> : 'Start Verification'}
          </button>
        </div>
      )}

      {step === 6 && (
        <div className="text-center space-y-6 py-10">
          <CheckCircle size={64} className="mx-auto text-green-500" />
          <h2 className="text-2xl font-bold dark:text-white">{t.aiApproved}</h2>
          <p className="text-gray-500">Your listing is ready to go public.</p>
          <button onClick={finish} className="w-full py-4 bg-green-500 text-white rounded-xl font-bold">Launch Listing</button>
        </div>
      )}
    </div>
  );
};

