import React, { useState, useEffect } from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';
import { User, Gender, PayoutMethods } from './types';
import Navbar from './components/Navbar';
import HomePage from './pages/HomePage';
import SupportAI from './components/SupportAI';
import SubscriptionPage from './pages/SubscriptionPage';
import ItemDetailPage from './pages/ItemDetailPage';
import CreateListingPage from './pages/CreateListingPage';
import ChatPage from './pages/ChatPage';
import { translations } from './i18n';
import { MessageCircle, Globe, UserPlus, Share2, Crown, Wallet, CreditCard, Save, Bitcoin, Zap, ShieldBan, MapPin, Camera, Lock, Sun, Moon, Trash2, ShieldCheck, CheckCircle } from 'lucide-react';

const App: React.FC = () => {
  const [lang, setLang] = useState<string>('ar');
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [user, setUser] = useState<User | null>(null);

  // SignUp State
  const [signupStep, setSignupStep] = useState(1);
  const [signupData, setSignupData] = useState({
    avatar: '',
    fullName: '',
    username: '',
    location: { address: '', lat: 0, lng: 0 },
    email: '',
    password: '',
    agreed: false
  });

  useEffect(() => {
    if (isDarkMode) document.documentElement.classList.add('dark');
    else document.documentElement.classList.remove('dark');
  }, [isDarkMode]);

  const toggleTheme = () => setIsDarkMode(!isDarkMode);
  const t = translations[lang] || translations['en'];
  const isRtl = t.dir === 'rtl';

  const handleSignUpFinish = () => {
    const newUser: User = {
      id: 'u_' + Date.now(),
      fullName: signupData.fullName,
      username: signupData.username,
      email: signupData.email,
      avatar: signupData.avatar,
      gender: Gender.OTHER,
      birthDate: '2000-01-01',
      location: signupData.location,
      status: 'Member',
      points: 0,
      listingsCount: 0,
      walletBalance: 0,
      payoutMethods: {},
      blockedUsers: []
    };
    setUser(newUser);
  };

  const SignUpFlow = () => (
    <div className="max-w-xl mx-auto mt-10 bg-white dark:bg-gray-900 p-10 rounded-[3rem] shadow-2xl border border-gray-100 dark:border-gray-800">
      <div className="flex justify-center mb-8 gap-2">
        {[1,2,3,4,5,6].map(s => <div key={s} className={`w-2 h-2 rounded-full ${signupStep >= s ? 'bg-brand' : 'bg-gray-200'}`} />)}
      </div>

      {signupStep === 1 && (
        <div className="space-y-6 text-center">
          <h2 className="text-3xl font-black dark:text-white">{t.signupSteps.profilePic}</h2>
          <label className="w-32 h-32 rounded-full bg-gray-100 dark:bg-gray-800 mx-auto flex items-center justify-center border-4 border-brand cursor-pointer overflow-hidden relative group">
             {signupData.avatar ? <img src={signupData.avatar} className="w-full h-full object-cover" /> : <Camera size={40} className="text-gray-400" />}
             <input type="file" className="hidden" onChange={e => e.target.files && setSignupData({...signupData, avatar: URL.createObjectURL(e.target.files[0])})} />
          </label>
          <button onClick={() => signupData.avatar && setSignupStep(2)} className="w-full py-4 bg-brand text-white rounded-2xl font-bold disabled:opacity-50">{t.next}</button>
        </div>
      )}

      {signupStep === 2 && (
        <div className="space-y-6">
          <h2 className="text-3xl font-black dark:text-white text-center">{t.signupSteps.personalName}</h2>
          <input type="text" placeholder={t.signupSteps.personalName} value={signupData.fullName} onChange={e => setSignupData({...signupData, fullName: e.target.value})} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none focus:ring-2 focus:ring-brand" />
          <button onClick={() => signupData.fullName && setSignupStep(3)} className="w-full py-4 bg-brand text-white rounded-2xl font-bold">{t.next}</button>
        </div>
      )}

      {signupStep === 3 && (
        <div className="space-y-6">
          <h2 className="text-3xl font-black dark:text-white text-center">{t.signupSteps.userName}</h2>
          <input type="text" placeholder={t.signupSteps.userName} value={signupData.username} onChange={e => setSignupData({...signupData, username: e.target.value})} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none focus:ring-2 focus:ring-brand" />
          <button onClick={() => signupData.username && setSignupStep(4)} className="w-full py-4 bg-brand text-white rounded-2xl font-bold">{t.next}</button>
        </div>
      )}

      {signupStep === 4 && (
        <div className="space-y-6 text-center">
          <h2 className="text-3xl font-black dark:text-white">{t.signupSteps.geolocation}</h2>
          <div className="p-10 border-2 border-dashed rounded-3xl text-gray-400">
             <MapPin size={48} className="mx-auto mb-4 text-brand" />
             <p className="text-sm">{signupData.location.address || (lang === 'ar' ? 'حدد موقعك الجغرافي' : 'Click to fetch location')}</p>
          </div>
          <button onClick={() => setSignupData({...signupData, location: {address: 'Current Location Detected', lat: 24.7, lng: 46.6}})} className="w-full py-4 border-2 border-brand text-brand rounded-2xl font-bold flex items-center justify-center gap-2">📍 {lang === 'ar' ? 'تحديد الموقع الآن' : 'Fetch Location'}</button>
          <button onClick={() => signupData.location.address && setSignupStep(5)} className="w-full py-4 bg-brand text-white rounded-2xl font-bold disabled:opacity-50">{t.next}</button>
        </div>
      )}

      {signupStep === 5 && (
        <div className="space-y-6">
          <h2 className="text-3xl font-black dark:text-white text-center">{t.signupSteps.credentials}</h2>
          <input type="email" placeholder="Email" value={signupData.email} onChange={e => setSignupData({...signupData, email: e.target.value})} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none" />
          <input type="password" placeholder="Password" value={signupData.password} onChange={e => setSignupData({...signupData, password: e.target.value})} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none" />
          <button onClick={() => signupData.email && signupData.password && setSignupStep(6)} className="w-full py-4 bg-brand text-white rounded-2xl font-bold">{t.next}</button>
        </div>
      )}

      {signupStep === 6 && (
        <div className="space-y-6">
          <h2 className="text-3xl font-black dark:text-white text-center">{t.signupSteps.privacy}</h2>
          <div className="p-6 bg-gray-50 dark:bg-gray-800 rounded-3xl text-xs text-gray-500 max-h-48 overflow-y-auto leading-relaxed border border-gray-100 dark:border-gray-700">
             {t.privacyPolicy}
             <p className="mt-4">By creating this account, you acknowledge that all items listed are for RENT only. Misuse will lead to account termination.</p>
          </div>
          <label className="flex items-center gap-2 cursor-pointer p-2">
             <input type="checkbox" checked={signupData.agreed} onChange={e => setSignupData({...signupData, agreed: e.target.checked})} className="w-5 h-5 accent-brand" />
             <span className="text-sm dark:text-white font-medium">{lang === 'ar' ? 'أوافق على سياسة الخصوصية وشروط الاستخدام' : 'I agree to the privacy policy and terms of use'}</span>
          </label>
          <button onClick={handleSignUpFinish} disabled={!signupData.agreed} className="w-full py-4 bg-brand text-white rounded-2xl font-bold disabled:opacity-50">Finish & Get Started</button>
        </div>
      )}
    </div>
  );

  return (
    <HashRouter>
      <div className={`min-h-screen ${isRtl ? 'rtl' : 'ltr'} bg-white dark:bg-gray-950 font-sans transition-colors duration-200`} dir={isRtl ? 'rtl' : 'ltr'}>
        <Navbar lang={lang} isDark={isDarkMode} toggleTheme={toggleTheme} user={user} />

        <main className="min-h-[calc(100vh-64px)] pb-20">
          <Routes>
            <Route path="/" element={<HomePage lang={lang} />} />
            <Route path="/support" element={<div className="p-4 pt-8"><SupportAI lang={lang as any} /></div>} />
            <Route path="/subscribe" element={<SubscriptionPage lang={lang} />} />
            <Route path="/create" element={user ? <CreateListingPage lang={lang} user={user} /> : <Navigate to="/profile" />} />
            <Route path="/chat/*" element={user ? <ChatPage lang={lang} /> : <Navigate to="/profile" />} />
            <Route path="/item/:id" element={<ItemDetailPage lang={lang} />} />
            <Route path="/profile" element={
              user ? (
                <div className="p-4 sm:p-8 text-center max-w-4xl mx-auto">
                  <div className="bg-white dark:bg-gray-900 rounded-[3rem] p-10 shadow-sm border border-gray-100 dark:border-gray-800">
                    <div className="w-32 h-32 mx-auto rounded-full overflow-hidden border-4 border-brand mb-4">
                      <img src={user.avatar || `https://api.dicebear.com/7.x/avataaars/svg?seed=${user.username}`} className="w-full h-full object-cover" />
                    </div>
                    <h1 className="text-3xl font-black dark:text-white">{user.fullName}</h1>
                    <p className="text-[#CCCCCC] mb-8">@{user.username}</p>

                    <div className="bg-gray-50 dark:bg-gray-800 rounded-3xl p-6 text-left mb-6">
                       <h3 className="font-bold flex items-center gap-2 mb-4 dark:text-white"><ShieldBan size={20} className="text-brand" /> {t.blockedList}</h3>
                       <div className="space-y-2">
                          {user.blockedUsers.length === 0 ? <p className="text-xs text-gray-400 italic">No accounts blocked yet.</p> : null}
                          {user.blockedUsers.map(uId => (
                            <div key={uId} className="flex justify-between items-center bg-white dark:bg-gray-900 p-3 rounded-xl border border-gray-100 dark:border-gray-700">
                               <span className="text-xs dark:text-white font-bold">User {uId}</span>
                               <button className="text-xs text-brand font-bold uppercase tracking-wider hover:underline">{t.unblock}</button>
                            </div>
                          ))}
                       </div>
                    </div>

                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                      <button onClick={() => window.location.hash = '#/subscribe'} className="p-4 bg-brand text-white rounded-3xl font-bold flex flex-col items-center gap-2 shadow-xl shadow-brand/20 hover:scale-[1.02] transition-transform"><Crown /> {t.subscribe}</button>
                      <button onClick={toggleTheme} className="p-4 bg-gray-100 dark:bg-gray-800 dark:text-white rounded-3xl font-bold flex flex-col items-center gap-2 hover:scale-[1.02] transition-transform">{isDarkMode ? <Sun /> : <Moon />} {isDarkMode ? 'Light' : 'Dark'}</button>
                    </div>

                    <div className="mt-8 pt-8 border-t dark:border-gray-800 flex justify-center gap-4">
                       <button onClick={() => setLang(lang === 'ar' ? 'en' : 'ar')} className="px-6 py-2 bg-gray-50 dark:bg-gray-800 rounded-full text-xs font-bold dark:text-white">
                         {lang === 'ar' ? 'English' : 'العربية'}
                       </button>
                    </div>

                    <button onClick={() => setUser(null)} className="mt-10 text-red-500 font-bold hover:underline">{t.logout}</button>
                  </div>
                </div>
              ) : <SignUpFlow />
            } />
            <Route path="*" element={<Navigate to="/" />} />
          </Routes>
        </main>

        <div className="fixed bottom-24 right-6 md:bottom-8 md:right-8 z-40">
          <button onClick={() => window.location.hash = '#/chat'} className="w-14 h-14 bg-brand text-white rounded-full shadow-2xl flex items-center justify-center hover:scale-110 active:scale-95 transition-all">
            <MessageCircle size={28} />
          </button>
        </div>
      </div>
    </HashRouter>
  );
};

export default App;

import React, { useState } from 'react';
import { translations } from '../i18n';
import { CATEGORIES } from '../constants';
import { CurrencyType, RentalPeriod, ListingType } from '../types';
import { checkListingContent } from '../services/geminiService';
import { Camera, Video, MapPin, Loader2, CheckCircle, ShieldCheck, CreditCard, Bitcoin, Wallet } from 'lucide-react';
import { useNavigate } from 'react-router-dom';

const CreateListingPage: React.FC<{ lang: string; user: any }> = ({ lang, user }) => {
  const t = translations[lang] || translations['en'];
  const navigate = useNavigate();
  const [step, setStep] = useState(1);
  const [loading, setLoading] = useState(false);

  const [images, setImages] = useState<string[]>([]);
  const [video, setVideo] = useState<string | null>(null);
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [category, setCategory] = useState(CATEGORIES[0]);
  const [currencyType, setCurrencyType] = useState<CurrencyType>(CurrencyType.LOCAL);
  const [payoutMethod, setPayoutMethod] = useState('');
  const [price, setPrice] = useState('');
  const [period, setPeriod] = useState<RentalPeriod>(RentalPeriod.DAY);
  const [location, setLocation] = useState(user?.location || { lat: 0, lng: 0, address: '' });

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      const files = Array.from(e.target.files).slice(0, 5) as File[];
      const urls = files.map(f => URL.createObjectURL(f));
      setImages(prev => [...prev, ...urls].slice(0, 5));
    }
  };

  const startAiCheck = async () => {
    setLoading(true);
    const result = await checkListingContent(title, description);
    if (result.status === 'APPROVED') {
      setStep(6);
    } else {
      alert(t.aiRejected + ": " + result.reason);
      setStep(2);
    }
    setLoading(false);
  };

  const finish = () => {
    navigate('/');
  };

  const cryptoOptions = [
    { name: 'Solana', icon: <Zap size={14} className="text-purple-500" /> },
    { name: 'Ethereum', icon: <Zap size={14} className="text-blue-500" /> },
    { name: 'Monad', icon: <Zap size={14} className="text-brand" /> },
    { name: 'Base', icon: <Zap size={14} className="text-blue-400" /> },
    { name: 'Sui', icon: <Zap size={14} className="text-teal-400" /> },
    { name: 'Polygon', icon: <Zap size={14} className="text-purple-600" /> },
    { name: 'Bitcoin', icon: <Bitcoin size={14} className="text-orange-500" /> }
  ];

  return (
    <div className="max-w-2xl mx-auto p-6 bg-white dark:bg-gray-900 rounded-[3rem] shadow-sm my-8 border border-gray-100 dark:border-gray-800">
      <div className="flex justify-between mb-8 px-4">
        {[1,2,3,4,5,6].map(s => (
          <div key={s} className={`w-3 h-3 rounded-full transition-all duration-300 ${step >= s ? 'bg-brand scale-125' : 'bg-gray-100 dark:bg-gray-800'}`} />
        ))}
      </div>

      {step === 1 && (
        <div className="space-y-6">
          <h2 className="text-2xl font-black dark:text-white">{lang === 'ar' ? 'رفع الوسائط' : 'Upload Media'}</h2>
          <div className="grid grid-cols-3 gap-3">
            {images.map((img, i) => (
              <div key={i} className="relative aspect-square">
                 <img src={img} className="w-full h-full object-cover rounded-2xl" />
                 <button onClick={() => setImages(images.filter((_, idx) => idx !== i))} className="absolute -top-2 -right-2 bg-red-500 text-white rounded-full p-1"><CheckCircle className="rotate-45" size={12} /></button>
              </div>
            ))}
            {images.length < 5 && (
              <label className="aspect-square border-2 border-dashed border-gray-200 dark:border-gray-700 rounded-2xl flex items-center justify-center cursor-pointer text-gray-400 hover:border-brand hover:text-brand transition-colors">
                <Camera size={32} /><input type="file" multiple accept="image/*" className="hidden" onChange={handleImageUpload} />
              </label>
            )}
          </div>
          <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">{lang === 'ar' ? '2 صور كحد أدنى، 5 صور كحد أقصى' : 'Min 2, Max 5 images'}</p>

          <div className="pt-4">
            <label className={`block p-4 border-2 rounded-2xl cursor-pointer transition-all ${video ? 'border-brand bg-brand/5' : 'border-gray-100 dark:border-gray-800'} dark:text-white`}>
              <div className="flex items-center justify-between">
                 <div className="flex items-center gap-2">
                    <Video className={video ? 'text-brand' : 'text-gray-400'} size={20} />
                    <span className="font-bold">{lang === 'ar' ? 'رفع فيديو المنتج' : 'Upload Product Video'}</span>
                 </div>
                 <span className="text-[10px] uppercase font-bold text-gray-400">({lang === 'ar' ? 'إختياري' : 'Optional'})</span>
              </div>
              <input type="file" accept="video/*" className="hidden" onChange={(e) => e.target.files && e.target.files[0] && setVideo(URL.createObjectURL(e.target.files[0]))} />
            </label>
          </div>

          <button disabled={images.length < 2} onClick={() => setStep(2)} className="w-full py-4 bg-brand text-white rounded-2xl font-bold shadow-xl shadow-brand/20 disabled:opacity-30 transition-all">{t.next}</button>
        </div>
      )}

      {step === 2 && (
        <div className="space-y-6">
          <h2 className="text-2xl font-black dark:text-white">{lang === 'ar' ? 'تفاصيل المنتج' : 'Item Details'}</h2>
          <div className="space-y-4">
            <input type="text" placeholder={lang === 'ar' ? 'إسم المنتج' : 'Item Name'} value={title} onChange={e => setTitle(e.target.value)} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none focus:ring-2 focus:ring-brand" />
            <textarea placeholder={lang === 'ar' ? 'وصف المنتج' : 'Description'} value={description} onChange={e => setDescription(e.target.value)} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white h-40 outline-none focus:ring-2 focus:ring-brand" />
            <select value={category} onChange={e => setCategory(e.target.value)} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none">
              {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
            </select>
          </div>
          <button disabled={!title || !description} onClick={() => setStep(3)} className="w-full py-4 bg-brand text-white rounded-2xl font-bold shadow-xl shadow-brand/20">{t.next}</button>
        </div>
      )}

      {step === 3 && (
        <div className="space-y-6">
          <h2 className="text-2xl font-black dark:text-white">{t.payoutMethod}</h2>
          <div className="flex gap-4 p-2 bg-gray-50 dark:bg-gray-800 rounded-3xl">
            <button 
              onClick={() => {setCurrencyType(CurrencyType.CRYPTO); setPayoutMethod('')}} 
              className={`flex-1 py-4 rounded-2xl font-bold flex items-center justify-center gap-2 transition-all ${currencyType === CurrencyType.CRYPTO ? 'bg-white dark:bg-gray-900 text-brand shadow-sm' : 'text-gray-400'}`}
            >
              <Bitcoin size={20} /> {t.crypto}
            </button>
            <button 
              onClick={() => {setCurrencyType(CurrencyType.LOCAL); setPayoutMethod('')}} 
              className={`flex-1 py-4 rounded-2xl font-bold flex items-center justify-center gap-2 transition-all ${currencyType === CurrencyType.LOCAL ? 'bg-white dark:bg-gray-900 text-brand shadow-sm' : 'text-gray-400'}`}
            >
              <CreditCard size={20} /> {t.local}
            </button>
          </div>

          <div className="p-4 bg-gray-50 dark:bg-gray-800 rounded-3xl min-h-[120px] flex flex-col justify-center">
            {currencyType === CurrencyType.CRYPTO ? (
              <div className="grid grid-cols-2 gap-2">
                {cryptoOptions.map(opt => (
                  <button 
                    key={opt.name}
                    onClick={() => setPayoutMethod(opt.name)}
                    className={`p-3 rounded-xl border-2 flex items-center gap-2 transition-all ${payoutMethod === opt.name ? 'border-brand bg-brand/5' : 'border-transparent bg-white dark:bg-gray-900 dark:text-white'}`}
                  >
                    {opt.icon} <span className="text-xs font-bold">{opt.name}</span>
                  </button>
                ))}
              </div>
            ) : (
              <div className="space-y-2">
                <p className="text-xs text-gray-500 font-bold uppercase text-center mb-2">PayPal payout</p>
                <input 
                  type="email" 
                  placeholder="PayPal Email Address" 
                  value={payoutMethod} 
                  onChange={e => setPayoutMethod(e.target.value)} 
                  className="w-full p-4 rounded-2xl bg-white dark:bg-gray-900 dark:text-white outline-none border-2 border-transparent focus:border-brand" 
                />
              </div>
            )}
          </div>

          <button disabled={!payoutMethod} onClick={() => setStep(4)} className="w-full py-4 bg-brand text-white rounded-2xl font-bold shadow-xl shadow-brand/20 disabled:opacity-30">{t.next}</button>
        </div>
      )}

      {step === 4 && (
        <div className="space-y-6">
          <h2 className="text-2xl font-black dark:text-white">{lang === 'ar' ? 'السعر ومدة التأجير' : 'Price & Rental Period'}</h2>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <div className="space-y-2">
               <label className="text-xs font-bold text-gray-400 uppercase">{t.price}</label>
               <input type="number" placeholder="0.00" value={price} onChange={e => setPrice(e.target.value)} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none focus:ring-2 focus:ring-brand" />
            </div>
            <div className="space-y-2">
               <label className="text-xs font-bold text-gray-400 uppercase">{t.rentalPeriod}</label>
               <select value={period} onChange={e => setPeriod(e.target.value as RentalPeriod)} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none">
                 {Object.keys(RentalPeriod).map(p => <option key={p} value={p}>{t.periods[p]}</option>)}
               </select>
            </div>
          </div>

          <div className="p-6 bg-gray-50 dark:bg-gray-800 rounded-3xl">
             <div className="flex items-center justify-between mb-2">
                <span className="font-bold dark:text-white">{t.location}</span>
                <span className="text-brand">📍</span>
             </div>
             <p className="text-sm text-gray-500">{location.address || 'User current location will be attached'}</p>
          </div>

          <button disabled={!price} onClick={() => setStep(5)} className="w-full py-4 bg-brand text-white rounded-2xl font-bold shadow-xl shadow-brand/20">{t.next}</button>
        </div>
      )}

      {step === 5 && (
        <div className="text-center py-12 space-y-6">
          <ShieldCheck size={72} className="mx-auto text-brand animate-pulse" />
          <h2 className="text-3xl font-black dark:text-white">{t.aiChecking}</h2>
          <p className="text-gray-500 max-w-sm mx-auto">{lang === 'ar' ? 'يقوم نظام AI My Rents الآن بفحص بيانات المنتج للتأكد من سلامته ومطابقته للشروط' : 'AI My Rents is now scanning your listing data for safety and policy compliance'}</p>
          <div className="pt-4">
             <button onClick={startAiCheck} className="px-10 py-4 bg-brand text-white rounded-2xl font-bold flex items-center justify-center gap-3 mx-auto">
               {loading ? <Loader2 className="animate-spin" /> : <><ShieldCheck size={20} /> Verify with AI</>}
             </button>
          </div>
        </div>
      )}

      {step === 6 && (
        <div className="text-center py-12 space-y-6 animate-in zoom-in-95 duration-500">
          <CheckCircle size={72} className="mx-auto text-green-500" />
          <h2 className="text-3xl font-black dark:text-white">{t.aiApproved}</h2>
          <p className="text-gray-500">{lang === 'ar' ? 'تمت الموافقة على المنتج، يمكنك الآن إطلاقه في المنصة' : 'Your listing has been approved and is ready to be published.'}</p>
          <button onClick={finish} className="w-full py-4 bg-green-500 text-white rounded-2xl font-bold shadow-xl shadow-green-500/20">{lang === 'ar' ? 'إطلاق الإعلان الآن' : 'Publish Listing Now'}</button>
        </div>
      )}
    </div>
  );
};

export default CreateListingPage;

import React, { useState } from 'react';
import { translations } from '../i18n';
import { Mic, Image, Video, Trash2, MapPin, Flag, ShieldBan, Send, Users, UserPlus, Phone, MoreVertical, Search, ShieldCheck } from 'lucide-react';

const ChatPage: React.FC<{ lang: string }> = ({ lang }) => {
  const t = translations[lang] || translations['en'];
  const [activeTab, setActiveTab] = useState<'PRIVATE' | 'GROUPS'>('PRIVATE');
  const [messages, setMessages] = useState<any[]>([]);
  const [input, setInput] = useState('');
  const [showGroupCreate, setShowGroupCreate] = useState(false);

  // Group Create State
  const [groupData, setGroupData] = useState({ name: '', description: '', image: '' });

  const handleCreateGroup = () => {
    if (groupData.name && groupData.image) {
      alert(lang === 'ar' ? 'تم إنشاء المجموعة، أنت الآن المشرف!' : 'Group created! You are now the administrator.');
      setShowGroupCreate(false);
    }
  };

  const handleSend = () => {
    if (!input.trim()) return;
    setMessages([...messages, { id: Date.now(), text: input, sender: 'me' }]);
    setInput('');
  };

  return (
    <div className="max-w-6xl mx-auto flex h-[calc(100vh-160px)] mt-4 bg-white dark:bg-gray-900 rounded-[3rem] overflow-hidden shadow-2xl border border-gray-100 dark:border-gray-800">
