          </div>
          <button disabled={!title || !description} onClick={() => setStep(3)} className="w-full py-4 bg-brand text-white rounded-2xl font-bold shadow-xl shadow-brand/20">{t.next}</button>
        </div>
      )}

      {step === 3 && (
        <div className="space-y-6">
          <h2 className="text-2xl font-black dark:text-white">{t.payoutMethod}</h2>
          <div className="flex gap-4 p-2 bg-gray-50 dark:bg-gray-800 rounded-3xl">
            <button 
              onClick={() => {setCurrencyType(CurrencyType.CRYPTO); setPayoutMethod('')}} 
              className={`flex-1 py-4 rounded-2xl font-bold flex items-center justify-center gap-2 transition-all ${currencyType === CurrencyType.CRYPTO ? 'bg-white dark:bg-gray-900 text-brand shadow-sm' : 'text-gray-400'}`}
            >
              <Bitcoin size={20} /> {t.crypto}
            </button>
            <button 
              onClick={() => {setCurrencyType(CurrencyType.LOCAL); setPayoutMethod('')}} 
              className={`flex-1 py-4 rounded-2xl font-bold flex items-center justify-center gap-2 transition-all ${currencyType === CurrencyType.LOCAL ? 'bg-white dark:bg-gray-900 text-brand shadow-sm' : 'text-gray-400'}`}
            >
              <CreditCard size={20} /> {t.local}
            </button>
          </div>

          <div className="p-4 bg-gray-50 dark:bg-gray-800 rounded-3xl min-h-[120px] flex flex-col justify-center">
            {currencyType === CurrencyType.CRYPTO ? (
              <div className="grid grid-cols-2 gap-2">
                {cryptoOptions.map(opt => (
                  <button 
                    key={opt.name}
                    onClick={() => setPayoutMethod(opt.name)}
                    className={`p-3 rounded-xl border-2 flex items-center gap-2 transition-all ${payoutMethod === opt.name ? 'border-brand bg-brand/5' : 'border-transparent bg-white dark:bg-gray-900 dark:text-white'}`}
                  >
                    {opt.icon} <span className="text-xs font-bold">{opt.name}</span>
                  </button>
                ))}
              </div>
            ) : (
              <div className="space-y-2">
                <p className="text-xs text-gray-500 font-bold uppercase text-center mb-2">PayPal payout</p>
                <input 
                  type="email" 
                  placeholder="PayPal Email Address" 
                  value={payoutMethod} 
                  onChange={e => setPayoutMethod(e.target.value)} 
                  className="w-full p-4 rounded-2xl bg-white dark:bg-gray-900 dark:text-white outline-none border-2 border-transparent focus:border-brand" 
                />
              </div>
            )}
          </div>

          <button disabled={!payoutMethod} onClick={() => setStep(4)} className="w-full py-4 bg-brand text-white rounded-2xl font-bold shadow-xl shadow-brand/20 disabled:opacity-30">{t.next}</button>
        </div>
      )}

      {step === 4 && (
        <div className="space-y-6">
          <h2 className="text-2xl font-black dark:text-white">{lang === 'ar' ? 'السعر ومدة التأجير' : 'Price & Rental Period'}</h2>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <div className="space-y-2">
               <label className="text-xs font-bold text-gray-400 uppercase">{t.price}</label>
               <input type="number" placeholder="0.00" value={price} onChange={e => setPrice(e.target.value)} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none focus:ring-2 focus:ring-brand" />
            </div>
            <div className="space-y-2">
               <label className="text-xs font-bold text-gray-400 uppercase">{t.rentalPeriod}</label>
               <select value={period} onChange={e => setPeriod(e.target.value as RentalPeriod)} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none">
                 {Object.keys(RentalPeriod).map(p => <option key={p} value={p}>{t.periods[p]}</option>)}
               </select>
            </div>
          </div>

          <div className="p-6 bg-gray-50 dark:bg-gray-800 rounded-3xl">
             <div className="flex items-center justify-between mb-2">
                <span className="font-bold dark:text-white">{t.location}</span>
                <span className="text-brand">📍</span>
             </div>
             <p className="text-sm text-gray-500">{location.address || 'User current location will be attached'}</p>
          </div>

          <button disabled={!price} onClick={() => setStep(5)} className="w-full py-4 bg-brand text-white rounded-2xl font-bold shadow-xl shadow-brand/20">{t.next}</button>
        </div>
      )}

      {step === 5 && (
        <div className="text-center py-12 space-y-6">
          <ShieldCheck size={72} className="mx-auto text-brand animate-pulse" />
          <h2 className="text-3xl font-black dark:text-white">{t.aiChecking}</h2>
          <p className="text-gray-500 max-w-sm mx-auto">{lang === 'ar' ? 'يقوم نظام AI My Rents الآن بفحص بيانات المنتج للتأكد من سلامته ومطابقته للشروط' : 'AI My Rents is now scanning your listing data for safety and policy compliance'}</p>
          <div className="pt-4">
             <button onClick={startAiCheck} className="px-10 py-4 bg-brand text-white rounded-2xl font-bold flex items-center justify-center gap-3 mx-auto">
               {loading ? <Loader2 className="animate-spin" /> : <><ShieldCheck size={20} /> Verify with AI</>}
             </button>
          </div>
        </div>
      )}

      {step === 6 && (
        <div className="text-center py-12 space-y-6 animate-in zoom-in-95 duration-500">
          <CheckCircle size={72} className="mx-auto text-green-500" />
          <h2 className="text-3xl font-black dark:text-white">{t.aiApproved}</h2>
          <p className="text-gray-500">{lang === 'ar' ? 'تمت الموافقة على المنتج، يمكنك الآن إطلاقه في المنصة' : 'Your listing has been approved and is ready to be published.'}</p>
          <button onClick={finish} className="w-full py-4 bg-green-500 text-white rounded-2xl font-bold shadow-xl shadow-green-500/20">{lang === 'ar' ? 'إطلاق الإعلان الآن' : 'Publish Listing Now'}</button>
        </div>
      )}
    </div>
