             <button onClick={() => setMessages([])} className="p-2.5 text-gray-400 hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-900/10 rounded-xl transition-all" title="Clear Chat"><Trash2 size={18} /></button>
             <button className="p-2.5 text-gray-400 hover:text-brand hover:bg-brand/5 rounded-xl transition-all"><Flag size={18} /></button>
             <button className="p-2.5 text-gray-400 hover:text-brand hover:bg-brand/5 rounded-xl transition-all"><ShieldBan size={18} /></button>
          </div>
        </div>

        <div className="flex-1 p-6 overflow-y-auto bg-gray-50/50 dark:bg-gray-950/30 space-y-4">
           {messages.length === 0 ? (
             <div className="h-full flex flex-col items-center justify-center opacity-30 text-center">
                <ShieldCheck size={64} className="mb-4 text-brand" />
                <p className="text-sm font-bold dark:text-white max-w-xs leading-relaxed">Safety is our priority. All conversations are analyzed by My Rents AI for protection.</p>
             </div>
           ) : (
             messages.map(m => (
               <div key={m.id} className="flex justify-end">
                  <div className="bg-brand text-white p-4 rounded-3xl rounded-tr-none text-sm font-medium shadow-lg shadow-brand/10">{m.text}</div>
               </div>
             ))
           )}
        </div>

        {/* Input Bar */}
        <div className="p-6 bg-white dark:bg-gray-900 border-t dark:border-gray-800">
           <div className="flex items-center gap-4 mb-4">
              <button className="p-2.5 text-gray-400 hover:text-brand bg-gray-50 dark:bg-gray-800 rounded-xl transition-all" title="Voice"><Mic size={20} /></button>
              <button className="p-2.5 text-gray-400 hover:text-brand bg-gray-50 dark:bg-gray-800 rounded-xl transition-all" title="Image"><Image size={20} /></button>
              <button className="p-2.5 text-gray-400 hover:text-brand bg-gray-50 dark:bg-gray-800 rounded-xl transition-all" title="Video"><Video size={20} /></button>
              <button onClick={() => alert('Sending Current Location...')} className="p-2.5 text-gray-400 hover:text-brand bg-gray-50 dark:bg-gray-800 rounded-xl transition-all" title="Location"><MapPin size={20} /></button>
           </div>
           <div className="flex gap-3">
              <input 
                type="text" 
                value={input} 
                onChange={e => setInput(e.target.value)}
                onKeyDown={e => e.key === 'Enter' && handleSend()}
                className="flex-1 bg-gray-100 dark:bg-gray-800 dark:text-white px-6 py-4 rounded-3xl outline-none focus:ring-2 focus:ring-brand font-medium" 
                placeholder="Message securely..."
              />
              <button onClick={handleSend} className="p-4 bg-brand text-white rounded-3xl shadow-xl shadow-brand/20 hover:scale-105 active:scale-95 transition-all">
                <Send size={24} />
              </button>
           </div>
        </div>
      </div>

      {/* Group Create Modal */}
      {showGroupCreate && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
           <div className="bg-white dark:bg-gray-900 w-full max-w-md rounded-[3rem] p-10 animate-in zoom-in-95 duration-200">
              <h3 className="text-2xl font-black mb-6 dark:text-white text-center">{t.createGroup}</h3>
              <div className="space-y-4">
                 <label className="w-24 h-24 rounded-3xl bg-gray-100 dark:bg-gray-800 mx-auto flex items-center justify-center border-4 border-dashed border-brand cursor-pointer overflow-hidden relative group">
                   {groupData.image ? <img src={groupData.image} className="w-full h-full object-cover" /> : <Camera size={32} className="text-gray-400" />}
                   <input type="file" className="hidden" onChange={e => e.target.files && setGroupData({...groupData, image: URL.createObjectURL(e.target.files[0])})} />
                 </label>
                 <input type="text" placeholder="Group Name" value={groupData.name} onChange={e => setGroupData({...groupData, name: e.target.value})} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none focus:ring-2 focus:ring-brand" />
                 <textarea placeholder="Description" value={groupData.description} onChange={e => setGroupData({...groupData, description: e.target.value})} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white h-24 outline-none focus:ring-2 focus:ring-brand" />
              </div>
              <div className="flex gap-2 mt-8">
                 <button onClick={() => setShowGroupCreate(false)} className="flex-1 py-4 text-gray-400 font-bold uppercase tracking-widest text-xs">{t.back}</button>
                 <button onClick={handleCreateGroup} disabled={!groupData.name || !groupData.image} className="flex-[2] py-4 bg-brand text-white rounded-2xl font-bold shadow-xl shadow-brand/20 disabled:opacity-30">{t.submit}</button>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

