            <code className="text-xs break-all text-brand font-black font-mono">{WALLETS[selectedWallet as keyof typeof WALLETS]}</code>
            <button onClick={() => copyToClipboard(WALLETS[selectedWallet as keyof typeof WALLETS])} className="text-gray-400 hover:text-brand p-2 rounded-lg bg-gray-50 dark:bg-gray-800 transition-colors ml-2">
