      <div className="flex gap-4">
        <button onClick={prevStep} className="flex-1 py-4 border-2 border-gray-100 dark:border-gray-800 rounded-2xl font-bold dark:text-white flex items-center justify-center gap-2 hover:bg-gray-50 dark:hover:bg-gray-800 transition-all">
