      </div>

      <button 
        onClick={() => navigate('/')}
        className="w-full max-w-sm py-4 bg-gray-950 dark:bg-white dark:text-gray-950 text-white rounded-2xl font-black text-lg shadow-2xl hover:scale-[1.02] active:scale-95 transition-all flex items-center justify-center gap-2 mx-auto"
      >
        {t.returnHome}
      </button>
    </div>
  );

  return (
    <div className="max-w-4xl mx-auto p-4 pt-10 pb-20">
      {/* Progress Bar */}
      <div className="flex justify-between items-center mb-16 px-4 relative">
        <div className="absolute top-1/2 left-0 right-0 h-1.5 bg-gray-100 dark:bg-gray-800 -translate-y-1/2 -z-10 rounded-full"></div>
        <div 
          className="absolute top-1/2 left-0 h-1.5 bg-brand -translate-y-1/2 -z-10 transition-all duration-700 rounded-full" 
          style={{ width: `${(step - 1) * 25}%` }}
        ></div>
        {[1, 2, 3, 4, 5].map(s => (
          <div 
            key={s} 
            className={`w-10 h-10 rounded-2xl flex items-center justify-center font-black text-sm transition-all duration-700 ${s <= step ? 'bg-brand text-white scale-110 shadow-xl shadow-brand/40 rotate-0' : 'bg-white dark:bg-gray-800 text-gray-400 border-2 border-gray-100 dark:border-gray-700 rotate-12'}`}
          >
            {s < step ? <CheckCircle size={20} /> : s}
          </div>
        ))}
      </div>

      <h1 className="text-4xl font-black mb-12 dark:text-white text-center leading-tight">
        {step === 1 && t.choosePlan}
        {step === 2 && t.chooseWallet}
        {step === 3 && t.enterYourWallet}
        {step === 4 && t.enterVerifyCode}
        {step === 5 && t.subSuccess}
      </h1>

      <div className="min-h-[500px]">
        {step === 1 && renderStep1()}
        {step === 2 && renderStep2()}
        {step === 3 && renderStep3()}
        {step === 4 && renderStep4()}
        {step === 5 && renderStep5()}
      </div>
    </div>
  );
};

