import React, { useState, useEffect } from 'react';
import { HashRouter, Routes, Route, Navigate, Link } from 'react-router-dom';
import { User, Gender, PayoutMethods } from './types';
import Navbar from './components/Navbar';
import HomePage from './pages/HomePage';
import SupportAI from './components/SupportAI';
import SubscriptionPage from './pages/SubscriptionPage';
import ItemDetailPage from './pages/ItemDetailPage';
import CreateListingPage from './pages/CreateListingPage';
import ChatPage from './pages/ChatPage';
import PrivacyPolicyPage from './pages/PrivacyPolicyPage';
import TermsOfUsePage from './pages/TermsOfUsePage';
import { translations } from './i18n';
import { MessageCircle, Globe, UserPlus, Share2, Crown, Wallet, CreditCard, Save, Bitcoin, Zap, ShieldBan, MapPin, Camera, Lock, Sun, Moon, Trash2, ShieldCheck, CheckCircle, FileText, Shield } from 'lucide-react';

const App: React.FC = () => {
  const [lang, setLang] = useState<string>('ar');
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [user, setUser] = useState<User | null>(null);

  // SignUp State
  const [signupStep, setSignupStep] = useState(1);
  const [signupData, setSignupData] = useState({
    avatar: '',
    fullName: '',
    username: '',
    location: { address: '', lat: 0, lng: 0 },
    email: '',
    password: '',
    agreed: false
  });

  useEffect(() => {
    if (isDarkMode) document.documentElement.classList.add('dark');
    else document.documentElement.classList.remove('dark');
  }, [isDarkMode]);

  const toggleTheme = () => setIsDarkMode(!isDarkMode);
  const t = translations[lang] || translations['en'];
  const isRtl = t.dir === 'rtl';

  const handleSignUpFinish = () => {
    const newUser: User = {
      id: 'u_' + Date.now(),
      fullName: signupData.fullName,
      username: signupData.username,
      email: signupData.email,
      avatar: signupData.avatar,
      gender: Gender.OTHER,
      birthDate: '2000-01-01',
      location: signupData.location,
      status: 'Member',
      points: 0,
      listingsCount: 0,
      walletBalance: 0,
      payoutMethods: {},
      blockedUsers: []
    };
    setUser(newUser);
  };

  const SignUpFlow = () => (
    <div className="max-w-xl mx-auto mt-10 bg-white dark:bg-gray-900 p-10 rounded-[3rem] shadow-2xl border border-gray-100 dark:border-gray-800">
      <div className="flex justify-center mb-8 gap-2">
        {[1,2,3,4,5,6].map(s => <div key={s} className={`w-2 h-2 rounded-full ${signupStep >= s ? 'bg-brand' : 'bg-gray-200'}`} />)}
      </div>

      {signupStep === 1 && (
        <div className="space-y-6 text-center">
          <h2 className="text-3xl font-black dark:text-white">{t.signupSteps.profilePic}</h2>
          <label className="w-32 h-32 rounded-full bg-gray-100 dark:bg-gray-800 mx-auto flex items-center justify-center border-4 border-brand cursor-pointer overflow-hidden relative group">
             {signupData.avatar ? <img src={signupData.avatar} className="w-full h-full object-cover" /> : <Camera size={40} className="text-gray-400" />}
             <input type="file" className="hidden" onChange={e => e.target.files && setSignupData({...signupData, avatar: URL.createObjectURL(e.target.files[0])})} />
          </label>
          <button onClick={() => signupData.avatar && setSignupStep(2)} className="w-full py-4 bg-brand text-white rounded-2xl font-bold disabled:opacity-50">{t.next}</button>
        </div>
      )}

      {signupStep === 2 && (
        <div className="space-y-6">
          <h2 className="text-3xl font-black dark:text-white text-center">{t.signupSteps.personalName}</h2>
          <input type="text" placeholder={t.signupSteps.personalName} value={signupData.fullName} onChange={e => setSignupData({...signupData, fullName: e.target.value})} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none focus:ring-2 focus:ring-brand" />
          <button onClick={() => signupData.fullName && setSignupStep(3)} className="w-full py-4 bg-brand text-white rounded-2xl font-bold">{t.next}</button>
        </div>
      )}

      {signupStep === 3 && (
        <div className="space-y-6">
          <h2 className="text-3xl font-black dark:text-white text-center">{t.signupSteps.userName}</h2>
          <input type="text" placeholder={t.signupSteps.userName} value={signupData.username} onChange={e => setSignupData({...signupData, username: e.target.value})} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none focus:ring-2 focus:ring-brand" />
          <button onClick={() => signupData.username && setSignupStep(4)} className="w-full py-4 bg-brand text-white rounded-2xl font-bold">{t.next}</button>
        </div>
      )}

      {signupStep === 4 && (
        <div className="space-y-6 text-center">
          <h2 className="text-3xl font-black dark:text-white">{t.signupSteps.geolocation}</h2>
          <div className="p-10 border-2 border-dashed rounded-3xl text-gray-400">
             <MapPin size={48} className="mx-auto mb-4 text-brand" />
             <p className="text-sm">{signupData.location.address || (lang === 'ar' ? 'حدد موقعك الجغرافي' : 'Click to fetch location')}</p>
          </div>
          <button onClick={() => setSignupData({...signupData, location: {address: 'Current Location Detected', lat: 24.7, lng: 46.6}})} className="w-full py-4 border-2 border-brand text-brand rounded-2xl font-bold flex items-center justify-center gap-2">📍 {lang === 'ar' ? 'تحديد الموقع الآن' : 'Fetch Location'}</button>
          <button onClick={() => signupData.location.address && setSignupStep(5)} className="w-full py-4 bg-brand text-white rounded-2xl font-bold disabled:opacity-50">{t.next}</button>
        </div>
      )}

      {signupStep === 5 && (
        <div className="space-y-6">
          <h2 className="text-3xl font-black dark:text-white text-center">{t.signupSteps.credentials}</h2>
          <input type="email" placeholder="Email" value={signupData.email} onChange={e => setSignupData({...signupData, email: e.target.value})} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none" />
          <input type="password" placeholder="Password" value={signupData.password} onChange={e => setSignupData({...signupData, password: e.target.value})} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none" />
          <button onClick={() => signupData.email && signupData.password && setSignupStep(6)} className="w-full py-4 bg-brand text-white rounded-2xl font-bold">{t.next}</button>
        </div>
      )}

      {signupStep === 6 && (
        <div className="space-y-6">
          <h2 className="text-3xl font-black dark:text-white text-center">{t.signupSteps.privacy}</h2>
          <div className="p-6 bg-gray-50 dark:bg-gray-800 rounded-3xl text-xs text-gray-500 max-h-48 overflow-y-auto leading-relaxed border border-gray-100 dark:border-gray-700">
             <p className="font-bold mb-2">{t.privacyPolicyDesc}</p>
             <p className="mb-2">1. My Rents is for RENTAL ONLY. Sales are prohibited.</p>
             <p className="mb-2">2. We collect geolocation to facilitate local transactions.</p>
             <p className="mb-2">3. All media is scanned by AI for safety.</p>
             <div className="flex gap-4 mt-4">
                <Link to="/privacy" className="text-brand font-bold underline">{t.privacyPolicy}</Link>
                <Link to="/terms" className="text-brand font-bold underline">{t.termsOfUse}</Link>
             </div>
          </div>
          <label className="flex items-center gap-2 cursor-pointer p-2">
             <input type="checkbox" checked={signupData.agreed} onChange={e => setSignupData({...signupData, agreed: e.target.checked})} className="w-5 h-5 accent-brand" />
             <span className="text-sm dark:text-white font-medium">{lang === 'ar' ? 'أوافق على سياسة الخصوصية وشروط الاستخدام' : 'I agree to the privacy policy and terms of use'}</span>
          </label>
          <button onClick={handleSignUpFinish} disabled={!signupData.agreed} className="w-full py-4 bg-brand text-white rounded-2xl font-bold disabled:opacity-50">Finish & Get Started</button>
        </div>
      )}
    </div>
  );

  return (
    <HashRouter>
      <div className={`min-h-screen ${isRtl ? 'rtl' : 'ltr'} bg-white dark:bg-gray-950 font-sans transition-colors duration-200`} dir={isRtl ? 'rtl' : 'ltr'}>
        <Navbar lang={lang} isDark={isDarkMode} toggleTheme={toggleTheme} user={user} />

        <main className="min-h-[calc(100vh-64px)] pb-20">
          <Routes>
            <Route path="/" element={<HomePage lang={lang} />} />
            <Route path="/support" element={<div className="p-4 pt-8"><SupportAI lang={lang as any} /></div>} />
            <Route path="/subscribe" element={<SubscriptionPage lang={lang} />} />
            <Route path="/create" element={user ? <CreateListingPage lang={lang} user={user} /> : <Navigate to="/profile" />} />
            <Route path="/chat/*" element={user ? <ChatPage lang={lang} /> : <Navigate to="/profile" />} />
            <Route path="/item/:id" element={<ItemDetailPage lang={lang} />} />
            <Route path="/privacy" element={<PrivacyPolicyPage lang={lang} />} />
            <Route path="/terms" element={<TermsOfUsePage lang={lang} />} />
            <Route path="/profile" element={
              user ? (
                <div className="p-4 sm:p-8 text-center max-w-4xl mx-auto">
                  <div className="bg-white dark:bg-gray-900 rounded-[3rem] p-10 shadow-sm border border-gray-100 dark:border-gray-800">
                    <div className="w-32 h-32 mx-auto rounded-full overflow-hidden border-4 border-brand mb-4">
                      <img src={user.avatar || `https://api.dicebear.com/7.x/avataaars/svg?seed=${user.username}`} className="w-full h-full object-cover" />
                    </div>
                    <h1 className="text-3xl font-black dark:text-white">{user.fullName}</h1>
                    <p className="text-[#CCCCCC] mb-8">@{user.username}</p>

                    <div className="bg-gray-50 dark:bg-gray-800 rounded-3xl p-6 text-left mb-6">
                       <h3 className="font-bold flex items-center gap-2 mb-4 dark:text-white"><ShieldBan size={20} className="text-brand" /> {t.blockedList}</h3>
                       <div className="space-y-2">
                          {user.blockedUsers.length === 0 ? <p className="text-xs text-gray-400 italic">No accounts blocked yet.</p> : null}
                          {user.blockedUsers.map(uId => (
                            <div key={uId} className="flex justify-between items-center bg-white dark:bg-gray-900 p-3 rounded-xl border border-gray-100 dark:border-gray-700">
                               <span className="text-xs dark:text-white font-bold">User {uId}</span>
                               <button className="text-xs text-brand font-bold uppercase tracking-wider hover:underline">{t.unblock}</button>
                            </div>
                          ))}
                       </div>
                    </div>

                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                      <button onClick={() => window.location.hash = '#/subscribe'} className="p-4 bg-brand text-white rounded-3xl font-bold flex flex-col items-center gap-2 shadow-xl shadow-brand/20 hover:scale-[1.02] transition-transform"><Crown /> {t.subscribe}</button>
                      <button onClick={toggleTheme} className="p-4 bg-gray-100 dark:bg-gray-800 dark:text-white rounded-3xl font-bold flex flex-col items-center gap-2 hover:scale-[1.02] transition-transform">{isDarkMode ? <Sun /> : <Moon />} {isDarkMode ? 'Light' : 'Dark'}</button>
                    </div>

                    <div className="mt-8 pt-8 border-t dark:border-gray-800 flex flex-col gap-4">
                       <div className="flex justify-center gap-4">
                         <button onClick={() => setLang(lang === 'ar' ? 'en' : 'ar')} className="px-6 py-2 bg-gray-50 dark:bg-gray-800 rounded-full text-xs font-bold dark:text-white">
                           {lang === 'ar' ? 'English' : 'العربية'}
                         </button>
                       </div>
                       <div className="flex justify-center gap-6 text-[10px] uppercase font-bold text-gray-400">
                          <Link to="/privacy" className="flex items-center gap-1 hover:text-brand transition-colors"><Shield size={12} /> {t.privacyPolicy}</Link>
                          <Link to="/terms" className="flex items-center gap-1 hover:text-brand transition-colors"><FileText size={12} /> {t.termsOfUse}</Link>
                       </div>
                    </div>

                    <button onClick={() => setUser(null)} className="mt-10 text-red-500 font-bold hover:underline">{t.logout}</button>
                  </div>
                </div>
              ) : <SignUpFlow />
            } />
            <Route path="*" element={<Navigate to="/" />} />
          </Routes>
        </main>

        <div className="fixed bottom-24 right-6 md:bottom-8 md:right-8 z-40">
          <button onClick={() => window.location.hash = '#/chat'} className="w-14 h-14 bg-brand text-white rounded-full shadow-2xl flex items-center justify-center hover:scale-110 active:scale-95 transition-all">
            <MessageCircle size={28} />
          </button>
        </div>
      </div>
    </HashRouter>
  );
};

