          <button onClick={() => signupData.fullName && setSignupStep(3)} className="w-full py-4 bg-brand text-white rounded-2xl font-bold shadow-lg shadow-brand/20 transition-all">{t.next}</button>
        </div>
      )}

      {signupStep === 3 && (
        <div className="space-y-6">
          <h2 className="text-2xl sm:text-3xl font-black dark:text-white text-center">{t.signupSteps.userName}</h2>
          <input type="text" placeholder={t.signupSteps.userName} value={signupData.username} onChange={e => setSignupData({...signupData, username: e.target.value})} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none focus:ring-2 focus:ring-brand border border-transparent" />
          <button onClick={() => signupData.username && setSignupStep(4)} className="w-full py-4 bg-brand text-white rounded-2xl font-bold shadow-lg shadow-brand/20 transition-all">{t.next}</button>
