          <input type="password" placeholder="Password" value={signupData.password} onChange={e => setSignupData({...signupData, password: e.target.value})} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none focus:ring-2 focus:ring-brand border border-transparent" />
          <button onClick={() => signupData.email && signupData.password && setSignupStep(6)} className="w-full py-4 bg-brand text-white rounded-2xl font-bold shadow-lg shadow-brand/20 transition-all">{t.next}</button>
        </div>
      )}

      {signupStep === 6 && (
