          <button onClick={handleSignUpFinish} disabled={!signupData.agreed} className="w-full py-4 bg-brand text-white rounded-2xl font-bold shadow-xl shadow-brand/20 disabled:opacity-50 transition-all transform hover:scale-[1.01] active:scale-95">Finish & Get Started</button>
        </div>
      )}
    </div>
  );

  return (
    <HashRouter>
      <div className={`min-h-screen ${isRtl ? 'rtl' : 'ltr'} bg-white dark:bg-gray-950 font-sans transition-colors duration-200`} dir={isRtl ? 'rtl' : 'ltr'}>
