import HomePage from './pages/HomePage';
import SupportAI from './components/SupportAI';
import SubscriptionPage from './pages/SubscriptionPage';
import ItemDetailPage from './pages/ItemDetailPage';
import CreateListingPage from './pages/CreateListingPage';
import ChatPage from './pages/ChatPage';
import PrivacyPolicyPage from './pages/PrivacyPolicyPage';
import TermsOfUsePage from './pages/TermsOfUsePage';
import { translations } from './i18n';
import { MessageCircle, Globe, UserPlus, Share2, Crown, Wallet, CreditCard, Save, Bitcoin, Zap, ShieldBan, MapPin, Camera, Lock, Sun, Moon, Trash2, ShieldCheck, CheckCircle, FileText, Shield } from 'lucide-react';

const App: React.FC = () => {
  const [lang, setLang] = useState<string>('ar');
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [user, setUser] = useState<User | null>(null);

  // SignUp State
  const [signupStep, setSignupStep] = useState(1);
  const [signupData, setSignupData] = useState({
    avatar: '',
    fullName: '',
    username: '',
    location: { address: '', lat: 0, lng: 0 },
    email: '',
    password: '',
    agreed: false
  });

  useEffect(() => {
    if (isDarkMode) document.documentElement.classList.add('dark');
    else document.documentElement.classList.remove('dark');
  }, [isDarkMode]);

  const toggleTheme = () => setIsDarkMode(!isDarkMode);
  const t = translations[lang] || translations['en'];
  const isRtl = t.dir === 'rtl';

  const handleSignUpFinish = () => {
    const newUser: User = {
      id: 'u_' + Date.now(),
      fullName: signupData.fullName,
      username: signupData.username,
      email: signupData.email,
      avatar: signupData.avatar,
      gender: Gender.OTHER,
      birthDate: '2000-01-01',
      location: signupData.location,
      status: 'Member',
      points: 0,
      listingsCount: 0,
      walletBalance: 0,
      payoutMethods: {},
      blockedUsers: []
    };
    setUser(newUser);
  };

  const SignUpFlow = () => (
    <div className="max-w-xl mx-auto mt-10 px-4 sm:px-0 bg-white dark:bg-gray-900 p-6 sm:p-10 rounded-[2rem] sm:rounded-[3rem] shadow-2xl border border-gray-100 dark:border-gray-800 animate-in fade-in zoom-in-95 duration-500">
      <div className="flex justify-center mb-8 gap-2">
        {[1,2,3,4,5,6].map(s => <div key={s} className={`w-2 h-2 rounded-full transition-all duration-300 ${signupStep >= s ? 'bg-brand scale-125' : 'bg-gray-200 dark:bg-gray-800'}`} />)}
      </div>

      <div className="min-h-[300px] flex flex-col">
        {signupStep === 1 && (
          <div className="space-y-6 text-center animate-in fade-in slide-in-from-bottom-4">
            <h2 className="text-2xl sm:text-3xl font-black dark:text-white">{t.signupSteps.profilePic}</h2>
            <label className="w-32 h-32 rounded-full bg-gray-100 dark:bg-gray-800 mx-auto flex items-center justify-center border-4 border-brand cursor-pointer overflow-hidden relative group">
               {signupData.avatar ? <img src={signupData.avatar} className="w-full h-full object-cover" /> : <Camera size={40} className="text-gray-400" />}
               <input type="file" className="hidden" onChange={e => e.target.files && setSignupData({...signupData, avatar: URL.createObjectURL(e.target.files[0])})} />
            </label>
            <button onClick={() => signupData.avatar && setSignupStep(2)} className="w-full py-4 bg-brand text-white rounded-2xl font-bold shadow-lg shadow-brand/20 disabled:opacity-50 hover:bg-brand-dark transition-all">{t.next}</button>
          </div>
        )}

        {signupStep === 2 && (
          <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4">
            <h2 className="text-2xl sm:text-3xl font-black dark:text-white text-center">{t.signupSteps.personalName}</h2>
            <input type="text" placeholder={t.signupSteps.personalName} value={signupData.fullName} onChange={e => setSignupData({...signupData, fullName: e.target.value})} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none focus:ring-2 focus:ring-brand border border-transparent" />
            <button onClick={() => signupData.fullName && setSignupStep(3)} className="w-full py-4 bg-brand text-white rounded-2xl font-bold shadow-lg shadow-brand/20 transition-all">{t.next}</button>
          </div>
        )}

        {signupStep === 3 && (
          <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4">
            <h2 className="text-2xl sm:text-3xl font-black dark:text-white text-center">{t.signupSteps.userName}</h2>
            <input type="text" placeholder={t.signupSteps.userName} value={signupData.username} onChange={e => setSignupData({...signupData, username: e.target.value})} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none focus:ring-2 focus:ring-brand border border-transparent" />
            <button onClick={() => signupData.username && setSignupStep(4)} className="w-full py-4 bg-brand text-white rounded-2xl font-bold shadow-lg shadow-brand/20 transition-all">{t.next}</button>
          </div>
        )}

        {signupStep === 4 && (
          <div className="space-y-6 text-center animate-in fade-in slide-in-from-bottom-4">
            <h2 className="text-2xl sm:text-3xl font-black dark:text-white">{t.signupSteps.geolocation}</h2>
            <div className="p-10 border-2 border-dashed border-gray-100 dark:border-gray-800 rounded-3xl text-gray-400">
               <MapPin size={48} className="mx-auto mb-4 text-brand" />
               <p className="text-sm">{signupData.location.address || (lang === 'ar' ? 'حدد موقعك الجغرافي' : 'Click to fetch location')}</p>
            </div>
            <button onClick={() => setSignupData({...signupData, location: {address: 'Current Location Detected', lat: 24.7, lng: 46.6}})} className="w-full py-4 border-2 border-brand text-brand rounded-2xl font-bold flex items-center justify-center gap-2 hover:bg-brand/5 transition-all">📍 {lang === 'ar' ? 'تحديد الموقع الآن' : 'Fetch Location'}</button>
            <button onClick={() => signupData.location.address && setSignupStep(5)} className="w-full py-4 bg-brand text-white rounded-2xl font-bold shadow-lg shadow-brand/20 disabled:opacity-50 transition-all">{t.next}</button>
          </div>
        )}

        {signupStep === 5 && (
          <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4">
            <h2 className="text-2xl sm:text-3xl font-black dark:text-white text-center">{t.signupSteps.credentials}</h2>
            <input type="email" placeholder="Email" value={signupData.email} onChange={e => setSignupData({...signupData, email: e.target.value})} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none focus:ring-2 focus:ring-brand border border-transparent" />
            <input type="password" placeholder="Password" value={signupData.password} onChange={e => setSignupData({...signupData, password: e.target.value})} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none focus:ring-2 focus:ring-brand border border-transparent" />
            <button onClick={() => signupData.email && signupData.password && setSignupStep(6)} className="w-full py-4 bg-brand text-white rounded-2xl font-bold shadow-lg shadow-brand/20 transition-all">{t.next}</button>
          </div>
        )}

        {signupStep === 6 && (
          <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4">
            <h2 className="text-2xl sm:text-3xl font-black dark:text-white text-center">{t.signupSteps.privacy}</h2>
            <div className="p-6 bg-gray-50 dark:bg-gray-800 rounded-3xl text-xs text-gray-500 max-h-48 overflow-y-auto leading-relaxed border border-gray-100 dark:border-gray-700 shadow-inner">
               <p className="font-bold mb-2 text-gray-700 dark:text-gray-300">{t.privacyPolicyDesc}</p>
               <p className="mb-2">1. My Rents is for RENTAL ONLY. Sales are prohibited.</p>
               <p className="mb-2">2. We collect geolocation to facilitate local transactions.</p>
               <p className="mb-2">3. All media is scanned by AI for safety.</p>
            </div>
            <label className="flex items-center gap-3 cursor-pointer p-2 hover:bg-gray-50 dark:hover:bg-gray-800 rounded-xl transition-all">
               <input type="checkbox" checked={signupData.agreed} onChange={e => setSignupData({...signupData, agreed: e.target.checked})} className="w-5 h-5 accent-brand rounded border-gray-300 text-brand focus:ring-brand" />
               <span className="text-sm dark:text-white font-medium">{lang === 'ar' ? 'أوافق على الشروط والأحكام' : 'I agree to the terms and conditions'}</span>
            </label>
            <button onClick={handleSignUpFinish} disabled={!signupData.agreed} className="w-full py-4 bg-brand text-white rounded-2xl font-bold shadow-xl shadow-brand/20 disabled:opacity-50 transition-all transform hover:scale-[1.01] active:scale-95">Finish & Get Started</button>
