                      <img src={user.avatar || `https://api.dicebear.com/7.x/avataaars/svg?seed=${user.username}`} className="w-full h-full object-cover" />
                    </div>
                    <h1 className="text-3xl font-black dark:text-white">{user.fullName}</h1>
                    <p className="text-[#CCCCCC] mb-8">@{user.username}</p>

                    <div className="bg-gray-50 dark:bg-gray-800 rounded-3xl p-6 text-left mb-6">
                       <h3 className="font-bold flex items-center gap-2 mb-4 dark:text-white"><ShieldBan size={20} className="text-brand" /> {t.blockedList}</h3>
                       <div className="space-y-2">
                          {user.blockedUsers.length === 0 ? <p className="text-xs text-gray-400 italic">No accounts blocked yet.</p> : null}
                          {user.blockedUsers.map(uId => (
                            <div key={uId} className="flex justify-between items-center bg-white dark:bg-gray-900 p-3 rounded-xl border border-gray-100 dark:border-gray-700">
                               <span className="text-xs dark:text-white font-bold">User {uId}</span>
                               <button className="text-xs text-brand font-bold uppercase tracking-wider hover:underline">{t.unblock}</button>
                            </div>
                          ))}
                       </div>
                    </div>

                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                      <button onClick={() => window.location.hash = '#/subscribe'} className="p-4 bg-brand text-white rounded-3xl font-bold flex flex-col items-center gap-2 shadow-xl shadow-brand/20 hover:scale-[1.02] transition-transform"><Crown /> {t.subscribe}</button>
                      <button onClick={toggleTheme} className="p-4 bg-gray-100 dark:bg-gray-800 dark:text-white rounded-3xl font-bold flex flex-col items-center gap-2 hover:scale-[1.02] transition-transform">{isDarkMode ? <Sun /> : <Moon />} {isDarkMode ? 'Light' : 'Dark'}</button>
                    </div>

                    <div className="mt-8 pt-8 border-t dark:border-gray-800 flex flex-col gap-6">
                       <div className="flex justify-center gap-4">
                         <button onClick={() => setLang(lang === 'ar' ? 'en' : 'ar')} className="px-6 py-2 bg-gray-50 dark:bg-gray-800 rounded-full text-xs font-bold dark:text-white hover:bg-gray-100 dark:hover:bg-gray-700 transition-all border border-transparent hover:border-brand/20">
                           {lang === 'ar' ? 'English' : 'العربية'}
                         </button>
                       </div>

                       {/* Prominent Policy Links in Profile */}
                       <div className="bg-gray-50 dark:bg-gray-800/50 p-6 rounded-3xl border border-gray-100 dark:border-gray-800">
                         <p className="text-[10px] font-black uppercase text-gray-400 mb-4 tracking-widest">{lang === 'ar' ? 'القوانين والسياسات' : 'Legal & Policies'}</p>
                         <div className="flex justify-center gap-8">
                            <Link to="/privacy" className="flex flex-col items-center gap-2 text-xs font-bold text-gray-600 dark:text-gray-400 hover:text-brand transition-all group">
                               <div className="w-10 h-10 rounded-full bg-white dark:bg-gray-900 flex items-center justify-center shadow-sm group-hover:shadow-md transition-all group-hover:-translate-y-1">
                                  <Shield size={18} className="text-brand" />
                               </div>
                               {t.privacyPolicy}
                            </Link>
                            <div className="w-[1px] h-12 bg-gray-200 dark:bg-gray-700"></div>
                            <Link to="/terms" className="flex flex-col items-center gap-2 text-xs font-bold text-gray-600 dark:text-gray-400 hover:text-brand transition-all group">
                               <div className="w-10 h-10 rounded-full bg-white dark:bg-gray-900 flex items-center justify-center shadow-sm group-hover:shadow-md transition-all group-hover:-translate-y-1">
                                  <FileText size={18} className="text-brand" />
                               </div>
                               {t.termsOfUse}
                            </Link>
                         </div>
                       </div>
                    </div>

                    <button onClick={() => setUser(null)} className="mt-10 text-red-500 font-bold hover:underline transition-all opacity-60 hover:opacity-100">{t.logout}</button>
                  </div>
                </div>
              } />
              <Route path="*" element={<Navigate to="/" />} />
            </Routes>
          )}
        </main>

        {user && (
          <div className="fixed bottom-24 right-6 md:bottom-8 md:right-8 z-40">
            <button onClick={() => window.location.hash = '#/chat'} className="w-14 h-14 bg-brand text-white rounded-full shadow-2xl flex items-center justify-center hover:scale-110 active:scale-95 transition-all">
              <MessageCircle size={28} />
            </button>
          </div>
        )}
      </div>
    </HashRouter>
  );
};

export default App;

