             {signupData.avatar ? <img src={signupData.avatar} className="w-full h-full object-cover" /> : <Camera size={40} className="text-gray-400" />}
             <input type="file" className="hidden" onChange={e => e.target.files && setSignupData({...signupData, avatar: URL.createObjectURL(e.target.files[0])})} />
          </label>
          <span className="text-xs font-black uppercase tracking-widest text-gray-400">{t.signupSteps.profilePic}</span>
        </div>

        {/* Basic Info */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <div className="space-y-2">
            <label className="text-xs font-black uppercase tracking-widest text-gray-400 ml-2">{t.signupSteps.personalName}</label>
            <input type="text" placeholder={t.signupSteps.personalName} value={signupData.fullName} onChange={e => setSignupData({...signupData, fullName: e.target.value})} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-900 dark:text-white outline-none focus:ring-2 focus:ring-brand border border-transparent transition-all" />
          </div>
          <div className="space-y-2">
            <label className="text-xs font-black uppercase tracking-widest text-gray-400 ml-2">{t.signupSteps.userName}</label>
            <input type="text" placeholder={t.signupSteps.userName} value={signupData.username} onChange={e => setSignupData({...signupData, username: e.target.value})} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-900 dark:text-white outline-none focus:ring-2 focus:ring-brand border border-transparent transition-all" />
          </div>
        </div>

        {/* Credentials */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <div className="space-y-2">
            <label className="text-xs font-black uppercase tracking-widest text-gray-400 ml-2">Email</label>
            <input type="email" placeholder="Email" value={signupData.email} onChange={e => setSignupData({...signupData, email: e.target.value})} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-900 dark:text-white outline-none focus:ring-2 focus:ring-brand border border-transparent transition-all" />
          </div>
          <div className="space-y-2">
            <label className="text-xs font-black uppercase tracking-widest text-gray-400 ml-2">Password</label>
            <input type="password" placeholder="Password" value={signupData.password} onChange={e => setSignupData({...signupData, password: e.target.value})} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-900 dark:text-white outline-none focus:ring-2 focus:ring-brand border border-transparent transition-all" />
          </div>
        </div>

        {/* Geolocation Section */}
        <div className="space-y-2">
          <label className="text-xs font-black uppercase tracking-widest text-gray-400 ml-2">{t.signupSteps.geolocation}</label>
          <div className="flex gap-2">
            <div className="flex-1 p-4 bg-gray-50 dark:bg-gray-900 rounded-2xl border border-transparent dark:text-gray-400 text-sm truncate flex items-center gap-2">
              <MapPin size={18} className="text-brand shrink-0" />
              {signupData.location.address || (lang === 'ar' ? 'الموقع غير محدد' : 'Location not set')}
            </div>
            <button 
              type="button"
              onClick={() => setSignupData({...signupData, location: {address: 'Current Location Detected', lat: 24.7, lng: 46.6}})} 
              className="px-6 py-4 bg-gray-100 dark:bg-gray-800 text-brand rounded-2xl font-bold hover:bg-brand hover:text-white transition-all whitespace-nowrap"
            >
              📍 {lang === 'ar' ? 'تحديد الآن' : 'Fetch'}
            </button>
          </div>
        </div>

        {/* Policy Check */}
        <div className="space-y-4 pt-4">
          <div className="p-6 bg-gray-50 dark:bg-gray-900 rounded-3xl border border-gray-100 dark:border-gray-800">
             <div className="flex items-center gap-2 text-brand font-black text-xs uppercase tracking-widest mb-2">
                <Shield size={14} /> {t.signupSteps.privacy}
             </div>
             <p className="text-xs text-gray-500 leading-relaxed mb-4">
                {t.privacyPolicyDesc}
             </p>
             <div className="flex gap-4">
                <Link to="/privacy" className="text-xs font-black text-brand hover:underline">{t.privacyPolicy}</Link>
                <Link to="/terms" className="text-xs font-black text-brand hover:underline">{t.termsOfUse}</Link>
             </div>
          </div>

          <label className="flex items-center gap-3 cursor-pointer p-2 hover:bg-gray-50 dark:hover:bg-gray-900 rounded-xl transition-all">
             <input type="checkbox" checked={signupData.agreed} onChange={e => setSignupData({...signupData, agreed: e.target.checked})} className="w-6 h-6 accent-brand rounded-lg border-gray-300 text-brand focus:ring-brand transition-all" />
             <span className="text-sm dark:text-white font-bold">{lang === 'ar' ? 'أوافق على سياسة الخصوصية وشروط الاستخدام' : 'I agree to the privacy policy and terms of use'}</span>
          </label>
        </div>

        <button 
          type="submit"
          className="w-full py-5 bg-brand text-white rounded-3xl font-black text-lg shadow-2xl shadow-brand/20 hover:scale-[1.01] active:scale-95 transition-all"
        >
          {lang === 'ar' ? 'إنشاء الحساب الآن' : 'Create Account Now'}
        </button>

        <div className="flex justify-center gap-4 mt-8">
           <button type="button" onClick={() => setLang(lang === 'ar' ? 'en' : 'ar')} className="px-6 py-2 bg-gray-50 dark:bg-gray-900 rounded-full text-xs font-black dark:text-white hover:bg-brand hover:text-white transition-all">
             {lang === 'ar' ? 'English' : 'العربية'}
