           <button type="button" onClick={toggleTheme} className="px-6 py-2 bg-gray-50 dark:bg-gray-900 rounded-full text-xs font-black dark:text-white hover:bg-brand hover:text-white transition-all">
             {isDarkMode ? <Sun size={14} /> : <Moon size={14} />}
           </button>
        </div>
      </form>
    </div>
  );

