        {user && <Navbar lang={lang} isDark={isDarkMode} toggleTheme={toggleTheme} user={user} />}

        <main className={`min-h-screen ${user ? 'pb-20' : ''}`}>
          {!user ? (
            /* Walled Garden: Only the Full Page Signup is visible */
            <SignUpPage />
