  const [lang, setLang] = useState<string>('ar');
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [user, setUser] = useState<User | null>(null);

  // SignUp State
  const [signupData, setSignupData] = useState({
    avatar: '',
    fullName: '',
    username: '',
    location: { address: '', lat: 0, lng: 0 },
    email: '',
    password: '',
    agreed: false
  });

  useEffect(() => {
    if (isDarkMode) document.documentElement.classList.add('dark');
    else document.documentElement.classList.remove('dark');
  }, [isDarkMode]);

  const toggleTheme = () => setIsDarkMode(!isDarkMode);
  const t = translations[lang] || translations['en'];
  const isRtl = t.dir === 'rtl';

  const handleSignUpFinish = (e: React.FormEvent) => {
    e.preventDefault();
    if (!signupData.agreed || !signupData.email || !signupData.password || !signupData.fullName || !signupData.username) {
      alert(lang === 'ar' ? 'يرجى إكمال جميع الحقول والموافقة على الشروط' : 'Please complete all fields and agree to the terms');
      return;
    }

    const newUser: User = {
      id: 'u_' + Date.now(),
      fullName: signupData.fullName,
      username: signupData.username,
      email: signupData.email,
      avatar: signupData.avatar,
      gender: Gender.OTHER,
      birthDate: '2000-01-01',
      location: signupData.location,
      status: 'Member',
      points: 100, // Initial points
      listingsCount: 0,
      walletBalance: 0,
      payoutMethods: {},
      blockedUsers: []
    };
    setUser(newUser);
  };

  const handleUnblock = (userId: string) => {
    if (!user) return;
    setUser({
      ...user,
      blockedUsers: user.blockedUsers.filter(id => id !== userId)
    });
  };

