        <div className="inline-block px-4 py-2 bg-brand text-white rounded-2xl shadow-xl shadow-brand/20 font-black uppercase tracking-tighter text-2xl mb-4">
          my rents
        </div>
        <h1 className="text-3xl font-black dark:text-white mb-2">
          {lang === 'ar' ? 'إنشاء حساب جديد' : 'Create an Account'}
        </h1>
        <p className="text-gray-400 font-bold text-sm tracking-widest uppercase">{t.tagline}</p>
      </div>

      <form onSubmit={handleSignUpFinish} className="space-y-8">
        <div className="flex flex-col items-center gap-4">
          <label className="w-32 h-32 rounded-full bg-gray-100 dark:bg-gray-800 flex items-center justify-center border-4 border-brand cursor-pointer overflow-hidden relative group hover:scale-105 transition-transform">
             {signupData.avatar ? <img src={signupData.avatar} className="w-full h-full object-cover" /> : <Camera size={40} className="text-gray-400" />}
