                    </div>

                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                      <Link to="/subscribe" className="p-4 bg-brand text-white rounded-3xl font-bold flex flex-col items-center gap-2 shadow-xl shadow-brand/20 hover:scale-[1.02] transition-transform active:scale-95"><Crown /> {t.subscribe}</Link>
