                    </div>

                    <div className="mt-8 pt-8 border-t dark:border-gray-800 flex flex-col gap-6">
                       <div className="flex justify-center gap-4">
                         <button onClick={() => setLang(lang === 'ar' ? 'en' : 'ar')} className="px-6 py-2 bg-gray-50 dark:bg-gray-800 rounded-full text-xs font-bold dark:text-white hover:bg-gray-100 dark:hover:bg-gray-700 transition-all border border-transparent hover:border-brand/20 active:scale-95">
                           {lang === 'ar' ? 'English' : 'العربية'}
                         </button>
                       </div>

                       <div className="bg-gray-50 dark:bg-gray-800/50 p-6 rounded-3xl border border-gray-100 dark:border-gray-800">
                         <p className="text-[10px] font-black uppercase text-gray-400 mb-4 tracking-widest">{lang === 'ar' ? 'القوانين والسياسات' : 'Legal & Policies'}</p>
                         <div className="flex justify-center gap-8">
                            <Link to="/privacy" className="flex flex-col items-center gap-2 text-xs font-bold text-gray-600 dark:text-gray-400 hover:text-brand transition-all group active:scale-95">
                               <div className="w-10 h-10 rounded-full bg-white dark:bg-gray-900 flex items-center justify-center shadow-sm group-hover:shadow-md transition-all group-hover:-translate-y-1">
                                  <Shield size={18} className="text-brand" />
                               </div>
                               {t.privacyPolicy}
                            </Link>
                            <div className="w-[1px] h-12 bg-gray-200 dark:bg-gray-700"></div>
                            <Link to="/terms" className="flex flex-col items-center gap-2 text-xs font-bold text-gray-600 dark:text-gray-400 hover:text-brand transition-all group active:scale-95">
                               <div className="w-10 h-10 rounded-full bg-white dark:bg-gray-900 flex items-center justify-center shadow-sm group-hover:shadow-md transition-all group-hover:-translate-y-1">
                                  <FileText size={18} className="text-brand" />
                               </div>
                               {t.termsOfUse}
                            </Link>
                         </div>
                       </div>
                    </div>

                    <button onClick={() => setUser(null)} className="mt-10 text-red-500 font-bold hover:underline transition-all opacity-60 hover:opacity-100 active:scale-95">{t.logout}</button>
                  </div>
                </div>
              } />
              <Route path="*" element={<Navigate to="/" />} />
            </Routes>
          )}
        </main>

        {user && (
          <div className="fixed bottom-24 right-6 md:bottom-8 md:right-8 z-40">
            <Link to="/chat" className="w-14 h-14 bg-brand text-white rounded-full shadow-2xl flex items-center justify-center hover:scale-110 active:scale-90 transition-all">
              <MessageCircle size={28} />
            </Link>
          </div>
        )}
      </div>
    </HashRouter>
  );
};

export default App;

