import React, { useState } from 'react';
import { Heart, MapPin, Eye, Star, Share2, MessageCircle, Trash2 } from 'lucide-react';
import { Listing } from '../types';
import { Link, useNavigate } from 'react-router-dom';

interface ListingCardProps {
  listing: Listing;
  lang: string;
  isOwner?: boolean;
  onDelete?: (id: string) => void;
}

const ListingCard: React.FC<ListingCardProps> = ({ listing, lang, isOwner, onDelete }) => {
  const navigate = useNavigate();
  const [isLiked, setIsLiked] = useState(false);
  const isRtl = lang === 'ar';

  const handleShare = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    const url = `${window.location.origin}/#/item/${listing.id}`;
    if (navigator.share) {
      navigator.share({ title: listing.title, url });
    } else {
      navigator.clipboard.writeText(url);
      alert(lang === 'ar' ? 'تم نسخ الرابط!' : 'Link copied to clipboard!');
    }
  };

  const handleLike = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsLiked(!isLiked);
  };

  return (
    <div className="bg-white dark:bg-gray-900 rounded-[2.5rem] overflow-hidden shadow-sm hover:shadow-2xl transition-all group border border-gray-100 dark:border-gray-800 flex flex-col h-full">
      {/* Owner Header */}
      <div className="p-4 flex items-center gap-3">
        <div className="w-10 h-10 rounded-full border-2 border-brand/10 p-0.5">
          <img src={listing.ownerAvatar || `https://api.dicebear.com/7.x/avataaars/svg?seed=${listing.ownerUsername}`} className="w-full h-full rounded-full object-cover" />
        </div>
        <div className="flex flex-col flex-1">
          <span className="text-xs font-black dark:text-white leading-tight uppercase tracking-tighter">{listing.ownerName}</span>
          <span className="text-[10px] font-bold text-[#CCCCCC]">@{listing.ownerUsername}</span>
        </div>
        {isOwner && (
          <button onClick={() => onDelete?.(listing.id)} className="text-red-500 hover:bg-red-50 p-2 rounded-xl transition-all active:scale-95">
            <Trash2 size={18} />
          </button>
        )}
      </div>

      <Link to={`/item/${listing.id}`} className="relative block group-hover:px-1 transition-all duration-300">
        <div className="aspect-square overflow-hidden rounded-[2rem] mx-2">
          <img src={listing.images[0]} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700" />
        </div>
        <div className="absolute top-5 right-5 flex flex-col gap-2">
          <button 
            onClick={handleLike}
            className={`p-2.5 backdrop-blur-lg rounded-2xl shadow-xl transition-all active:scale-90 ${isLiked ? 'bg-brand text-white' : 'bg-white/80 text-gray-900 hover:bg-white'}`}
          >
            <Heart size={20} fill={isLiked ? 'currentColor' : 'none'} />
          </button>
        </div>
        <div className="absolute bottom-5 left-5 bg-brand text-white px-4 py-1.5 rounded-2xl font-black shadow-2xl text-xs uppercase tracking-widest border-2 border-white/20">
          {listing.price} {listing.currency}
        </div>
      </Link>

      <div className="p-6 flex flex-col flex-1">
        <div className="flex justify-between items-start mb-2">
          <h3 className="font-black text-lg truncate flex-1 dark:text-white uppercase tracking-tighter">{listing.title}</h3>
          <div className="flex items-center gap-1 text-yellow-500 bg-yellow-50 dark:bg-yellow-900/20 px-2 py-1 rounded-lg">
            <Star size={12} fill="currentColor" />
            <span className="text-[10px] font-black">{listing.rating}</span>
          </div>
        </div>

        <div className="flex items-center gap-1.5 text-gray-400 text-[10px] font-bold uppercase tracking-widest mb-6">
          <MapPin size={12} className="text-brand" />
          <span className="truncate">{listing.location.address}</span>
        </div>

        <div className="mt-auto flex items-center justify-between pt-4 border-t border-gray-100 dark:border-gray-800">
          <div className="flex items-center gap-4">
            <div className="flex items-center gap-1.5 text-gray-400">
              <Eye size={16} />
              <span className="text-[10px] font-black">{listing.views}</span>
            </div>
            <button onClick={handleShare} className="text-gray-400 hover:text-brand transition-all active:scale-90"><Share2 size={18} /></button>
          </div>
          <button 
            onClick={() => navigate(`/chat/${listing.ownerId}`)}
            className="w-10 h-10 bg-brand/5 text-brand rounded-2xl flex items-center justify-center hover:bg-brand hover:text-white transition-all active:scale-90 shadow-sm"
          >
            <MessageCircle size={20} />
          </button>
        </div>
      </div>
    </div>
  );
};

