const CreateListingPage: React.FC<{ lang: string; user: any; onCreated: (l: Listing) => void }> = ({ lang, user, onCreated }) => {
  const t = translations[lang] || translations['en'];
  const navigate = useNavigate();
  const [step, setStep] = useState(1);
  const [loading, setLoading] = useState(false);

  const [images, setImages] = useState<string[]>([]);
  const [video, setVideo] = useState<string | null>(null);
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [category, setCategory] = useState(CATEGORIES[0]);
  const [currencyType, setCurrencyType] = useState<CurrencyType>(CurrencyType.LOCAL);
  const [payoutMethod, setPayoutMethod] = useState('');
  const [price, setPrice] = useState('');
  const [period, setPeriod] = useState<RentalPeriod>(RentalPeriod.DAY);

  const cryptoOptions = [
    { name: 'Solana', icon: <Zap size={14} className="text-purple-500" /> },
    { name: 'Ethereum', icon: <Zap size={14} className="text-blue-500" /> },
    { name: 'Monad', icon: <Zap size={14} className="text-brand" /> },
    { name: 'Base', icon: <Zap size={14} className="text-blue-400" /> },
    { name: 'Sui', icon: <Zap size={14} className="text-teal-400" /> },
    { name: 'Polygon', icon: <Zap size={14} className="text-purple-600" /> },
    { name: 'Bitcoin', icon: <Bitcoin size={14} className="text-orange-500" /> }
  ];

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      const files = Array.from(e.target.files).slice(0, 5 - images.length);
      const urls = files.map(f => URL.createObjectURL(f));
      setImages(prev => [...prev, ...urls]);
    }
  };

  const startAiCheck = async () => {
    setLoading(true);
    const result = await checkListingContent(title, description);
    if (result.status === 'APPROVED') {
      const newListing: Listing = {
        id: 'l_' + Date.now(),
        ownerId: user.id,
        ownerName: user.fullName,
        ownerUsername: user.username,
        ownerAvatar: user.avatar,
        title,
        description,
        type: ListingType.RENT,
        price: parseFloat(price),
        currency: 'USD',
        currencyType,
        payoutAddress: payoutMethod,
        category,
        location: user.location,
        images,
        video: video || undefined,
        rentalPeriod: period,
        createdAt: new Date().toISOString(),
        views: 0,
        likes: 0,
        rating: 0,
        isAiApproved: true
      };
      onCreated(newListing);
      setStep(6);
    } else {
      alert(t.aiRejected + ": " + result.reason);
      setStep(2);
    }
    setLoading(false);
  };

  return (
    <div className="max-w-2xl mx-auto p-6 bg-white dark:bg-gray-900 rounded-[3rem] shadow-sm my-8 border border-gray-100 dark:border-gray-800">
      <div className="flex justify-between mb-8 px-4">
        {[1,2,3,4,5,6].map(s => (
          <div key={s} className={`w-3 h-3 rounded-full transition-all duration-300 ${step >= s ? 'bg-brand scale-125' : 'bg-gray-100 dark:bg-gray-800'}`} />
        ))}
      </div>

      {step === 1 && (
        <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4">
          <h2 className="text-2xl font-black dark:text-white">{lang === 'ar' ? 'رفع الوسائط' : 'Upload Media'}</h2>
          <div className="grid grid-cols-3 gap-3">
            {images.map((img, i) => (
              <div key={i} className="relative aspect-square">
                 <img src={img} className="w-full h-full object-cover rounded-2xl" />
                 <button onClick={() => setImages(images.filter((_, idx) => idx !== i))} className="absolute -top-2 -right-2 bg-red-500 text-white rounded-full p-1"><CheckCircle className="rotate-45" size={12} /></button>
              </div>
            ))}
            {images.length < 5 && (
              <label className="aspect-square border-2 border-dashed border-gray-200 dark:border-gray-700 rounded-2xl flex items-center justify-center cursor-pointer text-gray-400 hover:border-brand hover:text-brand transition-colors">
                <Camera size={32} /><input type="file" multiple accept="image/*" className="hidden" onChange={handleImageUpload} />
              </label>
            )}
          </div>
          <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">{lang === 'ar' ? '2 صور كحد أدنى، 5 صور كحد أقصى*' : 'Min 2, Max 5 images*'}</p>
          <label className={`block p-4 border-2 rounded-2xl cursor-pointer transition-all ${video ? 'border-brand bg-brand/5' : 'border-gray-100 dark:border-gray-800'} dark:text-white`}>
            <div className="flex items-center justify-between">
               <div className="flex items-center gap-2">
                  <Video className={video ? 'text-brand' : 'text-gray-400'} size={20} />
                  <span className="font-bold">{lang === 'ar' ? 'رفع فيديو المنتج (إختياري)' : 'Upload Product Video (Optional)'}</span>
               </div>
            </div>
            <input type="file" accept="video/*" className="hidden" onChange={(e) => e.target.files && e.target.files[0] && setVideo(URL.createObjectURL(e.target.files[0]))} />
          </label>
          <button disabled={images.length < 2} onClick={() => setStep(2)} className="w-full py-4 bg-brand text-white rounded-2xl font-bold flex items-center justify-center gap-2 active:scale-95 disabled:opacity-30">{t.next} <ArrowRight size={18} /></button>
        </div>
      )}

      {step === 2 && (
        <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4">
          <h2 className="text-2xl font-black dark:text-white">{lang === 'ar' ? 'تفاصيل المنتج' : 'Item Details'}</h2>
          <input required type="text" placeholder={lang === 'ar' ? 'إسم المنتج*' : 'Item Name*'} value={title} onChange={e => setTitle(e.target.value)} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none focus:ring-2 focus:ring-brand" />
          <textarea required placeholder={lang === 'ar' ? 'وصف المنتج*' : 'Description*'} value={description} onChange={e => setDescription(e.target.value)} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white h-40 outline-none focus:ring-2 focus:ring-brand" />
          <select value={category} onChange={e => setCategory(e.target.value)} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none">
            {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
          </select>
          <div className="flex gap-4">
            <button onClick={() => setStep(1)} className="p-4 bg-gray-100 dark:bg-gray-800 rounded-2xl"><ArrowLeft /></button>
            <button disabled={!title || !description} onClick={() => setStep(3)} className="flex-1 py-4 bg-brand text-white rounded-2xl font-bold active:scale-95 disabled:opacity-30">{t.next}</button>
          </div>
        </div>
      )}

      {step === 3 && (
        <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4">
          <h2 className="text-2xl font-black dark:text-white">{t.payoutMethod}*</h2>
          <div className="flex gap-4 p-2 bg-gray-50 dark:bg-gray-800 rounded-3xl">
            <button onClick={() => {setCurrencyType(CurrencyType.CRYPTO); setPayoutMethod('')}} className={`flex-1 py-4 rounded-2xl font-bold flex items-center justify-center gap-2 transition-all ${currencyType === CurrencyType.CRYPTO ? 'bg-white dark:bg-gray-900 text-brand shadow-sm' : 'text-gray-400'}`}><Bitcoin size={20} /> {t.crypto}</button>
            <button onClick={() => {setCurrencyType(CurrencyType.LOCAL); setPayoutMethod('')}} className={`flex-1 py-4 rounded-2xl font-bold flex items-center justify-center gap-2 transition-all ${currencyType === CurrencyType.LOCAL ? 'bg-white dark:bg-gray-900 text-brand shadow-sm' : 'text-gray-400'}`}><CreditCard size={20} /> {t.local}</button>
          </div>
          <div className="p-4 bg-gray-50 dark:bg-gray-800 rounded-3xl">
            {currencyType === CurrencyType.CRYPTO ? (
              <div className="grid grid-cols-2 gap-2">
                {cryptoOptions.map(opt => (
                  <button key={opt.name} onClick={() => setPayoutMethod(opt.name)} className={`p-3 rounded-xl border-2 flex items-center gap-2 transition-all ${payoutMethod === opt.name ? 'border-brand bg-brand/5' : 'border-transparent bg-white dark:bg-gray-900 dark:text-white'}`}>
                    {opt.icon} <span className="text-xs font-bold">{opt.name}</span>
                  </button>
                ))}
              </div>
            ) : (
              <input required type="email" placeholder="PayPal Email Address*" value={payoutMethod} onChange={e => setPayoutMethod(e.target.value)} className="w-full p-4 rounded-2xl bg-white dark:bg-gray-900 dark:text-white outline-none border-2 border-transparent focus:border-brand" />
            )}
          </div>
          <button disabled={!payoutMethod} onClick={() => setStep(4)} className="w-full py-4 bg-brand text-white rounded-2xl font-bold active:scale-95 disabled:opacity-30">{t.next}</button>
        </div>
      )}

      {step === 4 && (
        <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4">
          <h2 className="text-2xl font-black dark:text-white">{lang === 'ar' ? 'السعر ومدة التأجير' : 'Price & Rental Period'}</h2>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <div className="space-y-2">
               <label className="text-xs font-bold text-gray-400 uppercase">{t.price}*</label>
               <input required type="number" placeholder="0.00" value={price} onChange={e => setPrice(e.target.value)} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none focus:ring-2 focus:ring-brand" />
            </div>
            <div className="space-y-2">
               <label className="text-xs font-bold text-gray-400 uppercase">{t.rentalPeriod}*</label>
               <select value={period} onChange={e => setPeriod(e.target.value as RentalPeriod)} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none">
                 {Object.keys(RentalPeriod).map(p => <option key={p} value={p}>{t.periods[p]}</option>)}
               </select>
            </div>
          </div>
          <div className="p-6 bg-gray-50 dark:bg-gray-800 rounded-3xl flex items-center justify-between">
             <span className="font-bold dark:text-white">{t.location}</span>
             <span className="text-sm text-gray-400">📍 {user.location.address}</span>
          </div>
          <button disabled={!price} onClick={() => setStep(5)} className="w-full py-4 bg-brand text-white rounded-2xl font-bold active:scale-95 disabled:opacity-30">{t.next}</button>
        </div>
      )}

      {step === 5 && (
        <div className="text-center py-12 space-y-6 animate-in zoom-in-95">
          <ShieldCheck size={72} className="mx-auto text-brand animate-pulse" />
          <h2 className="text-3xl font-black dark:text-white">{t.aiChecking}</h2>
          <p className="text-gray-500 max-w-sm mx-auto">{lang === 'ar' ? 'يقوم نظام AI my rents الآن بفحص بيانات المنتج' : 'AI my rents is scanning your listing'}</p>
          <button onClick={startAiCheck} className="px-10 py-4 bg-brand text-white rounded-2xl font-bold flex items-center justify-center gap-3 mx-auto active:scale-95">
            {loading ? <Loader2 className="animate-spin" /> : <><ShieldCheck size={20} /> Verify & Publish</>}
          </button>
        </div>
      )}

      {step === 6 && (
        <div className="text-center py-12 space-y-6 animate-in zoom-in-95">
          <CheckCircle size={72} className="mx-auto text-green-500" />
          <h2 className="text-3xl font-black dark:text-white">{t.aiApproved}</h2>
          <button onClick={() => navigate('/')} className="w-full py-4 bg-green-500 text-white rounded-2xl font-bold shadow-xl shadow-green-500/20 active:scale-95">{lang === 'ar' ? 'إطلاق الإعلان' : 'Publish Now'}</button>
        </div>
      )}
    </div>
  );
};

export default CreateListingPage;

