              <div className="space-y-4">
                 <label className="w-24 h-24 rounded-3xl bg-gray-100 dark:bg-gray-800 mx-auto flex items-center justify-center border-4 border-dashed border-brand cursor-pointer overflow-hidden relative">
                   {groupData.image ? <img src={groupData.image} className="w-full h-full object-cover" /> : <Camera size={32} className="text-gray-400" />}
