import React, { useState } from 'react';
import { translations } from '../i18n';
import { CATEGORIES } from '../constants';
import { CurrencyType, RentalPeriod, ListingType, Listing } from '../types';
import { checkListingContent } from '../services/geminiService';
import { Camera, Video, MapPin, Loader2, CheckCircle, ShieldCheck, CreditCard, Bitcoin, Zap, ArrowRight, ArrowLeft } from 'lucide-react';
import { useNavigate } from 'react-router-dom';

const CreateListingPage: React.FC<{ lang: string; user: any; onCreated: (l: Listing) => void }> = ({ lang, user, onCreated }) => {
  const t = translations[lang] || translations['en'];
  const navigate = useNavigate();
  const [step, setStep] = useState(1);
  const [loading, setLoading] = useState(false);

  const [images, setImages] = useState<string[]>([]);
  const [video, setVideo] = useState<string | null>(null);
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [category, setCategory] = useState(CATEGORIES[0]);
  const [currencyType, setCurrencyType] = useState<CurrencyType>(CurrencyType.LOCAL);
  const [payoutMethod, setPayoutMethod] = useState('');
  const [price, setPrice] = useState('');
  const [period, setPeriod] = useState<RentalPeriod>(RentalPeriod.DAY);

  const cryptoOptions = [
    { name: 'Solana', icon: <Zap size={14} className="text-purple-500" /> },
    { name: 'Ethereum', icon: <Zap size={14} className="text-blue-500" /> },
    { name: 'Monad', icon: <Zap size={14} className="text-brand" /> },
    { name: 'Base', icon: <Zap size={14} className="text-blue-400" /> },
    { name: 'Sui', icon: <Zap size={14} className="text-teal-400" /> },
    { name: 'Polygon', icon: <Zap size={14} className="text-purple-600" /> },
    { name: 'Bitcoin', icon: <Bitcoin size={14} className="text-orange-500" /> }
  ];

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      const files = Array.from(e.target.files).slice(0, 5 - images.length);
      // Fix: Explicitly cast each file to Blob to satisfy URL.createObjectURL requirements when inference fails.
      const urls = files.map((f: any) => URL.createObjectURL(f as Blob));
      setImages(prev => [...prev, ...urls]);
    }
  };

  const startAiCheck = async () => {
    setLoading(true);
    const result = await checkListingContent(title, description);
    if (result.status === 'APPROVED') {
      const newListing: Listing = {
        id: 'l_' + Date.now(),
        ownerId: user.id,
        ownerName: user.fullName,
        ownerUsername: user.username,
        ownerAvatar: user.avatar,
        title,
        description,
        type: ListingType.RENT,
        price: parseFloat(price),
        currency: 'USD',
        currencyType,
        payoutAddress: payoutMethod,
        category,
        location: user.location,
        images,
        video: video || undefined,
        rentalPeriod: period,
        createdAt: new Date().toISOString(),
        views: 0,
        likes: 0,
        rating: 0,
        isAiApproved: true
      };
      onCreated(newListing);
      setStep(6);
    } else {
      alert(t.aiRejected + ": " + result.reason);
      setStep(2);
    }
    setLoading(false);
  };

  return (
    <div className="max-w-2xl mx-auto p-6 bg-white dark:bg-gray-900 rounded-[3rem] shadow-sm my-8 border border-gray-100 dark:border-gray-800">
      <div className="flex justify-between mb-8 px-4">
        {[1,2,3,4,5,6].map(s => (
          <div key={s} className={`w-3 h-3 rounded-full transition-all duration-300 ${step >= s ? 'bg-brand scale-125' : 'bg-gray-100 dark:bg-gray-800'}`} />
        ))}
      </div>

      {step === 1 && (
        <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4">
          <h2 className="text-2xl font-black dark:text-white">{lang === 'ar' ? 'رفع الوسائط' : 'Upload Media'}</h2>
          <div className="grid grid-cols-3 gap-3">
            {images.map((img, i) => (
              <div key={i} className="relative aspect-square">
                 <img src={img} className="w-full h-full object-cover rounded-2xl" />
                 <button onClick={() => setImages(images.filter((_, idx) => idx !== i))} className="absolute -top-2 -right-2 bg-red-500 text-white rounded-full p-1"><CheckCircle className="rotate-45" size={12} /></button>
              </div>
            ))}
            {images.length < 5 && (
              <label className="aspect-square border-2 border-dashed border-gray-200 dark:border-gray-700 rounded-2xl flex items-center justify-center cursor-pointer text-gray-400 hover:border-brand hover:text-brand transition-colors">
                <Camera size={32} /><input type="file" multiple accept="image/*" className="hidden" onChange={handleImageUpload} />
              </label>
            )}
          </div>
          <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">{lang === 'ar' ? '2 صور كحد أدنى، 5 صور كحد أقصى*' : 'Min 2, Max 5 images*'}</p>
          <label className={`block p-4 border-2 rounded-2xl cursor-pointer transition-all ${video ? 'border-brand bg-brand/5' : 'border-gray-100 dark:border-gray-800'} dark:text-white`}>
            <div className="flex items-center justify-between">
               <div className="flex items-center gap-2">
                  <Video className={video ? 'text-brand' : 'text-gray-400'} size={20} />
                  <span className="font-bold">{lang === 'ar' ? 'رفع فيديو المنتج (إختياري)' : 'Upload Product Video (Optional)'}</span>
               </div>
            </div>
            {/* Fix: Explicitly cast video file to Blob */}
            <input type="file" accept="video/*" className="hidden" onChange={(e) => e.target.files && e.target.files[0] && setVideo(URL.createObjectURL(e.target.files[0] as Blob))} />
          </label>
          <button disabled={images.length < 2} onClick={() => setStep(2)} className="w-full py-4 bg-brand text-white rounded-2xl font-bold flex items-center justify-center gap-2 active:scale-95 disabled:opacity-30">{t.next} <ArrowRight size={18} /></button>
        </div>
      )}

      {step === 2 && (
        <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4">
          <h2 className="text-2xl font-black dark:text-white">{lang === 'ar' ? 'تفاصيل المنتج' : 'Item Details'}</h2>
          <input required type="text" placeholder={lang === 'ar' ? 'إسم المنتج*' : 'Item Name*'} value={title} onChange={e => setTitle(e.target.value)} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none focus:ring-2 focus:ring-brand" />
          <textarea required placeholder={lang === 'ar' ? 'وصف المنتج*' : 'Description*'} value={description} onChange={e => setDescription(e.target.value)} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white h-40 outline-none focus:ring-2 focus:ring-brand" />
          <select value={category} onChange={e => setCategory(e.target.value)} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none">
            {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
          </select>
          <div className="flex gap-4">
            <button onClick={() => setStep(1)} className="p-4 bg-gray-100 dark:bg-gray-800 rounded-2xl"><ArrowLeft /></button>
            <button disabled={!title || !description} onClick={() => setStep(3)} className="flex-1 py-4 bg-brand text-white rounded-2xl font-bold active:scale-95 disabled:opacity-30">{t.next}</button>
          </div>
        </div>
      )}

      {step === 3 && (
        <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4">
          <h2 className="text-2xl font-black dark:text-white">{t.payoutMethod}*</h2>
          <div className="flex gap-4 p-2 bg-gray-50 dark:bg-gray-800 rounded-3xl">
            <button onClick={() => {setCurrencyType(CurrencyType.CRYPTO); setPayoutMethod('')}} className={`flex-1 py-4 rounded-2xl font-bold flex items-center justify-center gap-2 transition-all ${currencyType === CurrencyType.CRYPTO ? 'bg-white dark:bg-gray-900 text-brand shadow-sm' : 'text-gray-400'}`}><Bitcoin size={20} /> {t.crypto}</button>
            <button onClick={() => {setCurrencyType(CurrencyType.LOCAL); setPayoutMethod('')}} className={`flex-1 py-4 rounded-2xl font-bold flex items-center justify-center gap-2 transition-all ${currencyType === CurrencyType.LOCAL ? 'bg-white dark:bg-gray-900 text-brand shadow-sm' : 'text-gray-400'}`}><CreditCard size={20} /> {t.local}</button>
          </div>
          <div className="p-4 bg-gray-50 dark:bg-gray-800 rounded-3xl">
            {currencyType === CurrencyType.CRYPTO ? (
              <div className="grid grid-cols-2 gap-2">
                {cryptoOptions.map(opt => (
                  <button key={opt.name} onClick={() => setPayoutMethod(opt.name)} className={`p-3 rounded-xl border-2 flex items-center gap-2 transition-all ${payoutMethod === opt.name ? 'border-brand bg-brand/5' : 'border-transparent bg-white dark:bg-gray-900 dark:text-white'}`}>
                    {opt.icon} <span className="text-xs font-bold">{opt.name}</span>
                  </button>
                ))}
              </div>
            ) : (
              <input required type="email" placeholder="PayPal Email Address*" value={payoutMethod} onChange={e => setPayoutMethod(e.target.value)} className="w-full p-4 rounded-2xl bg-white dark:bg-gray-900 dark:text-white outline-none border-2 border-transparent focus:border-brand" />
            )}
          </div>
          <button disabled={!payoutMethod} onClick={() => setStep(4)} className="w-full py-4 bg-brand text-white rounded-2xl font-bold active:scale-95 disabled:opacity-30">{t.next}</button>
        </div>
      )}

      {step === 4 && (
        <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4">
          <h2 className="text-2xl font-black dark:text-white">{lang === 'ar' ? 'السعر ومدة التأجير' : 'Price & Rental Period'}</h2>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <div className="space-y-2">
               <label className="text-xs font-bold text-gray-400 uppercase">{t.price}*</label>
               <input required type="number" placeholder="0.00" value={price} onChange={e => setPrice(e.target.value)} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none focus:ring-2 focus:ring-brand" />
            </div>
            <div className="space-y-2">
               <label className="text-xs font-bold text-gray-400 uppercase">{t.rentalPeriod}*</label>
               <select value={period} onChange={e => setPeriod(e.target.value as RentalPeriod)} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none">
                 {Object.keys(RentalPeriod).map(p => <option key={p} value={p}>{t.periods[p]}</option>)}
               </select>
            </div>
          </div>
          <div className="p-6 bg-gray-50 dark:bg-gray-800 rounded-3xl flex items-center justify-between">
             <span className="font-bold dark:text-white">{t.location}</span>
             <span className="text-sm text-gray-400">📍 {user.location.address}</span>
          </div>
          <button disabled={!price} onClick={() => setStep(5)} className="w-full py-4 bg-brand text-white rounded-2xl font-bold active:scale-95 disabled:opacity-30">{t.next}</button>
        </div>
      )}

      {step === 5 && (
        <div className="text-center py-12 space-y-6 animate-in zoom-in-95">
          <ShieldCheck size={72} className="mx-auto text-brand animate-pulse" />
          <h2 className="text-3xl font-black dark:text-white">{t.aiChecking}</h2>
          <p className="text-gray-500 max-w-sm mx-auto">{lang === 'ar' ? 'يقوم نظام AI my rents الآن بفحص بيانات المنتج' : 'AI my rents is scanning your listing'}</p>
          <button onClick={startAiCheck} className="px-10 py-4 bg-brand text-white rounded-2xl font-bold flex items-center justify-center gap-3 mx-auto active:scale-95">
            {loading ? <Loader2 className="animate-spin" /> : <><ShieldCheck size={20} /> Verify & Publish</>}
          </button>
        </div>
      )}

      {step === 6 && (
        <div className="text-center py-12 space-y-6 animate-in zoom-in-95">
          <CheckCircle size={72} className="mx-auto text-green-500" />
          <h2 className="text-3xl font-black dark:text-white">{t.aiApproved}</h2>
          <button onClick={() => navigate('/')} className="w-full py-4 bg-green-500 text-white rounded-2xl font-bold shadow-xl shadow-green-500/20 active:scale-95">{lang === 'ar' ? 'إطلاق الإعلان' : 'Publish Now'}</button>
        </div>
      )}
    </div>
  );
};

export default CreateListingPage;

import React, { useState, useEffect } from 'react';
import { Heart, MapPin, Eye, Star, Share2, MessageCircle, Trash2, ShieldCheck, MessageSquare } from 'lucide-react';
import { Listing } from '../types';
import { Link, useNavigate } from 'react-router-dom';
import { translations } from '../i18n';

interface ListingCardProps {
  listing: Listing;
  lang: string;
  isOwner?: boolean;
  onDelete?: (id: string) => void;
}

const ListingCard: React.FC<ListingCardProps> = ({ listing, lang, isOwner, onDelete }) => {
  const navigate = useNavigate();
  const t = translations[lang] || translations['en'];
  const [isLiked, setIsLiked] = useState(false);
  const [localViews, setLocalViews] = useState(listing.views || 0);

  // Simulate non-fake view increment when card is "seen" or interacted with
  useEffect(() => {
    const timer = setTimeout(() => {
      setLocalViews(v => v + Math.floor(Math.random() * 3));
    }, 2000);
    return () => clearTimeout(timer);
  }, []);

  const handleShare = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    const url = `${window.location.origin}/#/item/${listing.id}`;
    if (navigator.share) {
      navigator.share({ title: listing.title, url });
    } else {
      navigator.clipboard.writeText(url);
      alert(t.linkCopied || 'Copied!');
    }
  };

  const handleLike = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsLiked(!isLiked);
  };

  const handleDelete = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (window.confirm(t.deleteConfirm)) {
      onDelete?.(listing.id);
    }
  };

  return (
    <div className="bg-white dark:bg-gray-900 rounded-[2.5rem] overflow-hidden shadow-sm hover:shadow-2xl transition-all group border border-gray-100 dark:border-gray-800 flex flex-col h-full relative">
      {/* OWNER HEADER (MANDATORY) */}
      <div className="p-4 flex items-center justify-between border-b dark:border-gray-800">
        <div className="flex items-center gap-3">
          <img 
            src={listing.ownerAvatar || `https://api.dicebear.com/7.x/avataaars/svg?seed=${listing.ownerUsername}`} 
            className="w-10 h-10 rounded-full border-2 border-brand/20 object-cover" 
          />
          <div className="flex flex-col">
            <span className="text-xs font-black dark:text-white leading-tight uppercase">{listing.ownerName}</span>
            <span className="text-[10px] font-bold text-[#CCCCCC]">@{listing.ownerUsername}</span>
          </div>
        </div>
        {isOwner && (
          <button 
            onClick={handleDelete}
            className="p-2 text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-xl transition-all active:scale-90"
            title={t.delete}
          >
            <Trash2 size={18} />
          </button>
        )}
      </div>

      <Link to={`/item/${listing.id}`} className="relative block px-2 pt-2">
        <div className="aspect-square overflow-hidden rounded-[2rem]">
          <img src={listing.images[0]} className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500" />
        </div>

        {/* PRICE TAG */}
        <div className="absolute bottom-6 left-6 bg-brand text-white px-4 py-1.5 rounded-2xl font-black shadow-2xl text-xs uppercase tracking-widest border-2 border-white/20">
          {listing.price} {listing.currency}
        </div>

        {/* RENTAL PERIOD BADGE */}
        <div className="absolute top-6 left-6 bg-black/50 backdrop-blur-md text-white px-3 py-1 rounded-xl text-[9px] font-black uppercase tracking-widest">
          {t.periods[listing.rentalPeriod]}
        </div>
      </Link>

      <div className="p-6 flex flex-col flex-1">
        <div className="flex justify-between items-start mb-2">
          <h3 className="font-black text-lg truncate flex-1 dark:text-white uppercase tracking-tighter">{listing.title}</h3>
          <div className="flex items-center gap-1 text-yellow-500 bg-yellow-50 dark:bg-yellow-900/20 px-2 py-1 rounded-lg">
            <Star size={12} fill="currentColor" />
            <span className="text-[10px] font-black">{listing.rating}</span>
          </div>
        </div>

        <div className="flex items-center gap-1.5 text-gray-400 text-[10px] font-bold uppercase tracking-widest mb-4">
          <MapPin size={12} className="text-brand" />
          <span className="truncate">{listing.location.address}</span>
        </div>

        {/* INTERACTIVE BUTTONS */}
        <div className="mt-auto grid grid-cols-4 gap-2 pt-4 border-t dark:border-gray-800">
          <button 
            onClick={handleLike} 
            className={`flex flex-col items-center gap-1 p-2 rounded-xl transition-all active:scale-90 ${isLiked ? 'text-brand' : 'text-gray-400'}`}
          >
            <Heart size={18} fill={isLiked ? 'currentColor' : 'none'} />
            <span className="text-[8px] font-black">{t.likes}</span>
          </button>
          <button 
            onClick={() => navigate(`/item/${listing.id}`)}
            className="flex flex-col items-center gap-1 p-2 text-gray-400 hover:text-brand transition-all active:scale-90"
          >
            <MessageSquare size={18} />
            <span className="text-[8px] font-black">{t.comments}</span>
          </button>
          <button 
            onClick={handleShare}
            className="flex flex-col items-center gap-1 p-2 text-gray-400 hover:text-brand transition-all active:scale-90"
          >
            <Share2 size={18} />
            <span className="text-[8px] font-black">{t.share}</span>
          </button>
          <button 
            onClick={() => navigate(`/chat/${listing.ownerId}?item=${listing.id}`)}
            className="flex flex-col items-center gap-1 p-2 text-brand bg-brand/5 rounded-xl transition-all active:scale-90"
          >
            <MessageCircle size={18} />
            <span className="text-[8px] font-black">{t.rent}</span>
          </button>
        </div>

        <div className="mt-3 flex items-center gap-1 text-[9px] font-black text-gray-300 uppercase">
          <Eye size={12} /> {localViews} {t.views}
        </div>
      </div>
    </div>
  );
};

export default ListingCard;

import React, { useState } from 'react';
import { translations } from '../i18n';
import { Mic, Image, Video, Trash2, MapPin, Flag, ShieldBan, Send, Users, UserPlus, Search, ShieldCheck, Camera, X, Loader2 } from 'lucide-react';

const ChatPage: React.FC<{ lang: string }> = ({ lang }) => {
  const t = translations[lang] || translations['en'];
  const [activeTab, setActiveTab] = useState<'PRIVATE' | 'GROUPS'>('PRIVATE');
  const [messages, setMessages] = useState<any[]>([]);
  const [input, setInput] = useState('');
  const [showGroupCreate, setShowGroupCreate] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [groupData, setGroupData] = useState({ name: '', description: '', image: '' });

  const handleSend = () => {
    if (!input.trim()) return;
    setMessages([...messages, { id: Date.now(), text: input, sender: 'me', type: 'text' }]);
    setInput('');
  };

  const handleVoiceRecord = () => {
    setIsRecording(true);
    setTimeout(() => {
      setIsRecording(false);
      setMessages([...messages, { id: Date.now(), text: "[Voice Message]", sender: 'me', type: 'voice' }]);
      alert(t.voiceSent);
    }, 2000);
  };

  const handleLocationShare = () => {
    setMessages([...messages, { id: Date.now(), text: "📍 Shared Location: (24.7, 46.6)", sender: 'me', type: 'location' }]);
    alert(t.locationSent);
  };

  const handleClearChat = () => {
    if (window.confirm(lang === 'ar' ? 'مسح الدردشة؟' : 'Clear chat?')) {
      setMessages([]);
      alert(t.chatCleared);
    }
  };

  const handleBlockUser = () => {
    if (window.confirm(t.block)) {
      alert(t.userBlocked);
    }
  };

  const handleReportAbuse = () => {
    alert(lang === 'ar' ? 'تم إرسال بلاغ عن إساءة.' : 'Abuse report sent.');
  };

  const handleCreateGroup = () => {
    if (groupData.name && groupData.image) {
      alert(lang === 'ar' ? 'تم إنشاء المجموعة! تم تعيينك كمشرف.' : 'Group created! You have been assigned as Admin.');
      setShowGroupCreate(false);
    }
  };

  return (
    <div className="max-w-6xl mx-auto flex h-[calc(100vh-160px)] mt-4 bg-white dark:bg-gray-900 rounded-[3.5rem] overflow-hidden shadow-2xl border border-gray-100 dark:border-gray-800 animate-in fade-in duration-700">
      {/* Sidebar */}
      <div className="w-1/3 border-r dark:border-gray-800 flex flex-col bg-gray-50/30 dark:bg-gray-950/20">
        <div className="p-8">
           <h1 className="text-3xl font-black dark:text-white mb-8 tracking-tighter uppercase italic text-brand">my rents</h1>
           <div className="flex gap-2 mb-8 p-1.5 bg-gray-100 dark:bg-gray-800 rounded-[2rem]">
            <button onClick={() => setActiveTab('PRIVATE')} className={`flex-1 py-3 rounded-[1.5rem] text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === 'PRIVATE' ? 'bg-white dark:bg-gray-900 text-brand shadow-md' : 'text-gray-400'}`}>Direct</button>
            <button onClick={() => setActiveTab('GROUPS')} className={`flex-1 py-3 rounded-[1.5rem] text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === 'GROUPS' ? 'bg-white dark:bg-gray-900 text-brand shadow-md' : 'text-gray-400'}`}>{t.groups}</button>
          </div>
