import { translations } from './i18n';
import { Camera, MapPin, Shield, Sun, Moon, ShieldBan, FileText, Crown, User as UserIcon } from 'lucide-react';

const App: React.FC = () => {
  const [lang, setLang] = useState<string>('ar');
