            <input type="text" required placeholder={t.signupSteps.userName + "*"} value={signupData.username} onChange={e => setSignupData({...signupData, username: e.target.value})} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none" />
