          <label className="flex items-center gap-3 cursor-pointer p-4 bg-gray-50 dark:bg-gray-800 rounded-2xl">
            <input type="checkbox" required checked={signupData.agreed} onChange={e => setSignupData({...signupData, agreed: e.target.checked})} className="w-5 h-5 accent-brand" />
