              <Route path="/privacy" element={<PrivacyPolicyPage lang={lang} />} />
              <Route path="/terms" element={<TermsOfUsePage lang={lang} />} />
              <Route path="/profile" element={
                <div className="p-8 text-center max-w-2xl mx-auto">
                  <div className="bg-white dark:bg-gray-900 rounded-[3rem] p-10 shadow-sm border dark:border-gray-800">
                    <img src={user.avatar || `https://api.dicebear.com/7.x/avataaars/svg?seed=${user.username}`} className="w-32 h-32 mx-auto rounded-full border-4 border-brand mb-4 object-cover" />
                    <h1 className="text-2xl font-black dark:text-white">{user.fullName}</h1>
                    <p className="text-[#CCCCCC] mb-8">@{user.username}</p>

                    <div className="bg-gray-50 dark:bg-gray-800 p-6 rounded-3xl text-left mb-6">
                      <h3 className="font-bold flex items-center gap-2 mb-4 dark:text-white"><ShieldBan size={20} className="text-brand" /> {t.blockedList}</h3>
                      <p className="text-xs text-gray-400 italic">No blocked accounts found.</p>
                    </div>

                    <button onClick={() => setUser(null)} className="text-red-500 font-bold hover:underline">{t.logout}</button>
                  </div>
                </div>
              } />
              <Route path="*" element={<Navigate to="/" />} />
            </Routes>
          )}
        </main>
      </div>
    </HashRouter>
  );
};

export default App;

