              <label className="aspect-square border-2 border-dashed border-gray-200 dark:border-gray-700 rounded-xl flex items-center justify-center cursor-pointer text-gray-400">
                <Camera /><input type="file" multiple accept="image/*" className="hidden" onChange={e => {
                  // Explicitly type the mapped element as File to avoid unknown parameter type error for URL.createObjectURL
                  if (e.target.files) {
                    const files = Array.from(e.target.files).map((f: File) => URL.createObjectURL(f));
                    setImages([...images, ...files].slice(0, 5));
                  }
                }} />
              </label>
            )}
          </div>
          <label className="flex items-center gap-2 p-4 border rounded-2xl dark:text-white cursor-pointer">
            <Video size={20} className="text-brand" /> {lang === 'ar' ? 'رفع فيديو (اختياري)' : 'Upload Video'}
            <input type="file" accept="video/*" className="hidden" onChange={e => {
              // Check if files exist and have at least one element before creating object URL
              if (e.target.files && e.target.files[0]) {
                setVideo(URL.createObjectURL(e.target.files[0]));
              }
            }} />
