          <input type="number" placeholder="Price (USD)*" value={price} onChange={e => setPrice(e.target.value)} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none" />
          <select value={period} onChange={e => setPeriod(e.target.value as RentalPeriod)} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none">
            {Object.keys(RentalPeriod).map(p => <option key={p} value={p}>{t.periods[p]}</option>)}
          </select>
          <div className="p-4 bg-brand/5 border border-brand/20 rounded-2xl text-center">
             <ShieldCheck size={40} className="mx-auto text-brand mb-2 animate-pulse" />
             <h3 className="font-bold dark:text-white mb-1">{t.aiChecking}</h3>
             <p className="text-[10px] text-gray-400 uppercase tracking-widest">AI my rents verification required</p>
          </div>
