                    <button onClick={() => setUser(null)} className="text-red-500 font-black uppercase tracking-widest text-sm hover:underline">{t.logout}</button>
                  </div>
                </div>
              } />
              <Route path="*" element={<Navigate to="/" />} />
            </Routes>
          )}
        </main>
      </div>
    </HashRouter>
  );
};

export default App;

import React, { useState } from 'react';
