import React, { useState, useEffect } from 'react';
import { HashRouter, Routes, Route, Navigate, Link } from 'react-router-dom';
import { User, Gender, Listing } from './types';
import Navbar from './components/Navbar';
import HomePage from './pages/HomePage';
import ItemDetailPage from './pages/ItemDetailPage';
import CreateListingPage from './pages/CreateListingPage';
import ChatPage from './pages/ChatPage';
import PrivacyPolicyPage from './pages/PrivacyPolicyPage';
import TermsOfUsePage from './pages/TermsOfUsePage';
import { translations } from './i18n';
import { Camera, MapPin, Shield, Sun, Moon, ShieldBan, FileText, ChevronRight, ChevronLeft } from 'lucide-react';

const App: React.FC = () => {
  const [lang, setLang] = useState<string>('ar');
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [user, setUser] = useState<User | null>(null);
  const [userListings, setUserListings] = useState<Listing[]>([]);

  useEffect(() => {
    if (isDarkMode) document.documentElement.classList.add('dark');
    else document.documentElement.classList.remove('dark');
  }, [isDarkMode]);

  const toggleTheme = () => setIsDarkMode(!isDarkMode);
  const t = translations[lang] || translations['en'];

  const handleSignUpFinish = (e: React.FormEvent, data: any) => {
    e.preventDefault();
    const newUser: User = {
      id: 'u_' + Date.now(),
      fullName: data.fullName,
      username: data.username,
      email: data.email,
      avatar: data.avatar,
      gender: Gender.OTHER,
      birthDate: '2000-01-01',
      location: data.location,
      status: 'Member',
      points: 100,
      listingsCount: 0,
      walletBalance: 0,
      payoutMethods: {},
      blockedUsers: []
    };
    setUser(newUser);
  };

  const SignUpPage = () => {
    const [signupData, setSignupData] = useState({
      avatar: '', fullName: '', username: '', location: { address: '', lat: 0, lng: 0 },
      email: '', password: '', agreed: false
    });

    const isFormValid = signupData.avatar && signupData.fullName && signupData.username && signupData.location.address && signupData.email && signupData.password && signupData.agreed;

    return (
      <div className="w-full max-w-2xl px-6 py-12 mx-auto animate-in fade-in slide-in-from-bottom-8">
