          </div>
        </form>
      </div>
    );
  };

  return (
    <HashRouter>
      <div className={`min-h-screen ${lang === 'ar' ? 'rtl' : 'ltr'} bg-white dark:bg-gray-950 transition-colors duration-200`} dir={lang === 'ar' ? 'rtl' : 'ltr'}>
        {user && <Navbar lang={lang} isDark={isDarkMode} toggleTheme={toggleTheme} user={user} />}
        <main className={user ? 'pb-20' : ''}>
          {!user ? <SignUpPage /> : (
            <Routes>
              <Route path="/" element={<HomePage lang={lang} user={user} userListings={userListings} onDeleteListing={(id) => setUserListings(userListings.filter(l => l.id !== id))} />} />
              <Route path="/create" element={<CreateListingPage lang={lang} user={user} onCreated={(l) => setUserListings([...userListings, l])} />} />
              <Route path="/chat/*" element={<ChatPage lang={lang} />} />
              <Route path="/item/:id" element={<ItemDetailPage lang={lang} user={user} listings={userListings} onDelete={(id) => setUserListings(userListings.filter(l => l.id !== id))} />} />
              <Route path="/privacy" element={<PrivacyPolicyPage lang={lang} />} />
              <Route path="/terms" element={<TermsOfUsePage lang={lang} />} />
              <Route path="/profile" element={
                <div className="p-8 text-center max-w-2xl mx-auto animate-in fade-in">
                  <div className="bg-white dark:bg-gray-900 rounded-[3rem] p-10 shadow-sm border dark:border-gray-800">
                    <img src={user.avatar || `https://api.dicebear.com/7.x/avataaars/svg?seed=${user.username}`} className="w-32 h-32 mx-auto rounded-full border-4 border-brand mb-4 object-cover" />
                    <h1 className="text-2xl font-black dark:text-white uppercase tracking-tighter">{user.fullName}</h1>
                    <p className="text-[#CCCCCC] mb-8 font-bold">@{user.username}</p>

                    <div className="grid grid-cols-2 gap-4 mb-8">
                       <div className="p-4 bg-gray-50 dark:bg-gray-800 rounded-3xl">
                          <span className="text-[10px] text-gray-400 font-black uppercase block">{lang === 'ar' ? 'نقاطك' : 'Your Points'}</span>
                          <span className="text-xl font-black text-brand">{user.points}</span>
                       </div>
                       <div className="p-4 bg-gray-50 dark:bg-gray-800 rounded-3xl">
                          <span className="text-[10px] text-gray-400 font-black uppercase block">{lang === 'ar' ? 'إعلاناتك' : 'Your Listings'}</span>
                          <span className="text-xl font-black text-brand">{userListings.length}</span>
                       </div>
                    </div>

                    <div className="space-y-3 mb-8">
                      <h3 className="text-left font-black text-[10px] text-gray-400 uppercase tracking-widest px-4">{lang === 'ar' ? 'القانونية' : 'Legal'}</h3>
                      <Link to="/privacy" className="flex items-center justify-between p-4 bg-gray-50 dark:bg-gray-800 rounded-2xl hover:bg-gray-100 dark:hover:bg-gray-700 transition-colors">
                        <div className="flex items-center gap-3">
                          <Shield size={20} className="text-brand" />
                          <span className="text-sm font-bold dark:text-white">{t.privacyPolicy}</span>
                        </div>
                        {lang === 'ar' ? <ChevronLeft size={18} className="text-gray-400" /> : <ChevronRight size={18} className="text-gray-400" />}
                      </Link>
                      <Link to="/terms" className="flex items-center justify-between p-4 bg-gray-50 dark:bg-gray-800 rounded-2xl hover:bg-gray-100 dark:hover:bg-gray-700 transition-colors">
                        <div className="flex items-center gap-3">
                          <FileText size={20} className="text-brand" />
                          <span className="text-sm font-bold dark:text-white">{t.termsOfUse}</span>
                        </div>
                        {lang === 'ar' ? <ChevronLeft size={18} className="text-gray-400" /> : <ChevronRight size={18} className="text-gray-400" />}
                      </Link>
                      <button className="w-full flex items-center justify-between p-4 bg-gray-50 dark:bg-gray-800 rounded-2xl hover:bg-gray-100 dark:hover:bg-gray-700 transition-colors">
                        <div className="flex items-center gap-3 text-gray-400">
                          <ShieldBan size={20} />
                          <span className="text-sm font-bold">{t.blockedList}</span>
                        </div>
                      </button>
                    </div>

                    <button onClick={() => setUser(null)} className="text-red-500 font-black uppercase tracking-widest text-xs hover:underline">{t.logout}</button>
                  </div>
                </div>
              } />
              <Route path="*" element={<Navigate to="/" />} />
            </Routes>
          )}
        </main>
      </div>
    </HashRouter>
  );
};

export default App;

