import React, { useState, useRef } from 'react';
import { translations } from '../i18n';
import { CATEGORIES } from '../constants';
import { CurrencyType, RentalPeriod, ListingType, Listing } from '../types';
import { checkListingContent } from '../services/geminiService';
import { Camera, Video, MapPin, Loader2, CheckCircle, ShieldCheck, CreditCard, Bitcoin, Zap, ArrowRight, ArrowLeft } from 'lucide-react';
import { useNavigate } from 'react-router-dom';

const CreateListingPage: React.FC<{ lang: string; user: any; onCreated: (l: Listing) => void }> = ({ lang, user, onCreated }) => {
  const t = translations[lang] || translations['en'];
  const navigate = useNavigate();
  const [step, setStep] = useState(1);
  const [loading, setLoading] = useState(false);

  const imageInputRef = useRef<HTMLInputElement>(null);
  const videoInputRef = useRef<HTMLInputElement>(null);

  const [images, setImages] = useState<string[]>([]);
  const [video, setVideo] = useState<string | null>(null);
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [category, setCategory] = useState(CATEGORIES[0]);
  const [currencyType, setCurrencyType] = useState<CurrencyType>(CurrencyType.LOCAL);
  const [payoutMethod, setPayoutMethod] = useState('');
  const [price, setPrice] = useState('');
  const [period, setPeriod] = useState<RentalPeriod>(RentalPeriod.DAY);

  const cryptoCoins = ['Solana', 'Ethereum', 'Monad', 'Base', 'Sui', 'Polygon', 'Bitcoin'];

  const handlePublish = async () => {
    setLoading(true);
    const result = await checkListingContent(title, description);
    if (result.status === 'APPROVED') {
      const l: Listing = {
        id: 'l_' + Date.now(), ownerId: user.id, ownerName: user.fullName, ownerUsername: user.username,
        ownerAvatar: user.avatar, title, description, type: ListingType.RENT, price: parseFloat(price),
        currency: 'USD', currencyType, payoutAddress: payoutMethod, category, location: user.location,
        images, video: video || undefined, rentalPeriod: period, createdAt: new Date().toISOString(),
        views: 0, likes: 0, rating: 0, isAiApproved: true
      };
      onCreated(l);
      setStep(5);
    } else {
      alert(t.aiRejected + ": " + result.reason);
    }
    setLoading(false);
  };

  return (
    <div className="max-w-2xl mx-auto p-6 bg-white dark:bg-gray-900 rounded-[3rem] my-8 border dark:border-gray-800 shadow-sm">
      <div className="flex gap-1 mb-8">
        {[1,2,3,4,5].map(s => <div key={s} className={`h-1.5 flex-1 rounded-full ${step >= s ? 'bg-brand' : 'bg-gray-100 dark:bg-gray-800'}`} />)}
      </div>

      {step === 1 && (
        <div className="space-y-6">
          <h2 className="text-2xl font-black dark:text-white">{lang === 'ar' ? 'رفع الصور (2-5) والفيديو' : 'Media'}</h2>
          <div className="grid grid-cols-3 gap-2">
            {images.map((img, i) => <img key={i} src={img} className="aspect-square object-cover rounded-xl" />)}
            {images.length < 5 && (
              <button 
                type="button"
                onClick={() => imageInputRef.current?.click()}
                className="aspect-square border-2 border-dashed border-gray-200 dark:border-gray-700 rounded-xl flex items-center justify-center cursor-pointer text-gray-400 hover:border-brand hover:text-brand transition-all"
              >
                <Camera />
                <input 
                  type="file" 
                  ref={imageInputRef}
                  multiple 
                  accept="image/*" 
                  className="hidden" 
                  onChange={e => {
                    if (e.target.files) {
                      const files = Array.from(e.target.files).map((f: File) => URL.createObjectURL(f));
                      setImages([...images, ...files].slice(0, 5));
                    }
                  }} 
                />
              </button>
            )}
          </div>
          <button 
            type="button"
            onClick={() => videoInputRef.current?.click()}
            className="w-full flex items-center gap-2 p-4 border rounded-2xl dark:text-white cursor-pointer hover:bg-gray-50 dark:hover:bg-gray-800 transition-all"
          >
            <Video size={20} className="text-brand" /> {lang === 'ar' ? 'رفع فيديو (اختياري)' : 'Upload Video'}
            <input 
              type="file" 
              ref={videoInputRef}
              accept="video/*" 
              className="hidden" 
              onChange={e => {
                if (e.target.files && e.target.files[0]) {
                  setVideo(URL.createObjectURL(e.target.files[0]));
                }
              }} 
            />
          </button>
          <button disabled={images.length < 2} onClick={() => setStep(2)} className="w-full py-4 bg-brand text-white rounded-2xl font-bold disabled:opacity-30">{t.next}</button>
        </div>
      )}

      {step === 2 && (
        <div className="space-y-4">
          <h2 className="text-2xl font-black dark:text-white">{lang === 'ar' ? 'تفاصيل المنتج' : 'Details'}</h2>
          <input type="text" placeholder="Product Name*" value={title} onChange={e => setTitle(e.target.value)} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none" />
          <textarea placeholder="Description*" value={description} onChange={e => setDescription(e.target.value)} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white h-32 outline-none" />
          <select value={category} onChange={e => setCategory(e.target.value)} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none">
            {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
          </select>
          <button disabled={!title || !description} onClick={() => setStep(3)} className="w-full py-4 bg-brand text-white rounded-2xl font-bold">{t.next}</button>
        </div>
      )}

      {step === 3 && (
        <div className="space-y-6">
          <h2 className="text-2xl font-black dark:text-white">{t.payoutMethod}*</h2>
          <div className="flex gap-2 p-1 bg-gray-100 dark:bg-gray-800 rounded-2xl">
            <button onClick={() => {setCurrencyType(CurrencyType.CRYPTO); setPayoutMethod('')}} className={`flex-1 py-3 rounded-xl font-bold ${currencyType === CurrencyType.CRYPTO ? 'bg-white dark:bg-gray-900 text-brand shadow' : 'text-gray-400'}`}>{t.crypto}</button>
            <button onClick={() => {setCurrencyType(CurrencyType.LOCAL); setPayoutMethod('')}} className={`flex-1 py-3 rounded-xl font-bold ${currencyType === CurrencyType.LOCAL ? 'bg-white dark:bg-gray-900 text-brand shadow' : 'text-gray-400'}`}>{t.local}</button>
          </div>
          {currencyType === CurrencyType.CRYPTO ? (
            <div className="grid grid-cols-2 gap-2">
              {cryptoCoins.map(coin => (
                <button key={coin} onClick={() => setPayoutMethod(coin)} className={`p-3 rounded-xl border-2 text-xs font-bold transition-all ${payoutMethod === coin ? 'border-brand bg-brand/5 text-brand' : 'border-transparent bg-gray-50 dark:bg-gray-800 dark:text-white'}`}>{coin}</button>
              ))}
            </div>
          ) : (
            <input type="email" placeholder="PayPal Email*" value={payoutMethod} onChange={e => setPayoutMethod(e.target.value)} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none" />
          )}
          <button disabled={!payoutMethod} onClick={() => setStep(4)} className="w-full py-4 bg-brand text-white rounded-2xl font-bold">{t.next}</button>
        </div>
      )}

      {step === 4 && (
        <div className="space-y-6">
          <h2 className="text-2xl font-black dark:text-white">{lang === 'ar' ? 'السعر وفترة الإيجار' : 'Price & Period'}</h2>
          <input type="number" placeholder="Price (USD)*" value={price} onChange={e => setPrice(e.target.value)} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none" />
          <select value={period} onChange={e => setPeriod(e.target.value as RentalPeriod)} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none">
            {Object.keys(RentalPeriod).map(p => <option key={p} value={p}>{t.periods[p]}</option>)}
          </select>
          <div className="p-4 bg-brand/5 border border-brand/20 rounded-2xl text-center">
             <ShieldCheck size={40} className="mx-auto text-brand mb-2 animate-pulse" />
             <h3 className="font-bold dark:text-white mb-1">{t.aiChecking}</h3>
             <p className="text-[10px] text-gray-400 uppercase tracking-widest">AI my rents verification required</p>
          </div>
          <button onClick={handlePublish} disabled={loading} className="w-full py-5 bg-brand text-white rounded-[2rem] font-black shadow-xl shadow-brand/20 flex items-center justify-center gap-2">
            {loading ? <Loader2 className="animate-spin" /> : <><ShieldCheck size={20} /> Publish to Market</>}
          </button>
        </div>
      )}

      {step === 5 && (
        <div className="text-center py-12 space-y-6">
          <CheckCircle size={80} className="mx-auto text-green-500" />
          <h2 className="text-3xl font-black dark:text-white">{t.aiApproved}</h2>
          <button onClick={() => navigate('/')} className="w-full py-4 bg-brand text-white rounded-2xl font-bold">Return Home</button>
        </div>
      )}
    </div>
  );
};

export default CreateListingPage;

import React, { useState, useRef } from 'react';
import { translations } from '../i18n';
import { Mic, Image, Video, Trash2, MapPin, Flag, ShieldBan, Send, Users, UserPlus, Search, ShieldCheck, Camera } from 'lucide-react';

const ChatPage: React.FC<{ lang: string }> = ({ lang }) => {
