import React, { useState, useEffect, useRef } from 'react';
import { HashRouter, Routes, Route, Navigate, Link } from 'react-router-dom';
import { User, Gender, Listing } from './types';
import Navbar from './components/Navbar';
import HomePage from './pages/HomePage';
import ItemDetailPage from './pages/ItemDetailPage';
import CreateListingPage from './pages/CreateListingPage';
import ChatPage from './pages/ChatPage';
import PrivacyPolicyPage from './pages/PrivacyPolicyPage';
import TermsOfUsePage from './pages/TermsOfUsePage';
import { translations } from './i18n';
import { Camera, MapPin, Shield, Sun, Moon, ShieldBan, FileText, ChevronRight, ChevronLeft, Loader2, MapPinned } from 'lucide-react';

const App: React.FC = () => {
  const [lang, setLang] = useState<string>('ar');
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [user, setUser] = useState<User | null>(null);
  const [userListings, setUserListings] = useState<Listing[]>([]);

  useEffect(() => {
    if (isDarkMode) document.documentElement.classList.add('dark');
    else document.documentElement.classList.remove('dark');
  }, [isDarkMode]);

  const toggleTheme = () => setIsDarkMode(!isDarkMode);
  const t = translations[lang] || translations['en'];

  const handleSignUpFinish = (e: React.FormEvent, data: any) => {
    e.preventDefault();
    const newUser: User = {
      id: 'u_' + Date.now(),
      fullName: data.fullName,
      username: data.username,
      email: data.email,
      avatar: data.avatar,
      gender: Gender.OTHER,
      birthDate: '2000-01-01',
      location: data.location,
      status: 'Member',
      points: 100,
      listingsCount: 0,
      walletBalance: 0,
      payoutMethods: {},
      blockedUsers: []
    };
    setUser(newUser);
  };

  const SignUpPage = () => {
    const fileInputRef = useRef<HTMLInputElement>(null);
    const [signupData, setSignupData] = useState({
      avatar: '', fullName: '', username: '', location: { address: '', lat: 0, lng: 0 },
      email: '', password: '', agreed: false
    });
    const [isLocating, setIsLocating] = useState(false);

    const handleAvatarClick = () => {
      fileInputRef.current?.click();
    };

    const handleGetLocation = () => {
      setIsLocating(true);
      if (!navigator.geolocation) {
        alert(lang === 'ar' ? 'متصفحك لا يدعم تحديد الموقع' : 'Geolocation is not supported by your browser');
        setIsLocating(false);
        return;
      }

      navigator.geolocation.getCurrentPosition(
        (position) => {
          const { latitude, longitude } = position.coords;
          const addr = lang === 'ar' 
            ? `موقع دقيق (${latitude.toFixed(4)}, ${longitude.toFixed(4)})` 
            : `Precise Location (${latitude.toFixed(4)}, ${longitude.toFixed(4)})`;

          setSignupData({
            ...signupData, 
            location: { address: addr, lat: latitude, lng: longitude }
          });
          setIsLocating(false);
        },
        (error) => {
          console.error(error);
          alert(lang === 'ar' ? 'فشل تحديد الموقع. يرجى تفعيل GPS ومنح الإذن.' : 'Failed to get location. Please enable GPS and grant permission.');
          setIsLocating(false);
        },
        { enableHighAccuracy: true, timeout: 10000, maximumAge: 0 }
      );
    };

    const isFormValid = signupData.avatar && signupData.fullName && signupData.username && signupData.location.address && signupData.email && signupData.password && signupData.agreed;

    return (
      <div className="w-full max-w-2xl px-6 py-12 mx-auto animate-in fade-in slide-in-from-bottom-8">
        <div className="text-center mb-10">
          <div className="inline-block px-4 py-2 bg-brand text-white rounded-2xl shadow-xl font-black text-2xl mb-4 italic">my rents</div>
          <h1 className="text-3xl font-black dark:text-white mb-2">{lang === 'ar' ? 'إنشاء حساب جديد' : 'Create Account'}</h1>
        </div>

        <form onSubmit={(e) => handleSignUpFinish(e, signupData)} className="space-y-6">
          <div className="flex flex-col items-center gap-2">
            <button 
              type="button"
              onClick={handleAvatarClick}
              className="w-32 h-32 rounded-full bg-gray-100 dark:bg-gray-800 flex items-center justify-center border-4 border-brand cursor-pointer overflow-hidden relative hover:scale-105 transition-transform"
            >
               {signupData.avatar ? <img src={signupData.avatar} className="w-full h-full object-cover" /> : <Camera size={40} className="text-gray-400" />}
               <input 
                 type="file" 
                 ref={fileInputRef}
                 required 
                 className="hidden" 
                 accept="image/*"
                 onChange={e => {
                   if (e.target.files && e.target.files[0]) {
                     setSignupData({...signupData, avatar: URL.createObjectURL(e.target.files[0])});
                   }
                 }} 
               />
            </button>
            <span className="text-[10px] font-black uppercase text-gray-400">{t.signupSteps.profilePic}*</span>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <input type="text" required placeholder={t.signupSteps.personalName + "*"} value={signupData.fullName} onChange={e => setSignupData({...signupData, fullName: e.target.value})} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none focus:ring-2 focus:ring-brand font-bold" />
            <input type="text" required placeholder={t.signupSteps.userName + "*"} value={signupData.username} onChange={e => setSignupData({...signupData, username: e.target.value})} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none focus:ring-2 focus:ring-brand font-bold" />
          </div>

          <div className="flex gap-2">
            <div className={`flex-1 p-4 bg-gray-50 dark:bg-gray-800 rounded-2xl text-sm truncate flex items-center font-bold ${signupData.location.address ? 'text-brand' : 'text-gray-400'}`}>
              <MapPinned size={16} className="mr-2 ml-2" />
              {isLocating ? (lang === 'ar' ? 'جاري تحديد موقعك...' : 'Locating you...') : (signupData.location.address || t.signupSteps.geolocation)}
            </div>
            <button 
              type="button" 
              onClick={handleGetLocation} 
              disabled={isLocating}
              className="px-6 bg-white dark:bg-gray-700 text-brand dark:text-white border border-gray-100 dark:border-gray-600 rounded-2xl font-bold transition-all active:scale-95 disabled:opacity-50 flex items-center justify-center shadow-sm hover:shadow-md"
            >
              {isLocating ? <Loader2 size={20} className="animate-spin text-brand" /> : '📍'}
            </button>
          </div>

          <input type="email" required placeholder="Email*" value={signupData.email} onChange={e => setSignupData({...signupData, email: e.target.value})} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none focus:ring-2 focus:ring-brand font-bold" />
          <input type="password" required placeholder="Password*" value={signupData.password} onChange={e => setSignupData({...signupData, password: e.target.value})} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none focus:ring-2 focus:ring-brand font-bold" />

          <div className="p-4 bg-gray-50 dark:bg-gray-800 rounded-2xl flex items-start gap-3">
            <input type="checkbox" required checked={signupData.agreed} onChange={e => setSignupData({...signupData, agreed: e.target.checked})} className="mt-1 w-5 h-5 accent-brand cursor-pointer" id="agree-terms" />
            <label htmlFor="agree-terms" className="text-xs dark:text-white font-bold leading-relaxed cursor-pointer select-none">
              {lang === 'ar' ? (
                <>
                  أوافق على <Link to="/privacy" className="text-brand hover:underline">سياسة الخصوصية</Link> و <Link to="/terms" className="text-brand hover:underline">شروط الاستخدام</Link>
                </>
              ) : (
                <>
                  I agree to the <Link to="/privacy" className="text-brand hover:underline">Privacy Policy</Link> and <Link to="/terms" className="text-brand hover:underline">Terms of Use</Link>
                </>
              )}
            </label>
          </div>

          <button type="submit" disabled={!isFormValid} className="w-full py-5 bg-brand text-white rounded-3xl font-black shadow-xl disabled:opacity-30 transition-transform active:scale-95 uppercase tracking-widest">
            {lang === 'ar' ? 'إنشاء الحساب' : 'Sign Up'}
          </button>

          <div className="flex justify-center gap-4 pt-4">
             <button type="button" onClick={() => setLang(lang === 'ar' ? 'en' : 'ar')} className="text-xs font-black text-gray-400 uppercase tracking-widest hover:text-brand">{lang === 'ar' ? 'English' : 'العربية'}</button>
          </div>
        </form>
      </div>
    );
  };

  return (
    <HashRouter>
      <div className={`min-h-screen ${lang === 'ar' ? 'rtl' : 'ltr'} bg-white dark:bg-gray-950 transition-colors duration-200`} dir={lang === 'ar' ? 'rtl' : 'ltr'}>
        {user && <Navbar lang={lang} isDark={isDarkMode} toggleTheme={toggleTheme} user={user} />}
        <main className={user ? 'pb-20' : ''}>
          <Routes>
            {/* المسار الرئيسي - يعتمد على حالة تسجيل الدخول */}
            <Route path="/" element={!user ? <SignUpPage /> : <HomePage lang={lang} user={user} userListings={userListings} onDeleteListing={(id) => setUserListings(userListings.filter(l => l.id !== id))} />} />

            {/* صفحات السياسات - متاحة دائماً */}
            <Route path="/privacy" element={<PrivacyPolicyPage lang={lang} />} />
            <Route path="/terms" element={<TermsOfUsePage lang={lang} />} />

            {/* المسارات المحمية - تتطلب تسجيل دخول */}
            {user && (
              <>
                <Route path="/create" element={<CreateListingPage lang={lang} user={user} onCreated={(l) => setUserListings([...userListings, l])} />} />
                <Route path="/chat/*" element={<ChatPage lang={lang} />} />
                <Route path="/item/:id" element={<ItemDetailPage lang={lang} user={user} listings={userListings} onDelete={(id) => setUserListings(userListings.filter(l => l.id !== id))} />} />
                <Route path="/profile" element={
                  <div className="p-8 text-center max-w-2xl mx-auto animate-in fade-in">
                    <div className="bg-white dark:bg-gray-900 rounded-[3rem] p-10 shadow-sm border dark:border-gray-800">
                      <img src={user.avatar || `https://api.dicebear.com/7.x/avataaars/svg?seed=${user.username}`} className="w-32 h-32 mx-auto rounded-full border-4 border-brand mb-4 object-cover" />
                      <h1 className="text-2xl font-black dark:text-white uppercase tracking-tighter">{user.fullName}</h1>
                      <p className="text-[#CCCCCC] mb-8 font-bold">@{user.username}</p>

                      <div className="grid grid-cols-2 gap-4 mb-8">
                         <div className="p-4 bg-gray-50 dark:bg-gray-800 rounded-3xl">
                            <span className="text-[10px] text-gray-400 font-black uppercase block">{lang === 'ar' ? 'نقاطك' : 'Your Points'}</span>
                            <span className="text-xl font-black text-brand">{user.points}</span>
                         </div>
                         <div className="p-4 bg-gray-50 dark:bg-gray-800 rounded-3xl">
                            <span className="text-[10px] text-gray-400 font-black uppercase block">{lang === 'ar' ? 'إعلاناتك' : 'Your Listings'}</span>
                            <span className="text-xl font-black text-brand">{userListings.length}</span>
                         </div>
                      </div>

                      <div className="space-y-3 mb-8">
                        <h3 className="text-left font-black text-[10px] text-gray-400 uppercase tracking-widest px-4">{lang === 'ar' ? 'القانونية' : 'Legal'}</h3>
                        <Link to="/privacy" className="flex items-center justify-between p-4 bg-gray-50 dark:bg-gray-800 rounded-2xl hover:bg-gray-100 dark:hover:bg-gray-700 transition-colors">
                          <div className="flex items-center gap-3">
                            <Shield size={20} className="text-brand" />
                            <span className="text-sm font-bold dark:text-white">{t.privacyPolicy}</span>
                          </div>
                          {lang === 'ar' ? <ChevronLeft size={18} className="text-gray-400" /> : <ChevronRight size={18} className="text-gray-400" />}
                        </Link>
                        <Link to="/terms" className="flex items-center justify-between p-4 bg-gray-50 dark:bg-gray-800 rounded-2xl hover:bg-gray-100 dark:hover:bg-gray-700 transition-colors">
                          <div className="flex items-center gap-3">
                            <FileText size={20} className="text-brand" />
                            <span className="text-sm font-bold dark:text-white">{t.termsOfUse}</span>
                          </div>
                          {lang === 'ar' ? <ChevronLeft size={18} className="text-gray-400" /> : <ChevronRight size={18} className="text-gray-400" />}
                        </Link>
                        <button className="w-full flex items-center justify-between p-4 bg-gray-50 dark:bg-gray-800 rounded-2xl hover:bg-gray-100 dark:hover:bg-gray-700 transition-colors">
                          <div className="flex items-center gap-3 text-gray-400">
                            <ShieldBan size={20} />
                            <span className="text-sm font-bold">{t.blockedList}</span>
                          </div>
                        </button>
                      </div>

                      <button onClick={() => setUser(null)} className="text-red-500 font-black uppercase tracking-widest text-xs hover:underline">{t.logout}</button>
                    </div>
                  </div>
                } />
              </>
            )}

            {/* إعادة توجيه أي مسار غير معروف */}
            <Route path="*" element={<Navigate to="/" />} />
          </Routes>
        </main>
      </div>
    </HashRouter>
  );
};

export default App;

