import React, { useState, useEffect, useRef } from 'react';
import { HashRouter, Routes, Route, Navigate, Link } from 'react-router-dom';
import { User, Gender, Listing } from './types';
import Navbar from './components/Navbar';
import HomePage from './pages/HomePage';
import ItemDetailPage from './pages/ItemDetailPage';
import CreateListingPage from './pages/CreateListingPage';
import ChatPage from './pages/ChatPage';
import PrivacyPolicyPage from './pages/PrivacyPolicyPage';
import TermsOfUsePage from './pages/TermsOfUsePage';
import { translations } from './i18n';
import { POINTS_SYSTEM } from './constants';
import { Camera, Shield, ChevronRight, ChevronLeft, Loader2, MapPinned, Compass } from 'lucide-react';

const App: React.FC = () => {
  const [lang, setLang] = useState<string>('ar');
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [user, setUser] = useState<User | null>(null);
  const [userListings, setUserListings] = useState<Listing[]>([]);

  useEffect(() => {
    if (isDarkMode) document.documentElement.classList.add('dark');
    else document.documentElement.classList.remove('dark');
  }, [isDarkMode]);

  const toggleTheme = () => setIsDarkMode(!isDarkMode);
  const t = translations[lang] || translations['en'];

  const addPoints = (amount: number) => {
    if (user) {
      setUser({ ...user, points: user.points + amount });
    }
  };

  const handleSignUpFinish = (e: React.FormEvent, data: any) => {
    e.preventDefault();
    const newUser: User = {
      id: 'u_' + Date.now(),
      fullName: data.fullName,
      username: data.username,
      email: data.email,
      avatar: data.avatar,
      gender: Gender.OTHER,
      birthDate: '2000-01-01',
      location: data.location,
      status: 'Member',
      points: 0, // يبدأ بـ 0 نقاط كما طلب المستخدم
      listingsCount: 0,
      walletBalance: 0,
      payoutMethods: {},
      blockedUsers: []
    };
    setUser(newUser);
  };

  const SignUpPage = () => {
    const fileInputRef = useRef<HTMLInputElement>(null);
    const [signupData, setSignupData] = useState({
      avatar: '', fullName: '', username: '', location: { address: '', lat: 0, lng: 0 },
      email: '', password: '', agreed: false
    });
    const [isLocating, setIsLocating] = useState(false);

    const handleAvatarClick = () => fileInputRef.current?.click();

    const handleGetLocation = () => {
      setIsLocating(true);
      if (!navigator.geolocation) {
        alert(lang === 'ar' ? 'متصفحك لا يدعم تحديد الموقع' : 'Geolocation not supported');
        setIsLocating(false);
        return;
      }
      navigator.geolocation.getCurrentPosition((pos) => {
        const addr = lang === 'ar' ? `موقعي الحالي` : `Current Location`;
        setSignupData({ ...signupData, location: { address: addr, lat: pos.coords.latitude, lng: pos.coords.longitude } });
        setIsLocating(false);
      }, () => {
        alert(lang === 'ar' ? 'فشل التحديد' : 'Location failed');
        setIsLocating(false);
      });
    };

    return (
      <div className="w-full max-w-2xl px-6 py-12 mx-auto animate-in fade-in slide-in-from-bottom-8">
        <div className="text-center mb-10">
          <div className="inline-block px-4 py-2 bg-brand text-white rounded-2xl shadow-xl font-black text-2xl mb-4 italic">my rents</div>
          <h1 className="text-3xl font-black dark:text-white mb-2">{lang === 'ar' ? 'إنشاء حساب جديد' : 'Create Account'}</h1>
        </div>

        <form onSubmit={(e) => handleSignUpFinish(e, signupData)} className="space-y-6">
          <div className="flex flex-col items-center gap-2">
            <button type="button" onClick={handleAvatarClick} className="w-32 h-32 rounded-full bg-gray-100 dark:bg-gray-800 flex items-center justify-center border-4 border-brand cursor-pointer overflow-hidden relative">
               {signupData.avatar ? <img src={signupData.avatar} className="w-full h-full object-cover" /> : <Camera size={40} className="text-gray-400" />}
               <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={e => e.target.files && setSignupData({...signupData, avatar: URL.createObjectURL(e.target.files[0])})} />
            </button>
            <span className="text-[10px] font-black uppercase text-gray-400">{t.signupSteps.profilePic}*</span>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <input type="text" required placeholder={t.signupSteps.personalName} value={signupData.fullName} onChange={e => setSignupData({...signupData, fullName: e.target.value})} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none focus:ring-2 focus:ring-brand font-bold" />
            <input type="text" required placeholder={t.signupSteps.userName} value={signupData.username} onChange={e => setSignupData({...signupData, username: e.target.value})} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none focus:ring-2 focus:ring-brand font-bold" />
          </div>
          <div className="flex gap-2">
            <div className="flex-1 p-4 bg-gray-50 dark:bg-gray-800 rounded-2xl text-sm truncate flex items-center font-bold dark:text-white">
              <MapPinned size={16} className="mr-2 ml-2 text-brand" />
              {signupData.location.address || t.signupSteps.geolocation}
            </div>
            <button type="button" onClick={handleGetLocation} className="px-6 bg-white dark:bg-gray-700 text-brand border border-gray-100 dark:border-gray-600 rounded-2xl font-bold transition-all active:scale-95 shadow-sm">
              {isLocating ? <Loader2 size={20} className="animate-spin" /> : '📍'}
            </button>
          </div>
          <div className="p-4 bg-gray-50 dark:bg-gray-800 rounded-2xl flex items-start gap-3">
            <input type="checkbox" required checked={signupData.agreed} onChange={e => setSignupData({...signupData, agreed: e.target.checked})} className="mt-1 w-5 h-5 accent-brand cursor-pointer" id="agree-terms" />
            <label htmlFor="agree-terms" className="text-xs dark:text-white font-bold cursor-pointer">
              أوافق على <Link to="/privacy" className="text-brand hover:underline">سياسة الخصوصية</Link> و <Link to="/terms" className="text-brand hover:underline">شروط الاستخدام</Link>
            </label>
          </div>
          <button type="submit" disabled={!signupData.agreed || !signupData.fullName} className="w-full py-5 bg-brand text-white rounded-3xl font-black shadow-xl disabled:opacity-30">
            {lang === 'ar' ? 'إنشاء الحساب' : 'Sign Up'}
          </button>
        </form>
      </div>
    );
  };

  return (
    <HashRouter>
      <div className={`min-h-screen ${lang === 'ar' ? 'rtl' : 'ltr'} bg-white dark:bg-gray-950 transition-colors duration-200`} dir={lang === 'ar' ? 'rtl' : 'ltr'}>
        {user && <Navbar lang={lang} isDark={isDarkMode} toggleTheme={toggleTheme} user={user} />}
        <main className={user ? 'pb-20' : ''}>
          <Routes>
            <Route path="/" element={!user ? <SignUpPage /> : <HomePage lang={lang} user={user} userListings={userListings} onDeleteListing={(id) => setUserListings(userListings.filter(l => l.id !== id))} onAddPoints={addPoints} />} />
            <Route path="/privacy" element={<PrivacyPolicyPage lang={lang} />} />
            <Route path="/terms" element={<TermsOfUsePage lang={lang} />} />
            {user && (
              <>
                <Route path="/discovery" element={
                  <div className="p-8 text-center animate-in fade-in">
                    <Compass size={64} className="mx-auto text-brand mb-4 animate-spin-slow" />
