                            <span className="text-xl font-black text-brand">{user.points}</span>
                         </div>
                         <div className="p-4 bg-gray-50 dark:bg-gray-800 rounded-3xl">
                            <span className="text-[10px] text-gray-400 font-black uppercase block">{lang === 'ar' ? 'إعلاناتك' : 'Your Listings'}</span>
                            <span className="text-xl font-black text-brand">{userListings.length}</span>
                         </div>
                      </div>
                      <div className="space-y-3 mb-8">
                        <Link to="/privacy" className="flex items-center justify-between p-4 bg-gray-50 dark:bg-gray-800 rounded-2xl hover:bg-gray-100 transition-colors">
                          <span className="text-sm font-bold dark:text-white">{t.privacyPolicy}</span>
                          {lang === 'ar' ? <ChevronLeft size={18} className="text-gray-400" /> : <ChevronRight size={18} className="text-gray-400" />}
                        </Link>
                        <Link to="/terms" className="flex items-center justify-between p-4 bg-gray-50 dark:bg-gray-800 rounded-2xl hover:bg-gray-100 transition-colors">
                          <span className="text-sm font-bold dark:text-white">{t.termsOfUse}</span>
                          {lang === 'ar' ? <ChevronLeft size={18} className="text-gray-400" /> : <ChevronRight size={18} className="text-gray-400" />}
                        </Link>
                      </div>
                      <button onClick={() => setUser(null)} className="text-red-500 font-black uppercase tracking-widest text-xs hover:underline">{t.logout}</button>
                    </div>
                  </div>
                } />
              </>
            )}
            <Route path="*" element={<Navigate to="/" />} />
          </Routes>
        </main>
      </div>
    </HashRouter>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { translations } from '../i18n';
import ListingCard from '../components/ListingCard';
import { Listing, CurrencyType } from '../types';
import { Box, Search, Package, Users, ShoppingCart } from 'lucide-react';

const HomePage: React.FC<{ lang: string; user: any; userListings: Listing[]; onDeleteListing: (id: string) => void; onAddPoints: (a: number) => void }> = ({ lang, user, userListings, onDeleteListing, onAddPoints }) => {
  const t = translations[lang] || translations['en'];
  const [filterType, setFilterType] = useState<'ALL' | CurrencyType>('ALL');
  const [searchQuery, setSearchQuery] = useState('');

  const allListings = userListings;

  const filteredItems = useMemo(() => {
    return allListings.filter(item => {
      const matchesSearch = item.title.toLowerCase().includes(searchQuery.toLowerCase());
      const matchesType = filterType === 'ALL' || item.currencyType === filterType;
      return matchesSearch && matchesType;
    });
  }, [searchQuery, filterType, allListings]);

  return (
    <div className="pb-24 pt-4 px-4 max-w-7xl mx-auto">
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-8">
        {[
          { icon: <Package className="text-brand" />, label: lang === 'ar' ? 'أغراضك النشطة' : 'Your Active Items', value: userListings.length },
          { icon: <Users className="text-blue-500" />, label: lang === 'ar' ? 'طلبات الإيجار' : 'Rental Requests', value: '0' },
          { icon: <ShoppingCart className="text-green-500" />, label: lang === 'ar' ? 'عمليات مكتملة' : 'Completed Deals', value: '0' },
        ].map((stat, idx) => (
          <div key={idx} className="bg-white dark:bg-gray-900 p-6 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-800 flex items-center gap-4 hover:-translate-y-1 transition-all">
            <div className="p-3 bg-gray-50 dark:bg-gray-800 rounded-xl">{stat.icon}</div>
            <div>
              <p className="text-[10px] text-gray-500 font-bold uppercase tracking-widest">{stat.label}</p>
              <p className="text-2xl font-black dark:text-white">{stat.value}</p>
            </div>
          </div>
        ))}
      </div>

      <div className="flex flex-col md:flex-row gap-4 mb-8">
        <div className="flex-1 relative">
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
          <input type="text" placeholder={t.searchPlaceholder} value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} className="w-full pl-12 pr-4 py-3 bg-gray-100 dark:bg-gray-800 rounded-2xl outline-none focus:ring-2 focus:ring-brand font-medium" />
        </div>
        <div className="flex gap-2">
          {['ALL', CurrencyType.CRYPTO, CurrencyType.LOCAL].map(f => (
            <button key={f} onClick={() => setFilterType(f as any)} className={`px-6 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all ${filterType === f ? 'bg-brand text-white' : 'bg-gray-100 dark:bg-gray-800 dark:text-gray-400'}`}>
              {f === 'ALL' ? (lang === 'ar' ? 'الكل' : 'All') : t[f.toLowerCase()]}
            </button>
          ))}
        </div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
        {filteredItems.map(item => (
          <ListingCard key={item.id} listing={item} lang={lang} isOwner={item.ownerId === user?.id} onDelete={onDeleteListing} onAddPoints={onAddPoints} />
        ))}
      </div>

      {filteredItems.length === 0 && (
        <div className="py-24 text-center animate-in fade-in duration-700">
          <Box size={48} className="mx-auto mb-4 text-gray-200" />
          <h3 className="text-xl font-bold dark:text-white">{lang === 'ar' ? 'لا توجد منتجات منشورة حالياً' : 'No listings published yet'}</h3>
          <p className="text-sm text-gray-400 mt-2">{lang === 'ar' ? 'ابدأ بنشر أول غرض لك للإيجار الآن' : 'Start by listing your first item for rent now'}</p>
        </div>
      )}
    </div>
  );
};

