import React, { useState, useEffect } from 'react';
import { Heart, MapPin, Eye, Share2, MessageCircle, Trash2, MessageSquare } from 'lucide-react';
import { Listing } from '../types';
import { Link, useNavigate } from 'react-router-dom';
import { translations } from '../i18n';
import { POINTS_SYSTEM } from '../constants';

interface ListingCardProps {
  listing: Listing;
  lang: string;
  isOwner?: boolean;
  onDelete?: (id: string) => void;
  onAddPoints?: (a: number) => void;
}

const ListingCard: React.FC<ListingCardProps> = ({ listing, lang, isOwner, onDelete, onAddPoints }) => {
  const navigate = useNavigate();
  const t = translations[lang] || translations['en'];
  const [isLiked, setIsLiked] = useState(false);
  const [views, setViews] = useState(listing.views);

  useEffect(() => {
    const key = `views_${listing.id}`;
    const storedViews = localStorage.getItem(key);
    if (storedViews) {
      setViews(parseInt(storedViews) + 1);
      localStorage.setItem(key, (parseInt(storedViews) + 1).toString());
    } else {
      const initial = listing.views + 1;
      setViews(initial);
      localStorage.setItem(key, initial.toString());
    }
  }, [listing.id]);

  const handleLike = (e: React.MouseEvent) => {
    e.stopPropagation();
    setIsLiked(!isLiked);
    if (!isLiked) onAddPoints?.(POINTS_SYSTEM.LIKE);
  };

  const handleShare = (e: React.MouseEvent) => {
    e.stopPropagation();
    onAddPoints?.(POINTS_SYSTEM.SHARE);
    alert(lang === 'ar' ? 'تم نسخ الرابط لمشاركته! +10 نقاط' : 'Link copied! +10 Points');
  };

  return (
    <div className="bg-white dark:bg-gray-900 rounded-[2.5rem] overflow-hidden shadow-sm hover:shadow-2xl transition-all border dark:border-gray-800 flex flex-col h-full relative group">
      <div className="p-4 flex items-center justify-between border-b dark:border-gray-800">
        <div className="flex items-center gap-2">
          <img src={listing.ownerAvatar || `https://api.dicebear.com/7.x/avataaars/svg?seed=${listing.ownerUsername}`} className="w-10 h-10 rounded-full border-2 border-brand/20 object-cover" />
          <div className="flex flex-col">
            <span className="text-xs font-black dark:text-white uppercase leading-tight">{listing.ownerName}</span>
            <span className="text-[10px] font-bold text-[#CCCCCC]">@{listing.ownerUsername}</span>
          </div>
        </div>
        {isOwner && (
          <button onClick={() => onDelete?.(listing.id)} className="p-2 text-red-500 hover:bg-red-50 rounded-xl transition-all">
            <Trash2 size={18} />
          </button>
        )}
      </div>

      <Link to={`/item/${listing.id}`} className="block px-2 pt-2">
        <div className="aspect-square overflow-hidden rounded-[2rem]">
          <img src={listing.images[0]} className="w-full h-full object-cover group-hover:scale-105 transition-transform" />
        </div>
        <div className="absolute bottom-28 left-6 bg-brand text-white px-3 py-1 rounded-xl font-black text-xs shadow-xl border-2 border-white/20">
          {listing.price} {listing.currency}
        </div>
      </Link>

      <div className="p-5 flex flex-col flex-1">
        <div className="flex justify-between items-start mb-1">
          <h3 className="font-black dark:text-white uppercase truncate flex-1">{listing.title}</h3>
          <span className="text-[10px] font-black text-gray-400 bg-gray-50 dark:bg-gray-800 px-2 py-0.5 rounded-lg">{listing.category}</span>
        </div>

        <div className="flex items-center gap-1 text-gray-400 text-[10px] font-bold uppercase mb-4">
          <MapPin size={10} className="text-brand" /> {listing.location.address}
        </div>

        <div className="mt-auto grid grid-cols-4 gap-1 pt-4 border-t dark:border-gray-800">
          <button onClick={handleLike} className={`flex flex-col items-center gap-1 p-2 rounded-xl transition-all active:scale-90 ${isLiked ? 'text-brand bg-brand/5' : 'text-gray-400'}`}>
            <Heart size={18} fill={isLiked ? 'currentColor' : 'none'} /><span className="text-[8px] font-black">{t.likes}</span>
          </button>
          <button className="flex flex-col items-center gap-1 p-2 text-gray-400">
            <MessageSquare size={18} /><span className="text-[8px] font-black">{t.comments}</span>
          </button>
          <button onClick={handleShare} className="flex flex-col items-center gap-1 p-2 text-gray-400 hover:text-brand transition-all active:scale-90">
            <Share2 size={18} /><span className="text-[8px] font-black">{t.share}</span>
          </button>
          <button onClick={(e) => { e.preventDefault(); navigate(`/chat/${listing.ownerId}?item=${listing.id}`); }} className="flex flex-col items-center gap-1 p-2 text-brand bg-brand/5 rounded-xl transition-all active:scale-90">
            <MessageCircle size={18} /><span className="text-[8px] font-black">{t.rent}</span>
          </button>
        </div>

        <div className="mt-2 flex items-center gap-1 text-[9px] font-black text-gray-300 uppercase">
          <Eye size={10} /> {views} {t.views}
        </div>
      </div>
    </div>
  );
};

