            <button onClick={() => setShowGroupCreate(true)} className="w-full p-6 border-2 border-dashed dark:border-gray-800 rounded-3xl flex items-center justify-center gap-2 text-gray-400 font-black text-xs uppercase hover:text-brand transition-all">
               <UserPlus size={18} /> {t.createGroup}
            </button>
