    e.preventDefault();
    const newUser: User = {
      id: 'u_' + Date.now(),
      fullName: data.fullName,
      username: data.username,
      email: data.email,
      avatar: data.avatar,
      gender: Gender.OTHER,
      birthDate: '2000-01-01',
      location: data.location,
