                <Route path="/profile" element={
                  <div className="p-8 text-center max-w-2xl mx-auto animate-in fade-in">
                    <div className="bg-white dark:bg-gray-900 rounded-[3rem] p-10 shadow-sm border dark:border-gray-800">
                      <img src={user.avatar || `https://api.dicebear.com/7.x/avataaars/svg?seed=${user.username}`} className="w-32 h-32 mx-auto rounded-full border-4 border-brand mb-4 object-cover" />
                      <h1 className="text-2xl font-black dark:text-white uppercase tracking-tighter">{user.fullName}</h1>
                      <p className="text-[#CCCCCC] mb-8 font-bold">@{user.username}</p>
                      <div className="grid grid-cols-2 gap-4 mb-8">
                         <div className="p-4 bg-gray-50 dark:bg-gray-800 rounded-3xl">
                            <span className="text-[10px] text-gray-400 font-black uppercase block">{lang === 'ar' ? 'نقاطك' : 'Your Points'}</span>
