    if (selectedPlan && user.points >= selectedPlan.pointsCost) {
      const updatedUser = {
        ...user,
        points: user.points - selectedPlan.pointsCost,
        subscription: {
          tier: selectedPlan.name,
          expiresAt: new Date(Date.now() + 30 * 24 * 60 * 60 * 1000).toISOString()
        }
