            <button 
              disabled={paymentMode === 'POINTS' && user.points < plan.pointsCost}
              className={`w-full py-4 rounded-2xl font-black text-[10px] uppercase tracking-widest transition-all ${selectedPlan?.id === plan.id ? 'bg-brand text-white shadow-xl shadow-brand/30' : 'bg-gray-100 dark:bg-gray-800 text-gray-400'}`}
            >
              {paymentMode === 'POINTS' && user.points < plan.pointsCost ? t.insufficientPoints : (lang === 'ar' ? 'اختر الباقة' : 'Select Plan')}
            </button>
          </div>
        ))}
      </div>

      <div className="bg-gray-50 dark:bg-gray-800 p-6 rounded-[2.5rem] flex items-center justify-between border dark:border-gray-700 shadow-sm">
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 bg-brand/10 text-brand rounded-2xl flex items-center justify-center">
            <Coins size={24} />
          </div>
          <div>
            <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest leading-none">{t.pointsBalance}</p>
            <p className="text-xl font-black dark:text-white">{user.points} <span className="text-xs">PTS</span></p>
          </div>
        </div>
        {selectedPlan && (
          <button 
            onClick={paymentMode === 'CASH' ? () => setStep(2) : handlePointExchange}
            className="px-10 py-4 bg-brand text-white rounded-[2rem] font-black text-xs uppercase tracking-widest shadow-xl shadow-brand/20 active:scale-95 transition-transform"
          >
            {paymentMode === 'CASH' ? t.next : t.confirmExchange}
          </button>
        )}
      </div>
    </div>
  );

  return (
    <div className="max-w-6xl mx-auto p-4 pt-10 pb-24">
      <div className="text-center mb-12">
        <h1 className="text-5xl font-black dark:text-white uppercase tracking-tighter italic mb-2">Upgrade your rents</h1>
        <p className="text-gray-400 font-bold uppercase tracking-widest text-xs">Unleash the full power of the community</p>
      </div>

      {step === 1 && renderPlanSelection()}
      {step === 5 && (
        <div className="text-center py-20 animate-in zoom-in-95">
           <div className="w-32 h-32 bg-green-500 text-white rounded-[3rem] flex items-center justify-center mx-auto shadow-2xl shadow-green-500/30 mb-8 rotate-12">
              <CheckCircle size={64} />
           </div>
           <h2 className="text-4xl font-black dark:text-white uppercase tracking-tighter mb-4">{lang === 'ar' ? 'تم التفعيل بنجاح!' : 'Activation Successful!'}</h2>
           <p className="text-gray-400 font-bold mb-8">{lang === 'ar' ? 'أنت الآن مشترك في ' : 'You are now subscribed to '} {selectedPlan?.name}</p>
           <button onClick={() => navigate('/')} className="px-12 py-5 bg-brand text-white rounded-[2rem] font-black uppercase tracking-widest shadow-xl">Return to Market</button>
        </div>
      )}
    </div>
  );
};

