                   {groupData.image ? <img src={groupData.image} className="w-full h-full object-cover" /> : <Camera size={32} className="text-gray-400" />}
                   <input type="file" ref={groupImageRef} className="hidden" accept="image/*" onChange={e => e.target.files && setGroupData({...groupData, image: URL.createObjectURL(e.target.files[0])})} />
                 </button>
                 <input type="text" placeholder={lang === 'ar' ? 'اسم المجتمع*' : 'Community Name*'} value={groupData.name} onChange={e => setGroupData({...groupData, name: e.target.value})} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none font-bold" />
                 <textarea placeholder={lang === 'ar' ? 'وصف المجتمع*' : 'Description*'} value={groupData.description} onChange={e => setGroupData({...groupData, description: e.target.value})} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white h-24 outline-none font-bold" />
                 <button onClick={handleCreateGroup} disabled={!groupData.name || !groupData.image} className="w-full py-5 bg-brand text-white rounded-[2rem] font-black uppercase tracking-widest shadow-xl">Launch Community</button>
