import { Camera, MapPinned, Compass, Box, Star, ChevronRight, User as UserIcon, Coins, Sparkles, Loader2, ChevronLeft, ShieldCheck } from 'lucide-react';

const App: React.FC = () => {
  const [lang, setLang] = useState<string>('ar');
