  const SignUpPage = () => {
    const fileInputRef = useRef<HTMLInputElement>(null);
    const [signupData, setSignupData] = useState({
      avatar: '', fullName: '', username: '', location: { address: '', lat: 0, lng: 0 },
      email: '', password: '', agreed: false
    });
    const [isLocating, setIsLocating] = useState(false);

    const handleAutoLocation = () => {
      setIsLocating(true);
      if ("geolocation" in navigator) {
        navigator.geolocation.getCurrentPosition(async (position) => {
          const { latitude, longitude } = position.coords;
          // محاكاة جلب العنوان من الإحداثيات
          const mockAddress = lang === 'ar' ? `موقع محدد (خط عرض: ${latitude.toFixed(2)})` : `Detected Location (${latitude.toFixed(2)})`;
          setSignupData(prev => ({
            ...prev,
            location: { address: mockAddress, lat: latitude, lng: longitude }
          }));
          setIsLocating(false);
        }, (error) => {
          alert(lang === 'ar' ? 'فشل تحديد الموقع. يرجى إدخاله يدوياً.' : 'Location failed. Please enter manually.');
          setIsLocating(false);
        });
      }
    };

    return (
      <div className="w-full max-w-2xl px-6 py-12 mx-auto animate-in fade-in slide-in-from-bottom-8">
        <div className="text-center mb-10">
          <div className="inline-block px-4 py-2 bg-brand text-white rounded-2xl shadow-xl font-black text-2xl mb-4 italic">my rents</div>
          <h1 className="text-3xl font-black dark:text-white mb-2">{lang === 'ar' ? 'إنشاء حساب جديد' : 'Create New Account'}</h1>
        </div>
        <form onSubmit={(e) => handleSignUpFinish(e, signupData)} className="space-y-6">
          <div className="flex flex-col items-center gap-2">
            <button type="button" onClick={() => fileInputRef.current?.click()} className="w-32 h-32 rounded-full bg-gray-100 dark:bg-gray-800 flex items-center justify-center border-4 border-brand cursor-pointer overflow-hidden shadow-2xl">
               {signupData.avatar ? <img src={signupData.avatar} className="w-full h-full object-cover" /> : <Camera size={40} className="text-gray-400" />}
               <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={e => e.target.files && setSignupData({...signupData, avatar: URL.createObjectURL(e.target.files[0])})} />
            </button>
            <span className="text-[10px] font-black uppercase text-gray-400">{t.signupSteps.profilePic}</span>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <input type="text" required placeholder={t.signupSteps.personalName} value={signupData.fullName} onChange={e => setSignupData({...signupData, fullName: e.target.value})} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none focus:ring-2 focus:ring-brand font-bold" />
            <input type="text" required placeholder={t.signupSteps.userName} value={signupData.username} onChange={e => setSignupData({...signupData, username: e.target.value})} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none focus:ring-2 focus:ring-brand font-bold" />
          </div>

          <div className="space-y-2">
            <label className="text-xs font-black text-gray-400 uppercase tracking-widest block px-2">{t.location}</label>
            <div className="flex gap-2">
              <div className="relative flex-1">
                <MapPinned size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-brand" />
                <input 
                  type="text" 
                  required 
                  placeholder={lang === 'ar' ? 'أدخل عنوانك يدوياً...' : 'Enter address manually...'} 
                  value={signupData.location.address} 
                  onChange={e => setSignupData({...signupData, location: { ...signupData.location, address: e.target.value }})} 
                  className="w-full pl-12 pr-4 py-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none focus:ring-2 focus:ring-brand font-bold" 
                />
              </div>
              <button 
                type="button" 
                onClick={handleAutoLocation}
                className="p-4 bg-white dark:bg-gray-800 border-2 border-brand/20 text-brand rounded-2xl hover:bg-brand hover:text-white transition-all shadow-sm active:scale-90"
                title={lang === 'ar' ? 'تحديد تلقائي' : 'Auto Detect'}
              >
                {isLocating ? <Loader2 size={24} className="animate-spin" /> : <Compass size={24} />}
              </button>
            </div>
          </div>

          <div className="p-4 bg-gray-50 dark:bg-gray-800 rounded-2xl flex items-start gap-3 border dark:border-gray-700">
             <input 
                type="checkbox" 
                id="agreed" 
                required 
                checked={signupData.agreed} 
                onChange={e => setSignupData({...signupData, agreed: e.target.checked})} 
                className="mt-1 w-5 h-5 accent-brand rounded"
             />
             <label htmlFor="agreed" className="text-[11px] font-bold dark:text-white leading-relaxed">
                {lang === 'ar' ? (
                  <>أوافق على <Link to="/privacy" className="text-brand underline">سياسة الخصوصية</Link> و <Link to="/terms" className="text-brand underline">شروط الاستخدام</Link> الخاصة بـ my rents.</>
                ) : (
                  <>I agree to my rents <Link to="/privacy" className="text-brand underline">Privacy Policy</Link> and <Link to="/terms" className="text-brand underline">Terms of Use</Link>.</>
                )}
             </label>
          </div>

          <button type="submit" disabled={!signupData.fullName || !signupData.agreed} className="w-full py-5 bg-brand text-white rounded-3xl font-black shadow-xl tracking-widest uppercase hover:scale-[1.02] active:scale-95 transition-all disabled:opacity-30">
            {lang === 'ar' ? 'ابدأ الآن' : 'Start Now'}
          </button>
        </form>
      </div>
    );
  };

  return (
    <HashRouter>
      <div className={`min-h-screen ${lang === 'ar' ? 'rtl' : 'ltr'} bg-white dark:bg-gray-950 transition-colors duration-200`} dir={lang === 'ar' ? 'rtl' : 'ltr'}>
        {user && <Navbar lang={lang} isDark={isDarkMode} toggleTheme={toggleTheme} user={user} />}
        <main className={user ? 'pb-20' : ''}>
          <Routes>
            <Route path="/" element={!user ? <SignUpPage /> : <HomePage lang={lang} user={user} userListings={userListings} onDeleteListing={(id) => setUserListings(userListings.filter(l => l.id !== id))} onAddPoints={addPoints} />} />
            <Route path="/privacy" element={<PrivacyPolicyPage lang={lang} />} />
            <Route path="/terms" element={<TermsOfUsePage lang={lang} />} />
            {user && (
              <>
                <Route path="/discovery" element={
                  <div className="p-8 animate-in fade-in">
                    <div className="text-center mb-12">
                      <Compass size={64} className="mx-auto text-brand mb-4 animate-spin-slow" />
                      <h1 className="text-4xl font-black dark:text-white uppercase tracking-tighter mb-2 italic">{t.discovery}</h1>
                      <p className="text-gray-400 font-bold uppercase tracking-widest text-xs">{lang === 'ar' ? 'استكشف ما هو متاح بالقرب منك' : 'Explore what is available nearby'}</p>
                    </div>
                    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6 max-w-7xl mx-auto">
                      {userListings.length === 0 ? (
                         <div className="col-span-full py-20 text-center opacity-20">
                            <Box size={64} className="mx-auto mb-4" />
                            <p className="font-black uppercase tracking-widest text-sm">No items in your area yet</p>
                         </div>
                      ) : userListings.map(l => <ListingCard key={l.id} listing={l} lang={lang} onAddPoints={addPoints} />)}
                    </div>
                  </div>
                } />
                <Route path="/subscription" element={<SubscriptionPage lang={lang} user={user} onUpdateUser={setUser} />} />
                <Route path="/create" element={<CreateListingPage lang={lang} user={user} onCreated={(l) => { setUserListings([...userListings, l]); addPoints(POINTS_SYSTEM.CREATE_LISTING); }} />} />
                <Route path="/chat/*" element={<ChatPage lang={lang} onAddPoints={addPoints} />} />
                <Route path="/item/:id" element={<ItemDetailPage lang={lang} user={user} listings={userListings} onDelete={(id) => setUserListings(userListings.filter(l => l.id !== id))} onAddPoints={addPoints} />} />
                <Route path="/profile" element={
                  <div className="p-8 text-center max-w-2xl mx-auto animate-in fade-in">
                    <div className="bg-white dark:bg-gray-900 rounded-[3.5rem] p-10 shadow-sm border dark:border-gray-800">
                      <div className="relative inline-block mb-6">
                        <img src={user.avatar || `https://api.dicebear.com/7.x/avataaars/svg?seed=${user.username}`} className="w-32 h-32 rounded-full border-4 border-brand object-cover shadow-2xl" />
                        {user.subscription && (
                          <div className="absolute -bottom-2 -right-2 bg-brand text-white p-2 rounded-xl shadow-lg">
                            <Star size={18} fill="currentColor" />
                          </div>
                        )}
                      </div>

                      <h1 className="text-3xl font-black dark:text-white uppercase tracking-tighter mb-1 italic">{user.fullName}</h1>
                      <p className="text-[#CCCCCC] mb-8 font-bold">@{user.username}</p>

                      <div className="grid grid-cols-2 gap-4 mb-10">
                         <div className="p-6 bg-gray-50 dark:bg-gray-800 rounded-[2.5rem] border dark:border-gray-700">
                            <div className="flex items-center justify-center gap-2 mb-1">
                               <Coins size={14} className="text-brand" />
                               <span className="text-[10px] text-gray-400 font-black uppercase tracking-widest">Points</span>
                            </div>
                            <span className="text-3xl font-black text-brand">{user.points}</span>
                         </div>
                         <div className="p-6 bg-gray-50 dark:bg-gray-800 rounded-[2.5rem] border dark:border-gray-700">
                            <div className="flex items-center justify-center gap-2 mb-1">
                               <Box size={14} className="text-brand" />
                               <span className="text-[10px] text-gray-400 font-black uppercase tracking-widest">Ads</span>
                            </div>
                            <span className="text-3xl font-black text-brand">{userListings.length}</span>
                         </div>
                      </div>

                      <div className="space-y-3 mb-10">
                        <Link to="/subscription" className="w-full flex items-center justify-between p-6 bg-brand/5 border-2 border-brand/20 rounded-[2rem] hover:bg-brand text-brand hover:text-white transition-all group">
                           <div className="flex items-center gap-4 text-left">
                              <div className="w-12 h-12 rounded-2xl bg-brand/10 text-brand flex items-center justify-center group-hover:bg-white/20 group-hover:text-white">
                                <Sparkles size={24} />
                              </div>
                              <div>
                                <span className="font-black uppercase tracking-tighter text-sm block">{lang === 'ar' ? 'استبدال النقاط' : 'Redeem Points'}</span>
                                <span className="text-[9px] font-bold opacity-60 uppercase">{lang === 'ar' ? 'احصل على اشتراكات وميزات' : 'Get exclusive tiers and features'}</span>
                              </div>
                           </div>
                           <ChevronRight />
                        </Link>

                        <div className="grid grid-cols-1 gap-2">
                           <Link to="/privacy" className="flex items-center justify-between p-5 bg-gray-50 dark:bg-gray-800 rounded-[1.8rem] hover:bg-gray-100 transition-colors">
                             <span className="text-xs font-black uppercase tracking-widest dark:text-white">{t.privacyPolicy}</span>
                             <ChevronRight size={18} className="text-gray-400" />
                           </Link>
                           <Link to="/terms" className="flex items-center justify-between p-5 bg-gray-50 dark:bg-gray-800 rounded-[1.8rem] hover:bg-gray-100 transition-colors">
                             <span className="text-xs font-black uppercase tracking-widest dark:text-white">{t.termsOfUse}</span>
                             <ChevronRight size={18} className="text-gray-400" />
                           </Link>
                        </div>
                      </div>

                      <button onClick={() => setUser(null)} className="flex items-center justify-center gap-2 mx-auto text-red-500 font-black uppercase tracking-widest text-[10px] hover:underline hover:scale-105 transition-all">
                        {t.logout}
                      </button>
                    </div>
                  </div>
                } />
              </>
            )}
            <Route path="*" element={<Navigate to="/" />} />
          </Routes>
        </main>
      </div>
    </HashRouter>
  );
};

