        const { latitude, longitude } = position.coords;
        const mockAddress = lang === 'ar' ? `موقع محدد (إحداثيات: ${latitude.toFixed(2)})` : `Detected Location (${latitude.toFixed(2)})`;
        setLocation({ address: mockAddress, lat: latitude, lng: longitude });
        setIsLocating(false);
      }, () => {
        alert(lang === 'ar' ? 'فشل تحديد الموقع.' : 'Location failed.');
        setIsLocating(false);
      });
    }
  };

  const handlePublish = async () => {
    setLoading(true);
    const result = await checkListingContent(title, description);
    if (result.status === 'APPROVED') {
      const l: Listing = {
        id: 'l_' + Date.now(), ownerId: user.id, ownerName: user.fullName, ownerUsername: user.username,
        ownerAvatar: user.avatar, title, description, type: ListingType.RENT, price: parseFloat(price),
        currency: 'USD', currencyType, payoutAddress: payoutMethod, category, location,
        images, video: video || undefined, rentalPeriod: period, createdAt: new Date().toISOString(),
        views: 0, likes: 0, rating: 0, isAiApproved: true
      };
      onCreated(l);
      setStep(5);
    } else {
      alert(t.aiRejected + ": " + result.reason);
    }
    setLoading(false);
  };

  return (
    <div className="max-w-2xl mx-auto p-6 bg-white dark:bg-gray-900 rounded-[3rem] my-8 border dark:border-gray-800 shadow-sm animate-in fade-in slide-in-from-bottom-4">
      <div className="flex gap-1 mb-8">
        {[1,2,3,4,5].map(s => <div key={s} className={`h-1.5 flex-1 rounded-full ${step >= s ? 'bg-brand' : 'bg-gray-100 dark:bg-gray-800'}`} />)}
      </div>

      {step === 1 && (
        <div className="space-y-6">
          <h2 className="text-2xl font-black dark:text-white uppercase tracking-tighter">{lang === 'ar' ? 'وسائط المنتج' : 'Product Media'}</h2>
          <div className="grid grid-cols-3 gap-2">
            {images.map((img, i) => <img key={i} src={img} className="aspect-square object-cover rounded-xl" />)}
            {images.length < 5 && (
              <button 
                type="button"
                onClick={() => imageInputRef.current?.click()}
                className="aspect-square border-2 border-dashed border-gray-200 dark:border-gray-700 rounded-xl flex items-center justify-center cursor-pointer text-gray-400 hover:border-brand hover:text-brand transition-all"
              >
                <Camera />
                <input 
                  type="file" 
                  ref={imageInputRef}
                  multiple 
                  accept="image/*" 
                  className="hidden" 
                  onChange={e => {
                    if (e.target.files) {
                      const files = Array.from(e.target.files).map((f: File) => URL.createObjectURL(f));
                      setImages([...images, ...files].slice(0, 5));
                    }
                  }} 
                />
              </button>
            )}
          </div>
          <button 
            type="button"
            onClick={() => videoInputRef.current?.click()}
            className="w-full flex items-center gap-2 p-4 border rounded-2xl dark:text-white cursor-pointer hover:bg-gray-50 dark:hover:bg-gray-800 transition-all font-bold"
          >
            <Video size={20} className="text-brand" /> {lang === 'ar' ? 'رفع فيديو (اختياري)' : 'Upload Video'}
            <input 
              type="file" 
              ref={videoInputRef}
              accept="video/*" 
              className="hidden" 
              onChange={e => {
                if (e.target.files && e.target.files[0]) {
                  setVideo(URL.createObjectURL(e.target.files[0]));
                }
              }} 
            />
          </button>
          <button disabled={images.length < 2} onClick={() => setStep(2)} className="w-full py-4 bg-brand text-white rounded-2xl font-black uppercase tracking-widest disabled:opacity-30">{t.next}</button>
        </div>
      )}

      {step === 2 && (
        <div className="space-y-6">
          <h2 className="text-2xl font-black dark:text-white uppercase tracking-tighter">{lang === 'ar' ? 'وصف المنتج وموقعه' : 'Description & Location'}</h2>
          <input type="text" placeholder="Product Name*" value={title} onChange={e => setTitle(e.target.value)} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none font-bold" />
          <textarea placeholder="Description*" value={description} onChange={e => setDescription(e.target.value)} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white h-32 outline-none font-bold" />
          <select value={category} onChange={e => setCategory(e.target.value)} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none font-bold">
            {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
          </select>

          <div className="space-y-2">
            <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest block px-2">{t.location}*</label>
            <div className="flex gap-2">
              <div className="relative flex-1">
                <MapPinned size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-brand" />
                <input 
                  type="text" 
                  placeholder={lang === 'ar' ? 'أدخل عنوان الغرض يدوياً...' : 'Enter item address...'} 
                  value={location.address} 
                  onChange={e => setLocation({...location, address: e.target.value})} 
                  className="w-full pl-12 pr-4 py-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none focus:ring-2 focus:ring-brand font-bold" 
                />
              </div>
              <button 
                type="button" 
                onClick={handleAutoLocation}
                className="p-4 bg-white dark:bg-gray-800 border-2 border-brand/20 text-brand rounded-2xl hover:bg-brand hover:text-white transition-all shadow-sm active:scale-90"
              >
                {isLocating ? <Loader2 size={24} className="animate-spin" /> : <Compass size={24} />}
              </button>
            </div>
          </div>

          <div className="flex gap-2">
             <button onClick={() => setStep(1)} className="flex-1 py-4 bg-gray-100 dark:bg-gray-800 text-gray-400 rounded-2xl font-black uppercase tracking-widest">{t.back}</button>
             <button disabled={!title || !description || !location.address} onClick={() => setStep(3)} className="flex-[2] py-4 bg-brand text-white rounded-2xl font-black uppercase tracking-widest">{t.next}</button>
          </div>
        </div>
      )}

      {step === 3 && (
        <div className="space-y-6">
          <h2 className="text-2xl font-black dark:text-white uppercase tracking-tighter">{t.payoutMethod}*</h2>
          <div className="flex gap-2 p-1 bg-gray-100 dark:bg-gray-800 rounded-2xl">
            <button onClick={() => {setCurrencyType(CurrencyType.CRYPTO); setPayoutMethod('')}} className={`flex-1 py-3 rounded-xl font-black uppercase tracking-widest text-[10px] ${currencyType === CurrencyType.CRYPTO ? 'bg-white dark:bg-gray-900 text-brand shadow' : 'text-gray-400'}`}>{t.crypto}</button>
            <button onClick={() => {setCurrencyType(CurrencyType.LOCAL); setPayoutMethod('')}} className={`flex-1 py-3 rounded-xl font-black uppercase tracking-widest text-[10px] ${currencyType === CurrencyType.LOCAL ? 'bg-white dark:bg-gray-900 text-brand shadow' : 'text-gray-400'}`}>{t.local}</button>
          </div>
          {currencyType === CurrencyType.CRYPTO ? (
            <div className="grid grid-cols-2 gap-2">
              {cryptoCoins.map(coin => (
                <button key={coin} onClick={() => setPayoutMethod(coin)} className={`p-4 rounded-xl border-2 text-[10px] font-black uppercase tracking-widest transition-all ${payoutMethod === coin ? 'border-brand bg-brand/5 text-brand' : 'border-transparent bg-gray-50 dark:bg-gray-800 dark:text-white'}`}>{coin}</button>
              ))}
            </div>
          ) : (
            <input type="email" placeholder="PayPal Email*" value={payoutMethod} onChange={e => setPayoutMethod(e.target.value)} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none font-bold" />
          )}
          <div className="flex gap-2">
             <button onClick={() => setStep(2)} className="flex-1 py-4 bg-gray-100 dark:bg-gray-800 text-gray-400 rounded-2xl font-black uppercase tracking-widest">{t.back}</button>
             <button disabled={!payoutMethod} onClick={() => setStep(4)} className="flex-[2] py-4 bg-brand text-white rounded-2xl font-black uppercase tracking-widest">{t.next}</button>
          </div>
        </div>
      )}

      {step === 4 && (
        <div className="space-y-6">
          <h2 className="text-2xl font-black dark:text-white uppercase tracking-tighter">{lang === 'ar' ? 'السعر والمراجعة' : 'Price & Review'}</h2>
          <div className="relative">
            <span className="absolute left-4 top-1/2 -translate-y-1/2 font-black text-brand">$</span>
            <input type="number" placeholder="Price (USD)*" value={price} onChange={e => setPrice(e.target.value)} className="w-full pl-8 pr-4 py-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none font-bold" />
          </div>
          <select value={period} onChange={e => setPeriod(e.target.value as RentalPeriod)} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none font-bold">
            {Object.keys(RentalPeriod).map(p => <option key={p} value={p}>{t.periods[p]}</option>)}
          </select>
          <div className="p-6 bg-brand/5 border border-brand/20 rounded-[2rem] text-center">
             <ShieldCheck size={40} className="mx-auto text-brand mb-2 animate-pulse" />
             <h3 className="font-black dark:text-white mb-1 uppercase tracking-tighter">{t.aiChecking}</h3>
             <p className="text-[9px] text-gray-400 font-bold uppercase tracking-widest">AI my rents security protocols active</p>
          </div>
          <div className="flex gap-2">
             <button onClick={() => setStep(3)} className="flex-1 py-5 bg-gray-100 dark:bg-gray-800 text-gray-400 rounded-3xl font-black uppercase tracking-widest">{t.back}</button>
             <button onClick={handlePublish} disabled={loading || !price} className="flex-[2] py-5 bg-brand text-white rounded-3xl font-black shadow-xl shadow-brand/20 flex items-center justify-center gap-2 uppercase tracking-widest">
               {loading ? <Loader2 className="animate-spin" /> : <><ShieldCheck size={20} /> Publish Item</>}
             </button>
          </div>
        </div>
      )}

      {step === 5 && (
        <div className="text-center py-12 space-y-6">
          <div className="w-24 h-24 bg-green-500 text-white rounded-full flex items-center justify-center mx-auto shadow-2xl shadow-green-500/30">
            <CheckCircle size={48} />
          </div>
          <h2 className="text-4xl font-black dark:text-white uppercase tracking-tighter italic">{t.aiApproved}</h2>
          <p className="text-gray-400 font-bold uppercase tracking-widest text-[10px]">{lang === 'ar' ? 'تم نشر غرضك بنجاح في السوق!' : 'Your item is now live in the marketplace!'}</p>
          <button onClick={() => navigate('/')} className="w-full py-5 bg-brand text-white rounded-[2rem] font-black shadow-xl uppercase tracking-widest">Return Home</button>
        </div>
      )}
    </div>
  );
};

export default CreateListingPage;
